import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum InvoiceStatus {
  DRAFT = 'Brouillon',
  SENT = 'Envoyée',
  PAID = 'Payée',
  CANCELLED = 'Annulée'
}

export interface Client {
  id: string;
  name: string;
  email: string;
  address: string;
  siret?: string;
  phone?: string;
}

export interface InvoiceItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
}

export interface Invoice {
  id: string;
  number: string;
  date: string;
  dueDate: string;
  clientId: string;
  items: InvoiceItem[];
  status: InvoiceStatus;
  notes?: string;
  total: number;
}

export interface UserProfile {
  companyName: string;
  siret: string;
  address: string;
  email: string;
  phone: string;
  bankAccount?: string; // IBAN short
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
  timestamp: number;
}

export type ViewState = 'dashboard' | 'invoices' | 'clients' | 'assistant' | 'settings';

import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || '';
// Initialize securely - assumes environment variable is injected
const ai = new GoogleGenAI({ apiKey });

export const generateAssistantResponse = async (
  query: string, 
  context?: string
): Promise<string> => {
  try {
    const model = 'gemini-3-flash-preview';

    const systemPrompt = `Tu es un assistant expert pour les auto-entrepreneurs en France.
    Tu connais les règles de l'URSSAF, les seuils de TVA (Franchise en base), les plafonds de Chiffre d'Affaires, et les obligations de facturation.
    Réponds de manière concise, professionnelle et utile.
    Si on te demande de rédiger un email ou un texte, fais-le avec un ton courtois.
    Contexte actuel de l'utilisateur (si pertinent) : ${context || 'Aucun contexte spécifique'}`;

    const response = await ai.models.generateContent({
      model: model,
      contents: query,
      config: {
        systemInstruction: systemPrompt,
        thinkingConfig: { thinkingBudget: 0 } // Disable thinking for faster simple Q&A
      }
    });

    return response.text || "Désolé, je n'ai pas pu générer de réponse.";
  } catch (error) {
    console.error("Erreur Gemini:", error);
    return "Une erreur est survenue lors de la consultation de l'assistant IA. Veuillez vérifier votre clé API.";
  }
};

export const suggestInvoiceDescription = async (clientName: string, serviceType: string): Promise<string> => {
  try {
     const prompt = `Génère une description professionnelle courte pour une ligne de facture destinée au client "${clientName}" pour un service de type : "${serviceType}". 
     La description doit être claire et formelle. Ne donne que la description, pas de guillemets.`;

     const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text?.trim() || serviceType;
  } catch (error) {
    console.error("Erreur Gemini:", error);
    return serviceType;
  }
}

import React from 'react';
import { ViewState } from '../types';
import { LayoutDashboard, FileText, Users, Bot, Settings, Briefcase } from 'lucide-react';

interface SidebarProps {
  currentView: ViewState;
  setView: (view: ViewState) => void;
  isMobileMenuOpen: boolean;
  setIsMobileMenuOpen: (isOpen: boolean) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentView, setView, isMobileMenuOpen, setIsMobileMenuOpen }) => {
