import React, { useMemo } from 'react';
import { Invoice, InvoiceStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { Euro, TrendingUp, AlertCircle, CheckCircle } from 'lucide-react';

interface DashboardProps {
  invoices: Invoice[];
}

const Dashboard: React.FC<DashboardProps> = ({ invoices }) => {
  // Stats Calculation
  const totalRevenue = useMemo(() => {
    return invoices
      .filter(inv => inv.status === InvoiceStatus.PAID)
      .reduce((sum, inv) => sum + inv.total, 0);
  }, [invoices]);

  const pendingRevenue = useMemo(() => {
    return invoices
      .filter(inv => inv.status === InvoiceStatus.SENT)
      .reduce((sum, inv) => sum + inv.total, 0);
  }, [invoices]);

  const monthlyData = useMemo(() => {
    const data: Record<string, number> = {};
    const months = ['Jan', 'Fév', 'Mar', 'Avr', 'Mai', 'Juin', 'Juil', 'Août', 'Sep', 'Oct', 'Nov', 'Déc'];

    // Initialize
    months.forEach(m => data[m] = 0);

    invoices.forEach(inv => {
      if (inv.status === InvoiceStatus.PAID) {
        const date = new Date(inv.date);
        const monthIndex = date.getMonth();
        data[months[monthIndex]] += inv.total;
      }
    });

    return months.map(name => ({ name, ca: data[name] }));
  }, [invoices]);

  // Thresholds (2024 approx for services)
  const VAT_THRESHOLD = 36800;
  const STATUS_LIMIT = 77700; 

  const progressPercentage = Math.min((totalRevenue / VAT_THRESHOLD) * 100, 100);

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {/* Total Revenue Card */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500">Chiffre d'Affaires (Encassé)</p>
              <h3 className="text-3xl font-bold text-slate-900 mt-2">{totalRevenue.toLocaleString('fr-FR', { style: 'currency', currency: 'EUR' })}</h3>
            </div>
            <div className="p-3 bg-green-100 text-green-600 rounded-lg">
              <Euro size={24} />
            </div>
          </div>
          <div className="mt-4 flex items-center text-sm text-green-600">
            <TrendingUp size={16} className="mr-1" />
            <span>Sur l'année en cours</span>
          </div>
        </div>

        {/* Pending Card */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-slate-500">En attente de paiement</p>
              <h3 className="text-3xl font-bold text-slate-900 mt-2">{pendingRevenue.toLocaleString('fr-FR', { style: 'currency', currency: 'EUR' })}</h3>
            </div>
            <div className="p-3 bg-orange-100 text-orange-600 rounded-lg">
              <AlertCircle size={24} />
            </div>
          </div>
          <div className="mt-4 text-sm text-slate-500">
            {invoices.filter(i => i.status === InvoiceStatus.SENT).length} factures envoyées
          </div>
        </div>

        {/* VAT Threshold Card */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start">
            <div className="w-full">
              <p className="text-sm font-medium text-slate-500">Seuil Franchise TVA</p>
              <div className="flex justify-between items-baseline mt-2">
                 <h3 className="text-xl font-bold text-slate-900">{progressPercentage.toFixed(1)}%</h3>
                 <span className="text-xs text-slate-400">{VAT_THRESHOLD.toLocaleString()}€ max</span>
              </div>
              <div className="w-full bg-slate-100 rounded-full h-2.5 mt-3">
                <div 
                  className={`h-2.5 rounded-full ${progressPercentage > 85 ? 'bg-red-500' : 'bg-blue-600'}`} 
                  style={{ width: `${progressPercentage}%` }}
                ></div>
              </div>
            </div>
          </div>
          <div className="mt-4 text-sm text-slate-500">
            {totalRevenue < VAT_THRESHOLD 
              ? "Vous êtes en franchise de base TVA." 
              : "Attention : Seuil dépassé, TVA applicable."}
          </div>
        </div>
      </div>

      {/* Chart Section */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h3 className="text-lg font-bold text-slate-900 mb-6">Évolution du CA Mensuel</h3>
        <div className="h-80 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={monthlyData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
              <XAxis 
                dataKey="name" 
                axisLine={false} 
                tickLine={false} 
                tick={{ fill: '#64748b', fontSize: 12 }} 
                dy={10}
              />
              <YAxis 
                axisLine={false} 
                tickLine={false} 
                tick={{ fill: '#64748b', fontSize: 12 }}
                tickFormatter={(value) => `${value}€`}
              />
              <Tooltip 
                cursor={{ fill: '#f1f5f9' }}
                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
              />
              <Bar dataKey="ca" radius={[4, 4, 0, 0]}>
                {monthlyData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill="#3b82f6" />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Recent Activity List (Simplified) */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h3 className="text-lg font-bold text-slate-900 mb-4">Dernières Factures</h3>
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="border-b border-slate-100 text-slate-500">
              <tr>
                <th className="pb-3 font-medium">Numéro</th>
                <th className="pb-3 font-medium">Client</th>
                <th className="pb-3 font-medium">Date</th>
                <th className="pb-3 font-medium text-right">Montant</th>
                <th className="pb-3 font-medium text-right">Statut</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {invoices.slice(0, 5).map((invoice) => (
                <tr key={invoice.id} className="hover:bg-slate-50/50">
                  <td className="py-3 font-medium text-slate-900">{invoice.number}</td>
                  <td className="py-3 text-slate-600">Client #{invoice.clientId.substring(0,4)}</td>
                  <td className="py-3 text-slate-600">{invoice.date}</td>
                  <td className="py-3 text-right font-medium text-slate-900">{invoice.total.toFixed(2)} €</td>
                  <td className="py-3 text-right">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium
                      ${invoice.status === InvoiceStatus.PAID ? 'bg-green-100 text-green-800' : 
                        invoice.status === InvoiceStatus.SENT ? 'bg-orange-100 text-orange-800' :
                        'bg-slate-100 text-slate-800'}`}>
                      {invoice.status}
                    </span>
                  </td>
                </tr>
              ))}
              {invoices.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-8 text-center text-slate-500">Aucune facture récente.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Client } from '../types';
import { Plus, Search, Trash2, Mail, MapPin, Phone, Building } from 'lucide-react';

interface ClientManagerProps {
  clients: Client[];
  setClients: (clients: Client[]) => void;
}

const ClientManager: React.FC<ClientManagerProps> = ({ clients, setClients }) => {
  const [showForm, setShowForm] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [newClient, setNewClient] = useState<Partial<Client>>({
    name: '',
    email: '',
    address: '',
    siret: '',
    phone: ''
  });

  const handleAddClient = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newClient.name || !newClient.email) return;

    const client: Client = {
      id: Date.now().toString(),
      name: newClient.name,
      email: newClient.email,
      address: newClient.address || '',
      siret: newClient.siret,
      phone: newClient.phone
    };

    setClients([...clients, client]);
    setNewClient({ name: '', email: '', address: '', siret: '', phone: '' });
    setShowForm(false);
  };

  const handleDeleteClient = (id: string) => {
    if (confirm('Êtes-vous sûr de vouloir supprimer ce client ?')) {
      setClients(clients.filter(c => c.id !== id));
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Clients</h2>
          <p className="text-slate-500">Gérez votre carnet d'adresses</p>
        </div>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm"
        >
          <Plus size={18} />
          Nouveau Client
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-xl shadow-md border border-slate-200 animate-in fade-in slide-in-from-top-4">
          <h3 className="text-lg font-semibold mb-4">Ajouter un client</h3>
          <form onSubmit={handleAddClient} className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nom / Société *</label>
              <input 
                type="text" 
                required
                className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                value={newClient.name}
                onChange={e => setNewClient({...newClient, name: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Email *</label>
              <input 
                type="email" 
                required
                className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                value={newClient.email}
                onChange={e => setNewClient({...newClient, email: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">SIRET</label>
              <input 
                type="text" 
                className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                value={newClient.siret}
                onChange={e => setNewClient({...newClient, siret: e.target.value})}
              />
            </div>
             <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Téléphone</label>
              <input 
                type="tel" 
                className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                value={newClient.phone}
                onChange={e => setNewClient({...newClient, phone: e.target.value})}
              />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-slate-700 mb-1">Adresse complète</label>
              <textarea 
                className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                rows={2}
                value={newClient.address}
                onChange={e => setNewClient({...newClient, address: e.target.value})}
              />
            </div>
            <div className="md:col-span-2 flex justify-end gap-3 mt-2">
              <button 
                type="button" 
                onClick={() => setShowForm(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
              >
                Annuler
              </button>
              <button 
                type="submit" 
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
              >
                Enregistrer
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Search & List */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100">
           <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher un client..."
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:border-blue-400"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 p-4">
          {filteredClients.map(client => (
            <div key={client.id} className="border border-slate-200 rounded-lg p-4 hover:shadow-md transition-shadow group relative">
               <button 
                onClick={() => handleDeleteClient(client.id)}
                className="absolute top-4 right-4 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                title="Supprimer"
               >
                 <Trash2 size={16} />
               </button>

               <div className="flex items-center gap-3 mb-3">
                 <div className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 flex items-center justify-center font-bold text-lg">
                   {client.name.charAt(0).toUpperCase()}
                 </div>
                 <div>
                   <h4 className="font-semibold text-slate-900 truncate pr-6">{client.name}</h4>
                   <p className="text-xs text-slate-500">ID: {client.id.substring(client.id.length - 4)}</p>
                 </div>
               </div>

               <div className="space-y-2 text-sm text-slate-600">
                 <div className="flex items-center gap-2">
                   <Mail size={14} className="shrink-0" />
                   <span className="truncate">{client.email}</span>
                 </div>
                 {client.phone && (
                   <div className="flex items-center gap-2">
                     <Phone size={14} className="shrink-0" />
                     <span>{client.phone}</span>
                   </div>
                 )}
                 {client.siret && (
                   <div className="flex items-center gap-2">
                     <Building size={14} className="shrink-0" />
                     <span>{client.siret}</span>
                   </div>
                 )}
                 {client.address && (
                   <div className="flex items-start gap-2">
                     <MapPin size={14} className="shrink-0 mt-0.5" />
                     <span className="line-clamp-2">{client.address}</span>
                   </div>
                 )}
               </div>
            </div>
          ))}

          {filteredClients.length === 0 && (
             <div className="col-span-full py-12 text-center text-slate-400">
               Aucun client trouvé.
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ClientManager;

import React, { useState } from 'react';
import { Invoice, InvoiceItem, InvoiceStatus, Client, UserProfile } from '../types';
import { Plus, Trash2, Printer, Check, Wand2, ArrowLeft } from 'lucide-react';
import { suggestInvoiceDescription } from '../services/geminiService';

interface InvoiceManagerProps {
  invoices: Invoice[];
  setInvoices: (invoices: Invoice[]) => void;
  clients: Client[];
  userProfile: UserProfile;
}

const InvoiceManager: React.FC<InvoiceManagerProps> = ({ invoices, setInvoices, clients, userProfile }) => {
  const [view, setView] = useState<'list' | 'create' | 'detail'>('list');
  const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null);

  // New Invoice State
  const [newInvoiceData, setNewInvoiceData] = useState<Partial<Invoice>>({
    items: [],
    date: new Date().toISOString().split('T')[0],
    dueDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
  });
  const [selectedClientId, setSelectedClientId] = useState<string>('');
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);

  // Add Item
  const addItem = () => {
    const items = newInvoiceData.items || [];
    setNewInvoiceData({
      ...newInvoiceData,
      items: [...items, { id: Date.now().toString(), description: '', quantity: 1, unitPrice: 0 }]
    });
  };

  const updateItem = (id: string, field: keyof InvoiceItem, value: any) => {
    const items = newInvoiceData.items?.map(item => 
      item.id === id ? { ...item, [field]: value } : item
    ) || [];
    setNewInvoiceData({ ...newInvoiceData, items });
  };

  const removeItem = (id: string) => {
    const items = newInvoiceData.items?.filter(item => item.id !== id) || [];
    setNewInvoiceData({ ...newInvoiceData, items });
  };

  const handleGenerateDescription = async (itemId: string, currentDesc: string) => {
    if (!selectedClientId) {
      alert("Veuillez sélectionner un client d'abord.");
      return;
    }
    const client = clients.find(c => c.id === selectedClientId);
    if (!client) return;

    setIsGeneratingDesc(true);
    const suggestion = await suggestInvoiceDescription(client.name, currentDesc || "Service général");
    setIsGeneratingDesc(false);

    updateItem(itemId, 'description', suggestion);
  };

  const saveInvoice = () => {
    if (!selectedClientId || !newInvoiceData.date || !newInvoiceData.items?.length) {
      alert("Veuillez remplir tous les champs obligatoires (client, date, articles).");
      return;
    }

    const total = newInvoiceData.items.reduce((sum, item) => sum + (item.quantity * item.unitPrice), 0);

    // Generate Invoice Number (Simple Auto-increment logic)
    const currentYear = new Date().getFullYear();
    const countThisYear = invoices.filter(i => i.date.startsWith(currentYear.toString())).length + 1;
    const number = `FACT-${currentYear}-${countThisYear.toString().padStart(3, '0')}`;

    const invoice: Invoice = {
      id: Date.now().toString(),
      number,
      clientId: selectedClientId,
      date: newInvoiceData.date,
      dueDate: newInvoiceData.dueDate!,
      items: newInvoiceData.items,
      status: InvoiceStatus.DRAFT,
      total,
      notes: newInvoiceData.notes
    };

    setInvoices([invoice, ...invoices]);
    setView('list');
    // Reset
    setNewInvoiceData({
      items: [],
      date: new Date().toISOString().split('T')[0],
      dueDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    });
    setSelectedClientId('');
  };

  const updateStatus = (id: string, status: InvoiceStatus) => {
    setInvoices(invoices.map(inv => inv.id === id ? { ...inv, status } : inv));
  };

  const deleteInvoice = (id: string) => {
     if(confirm("Supprimer cette facture ?")) {
       setInvoices(invoices.filter(inv => inv.id !== id));
       if (selectedInvoice?.id === id) setView('list');
     }
  }

  // --- RENDERERS ---

  if (view === 'create') {
    return (
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 animate-fade-in max-w-4xl mx-auto">
        <div className="flex items-center gap-4 mb-6">
          <button onClick={() => setView('list')} className="p-2 hover:bg-slate-100 rounded-full">
            <ArrowLeft size={20} />
          </button>
          <h2 className="text-xl font-bold">Nouvelle Facture</h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Client</label>
            <select 
              className="w-full p-2 border border-slate-300 rounded-lg"
              value={selectedClientId}
              onChange={(e) => setSelectedClientId(e.target.value)}
            >
              <option value="">Sélectionner un client...</option>
              {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Date d'émission</label>
              <input 
                type="date" 
                className="w-full p-2 border border-slate-300 rounded-lg"
                value={newInvoiceData.date}
                onChange={(e) => setNewInvoiceData({...newInvoiceData, date: e.target.value})}
              />
            </div>
             <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Date d'échéance</label>
              <input 
                type="date" 
                className="w-full p-2 border border-slate-300 rounded-lg"
                value={newInvoiceData.dueDate}
                onChange={(e) => setNewInvoiceData({...newInvoiceData, dueDate: e.target.value})}
              />
            </div>
          </div>
        </div>

        <div className="mb-6">
          <table className="w-full text-left">
            <thead>
              <tr className="border-b border-slate-200 text-sm text-slate-500">
                <th className="py-2 w-1/2">Description</th>
                <th className="py-2 w-20">Qté</th>
                <th className="py-2 w-32">Prix Uni.</th>
                <th className="py-2 w-32 text-right">Total</th>
                <th className="py-2 w-10"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {newInvoiceData.items?.map((item) => (
                <tr key={item.id}>
                  <td className="py-2 pr-2">
                    <div className="flex gap-2">
                      <input 
                        type="text" 
                        placeholder="Description du service"
                        className="w-full p-2 border border-slate-300 rounded-lg text-sm"
                        value={item.description}
                        onChange={(e) => updateItem(item.id, 'description', e.target.value)}
                      />
                      <button 
                        onClick={() => handleGenerateDescription(item.id, item.description)}
                        className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg"
                        title="Améliorer avec l'IA"
                        disabled={isGeneratingDesc}
                      >
                        <Wand2 size={16} className={isGeneratingDesc ? "animate-spin" : ""} />
                      </button>
                    </div>
                  </td>
                  <td className="py-2 pr-2">
                     <input 
                        type="number" 
                        min="0"
                        className="w-full p-2 border border-slate-300 rounded-lg text-sm"
                        value={item.quantity}
                        onChange={(e) => updateItem(item.id, 'quantity', parseFloat(e.target.value))}
                      />
                  </td>
                  <td className="py-2 pr-2">
                     <input 
                        type="number" 
                        min="0"
                        step="0.01"
                        className="w-full p-2 border border-slate-300 rounded-lg text-sm"
                        value={item.unitPrice}
                        onChange={(e) => updateItem(item.id, 'unitPrice', parseFloat(e.target.value))}
                      />
                  </td>
                  <td className="py-2 text-right font-medium">
                    {(item.quantity * item.unitPrice).toFixed(2)} €
                  </td>
                  <td className="py-2 text-right">
                    <button onClick={() => removeItem(item.id)} className="text-red-500 hover:bg-red-50 p-1 rounded">
                      <Trash2 size={16} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          <button onClick={addItem} className="mt-4 flex items-center gap-2 text-sm text-blue-600 font-medium hover:underline">
            <Plus size={16} /> Ajouter une ligne
          </button>
        </div>

        <div className="flex justify-between items-center border-t border-slate-200 pt-6">
          <div className="text-xl font-bold">
            Total: {(newInvoiceData.items?.reduce((acc, i) => acc + (i.quantity * i.unitPrice), 0) || 0).toFixed(2)} €
          </div>
          <button 
            onClick={saveInvoice}
            className="bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-700 font-medium"
          >
            Créer la facture
          </button>
        </div>
      </div>
    );
  }

  if (view === 'detail' && selectedInvoice) {
    const client = clients.find(c => c.id === selectedInvoice.clientId);
    return (
      <div className="bg-white rounded-xl shadow-lg border border-slate-200 max-w-4xl mx-auto animate-fade-in print:shadow-none print:border-none">
        {/* Actions Bar (Hidden on Print) */}
        <div className="flex justify-between items-center p-4 border-b border-slate-100 print:hidden bg-slate-50 rounded-t-xl">
          <button onClick={() => setView('list')} className="flex items-center gap-2 text-slate-600 hover:text-slate-900">
            <ArrowLeft size={18} /> Retour
          </button>
          <div className="flex gap-2">
            <select 
              value={selectedInvoice.status}
              onChange={(e) => updateStatus(selectedInvoice.id, e.target.value as InvoiceStatus)}
              className="p-2 text-sm border border-slate-300 rounded-lg bg-white"
            >
              {Object.values(InvoiceStatus).map(s => <option key={s} value={s}>{s}</option>)}
            </select>
            <button 
              onClick={() => window.print()}
              className="flex items-center gap-2 px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900"
            >
              <Printer size={16} /> Imprimer / PDF
            </button>
          </div>
        </div>

        {/* Invoice Preview */}
        <div className="p-8 md:p-12 bg-white" id="invoice-preview">
          <div className="flex justify-between mb-12">
            <div>
              <h1 className="text-3xl font-bold text-slate-900 mb-2">FACTURE</h1>
              <p className="text-slate-500">#{selectedInvoice.number}</p>
              <div className="mt-4 text-sm text-slate-600">
                <p className="font-bold text-slate-900">{userProfile.companyName}</p>
                <p>{userProfile.address}</p>
                <p>{userProfile.email} | {userProfile.phone}</p>
                <p>SIRET: {userProfile.siret}</p>
              </div>
            </div>
            <div className="text-right">
              <h3 className="text-lg font-bold text-slate-700 mb-2">Facturé à :</h3>
              <p className="font-bold text-slate-900">{client?.name}</p>
              <p className="text-sm text-slate-600 whitespace-pre-line">{client?.address}</p>
              {client?.siret && <p className="text-sm text-slate-600">SIRET: {client.siret}</p>}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-8 mb-8 text-sm">
            <div>
              <span className="text-slate-500">Date d'émission:</span>
              <span className="ml-2 font-medium text-slate-900">{selectedInvoice.date}</span>
            </div>
            <div className="text-right">
              <span className="text-slate-500">Date d'échéance:</span>
              <span className="ml-2 font-medium text-slate-900">{selectedInvoice.dueDate}</span>
            </div>
          </div>

          <table className="w-full mb-8">
            <thead>
              <tr className="border-b-2 border-slate-900 text-left text-sm font-bold text-slate-900">
                <th className="py-3">Description</th>
                <th className="py-3 text-right">Qté</th>
                <th className="py-3 text-right">Prix Unitaire</th>
                <th className="py-3 text-right">Total</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm">
              {selectedInvoice.items.map((item, idx) => (
                <tr key={idx}>
                  <td className="py-4 text-slate-800">{item.description}</td>
                  <td className="py-4 text-right text-slate-600">{item.quantity}</td>
                  <td className="py-4 text-right text-slate-600">{item.unitPrice.toFixed(2)} €</td>
                  <td className="py-4 text-right font-medium text-slate-900">{(item.quantity * item.unitPrice).toFixed(2)} €</td>
                </tr>
              ))}
            </tbody>
          </table>

          <div className="flex justify-end">
            <div className="w-64 bg-slate-50 p-6 rounded-lg">
              <div className="flex justify-between mb-2 text-sm">
                <span className="text-slate-600">Total HT</span>
                <span className="font-medium text-slate-900">{selectedInvoice.total.toFixed(2)} €</span>
              </div>
              <div className="flex justify-between mb-4 text-sm">
                <span className="text-slate-600">TVA (non applicable)</span>
                <span className="font-medium text-slate-900">0.00 €</span>
              </div>
              <div className="flex justify-between border-t border-slate-200 pt-4 text-lg font-bold">
                <span>Total TTC</span>
                <span className="text-blue-600">{selectedInvoice.total.toFixed(2)} €</span>
              </div>
            </div>
          </div>

          <div className="mt-12 text-xs text-slate-400 border-t border-slate-100 pt-8 text-center">
