          </div>
        </div>
      </div>
    );
  }

  // List View
  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-900">Factures</h2>
        <button 
          onClick={() => setView('create')}
          className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors"
        >
          <Plus size={18} />
          Créer une facture
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 border-b border-slate-200 text-slate-500">
              <tr>
                <th className="px-6 py-3 font-medium">Numéro</th>
                <th className="px-6 py-3 font-medium">Client</th>
                <th className="px-6 py-3 font-medium">Date</th>
                <th className="px-6 py-3 font-medium text-right">Montant</th>
                <th className="px-6 py-3 font-medium text-center">Statut</th>
                <th className="px-6 py-3 font-medium text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {invoices.map((invoice) => {
                 const clientName = clients.find(c => c.id === invoice.clientId)?.name || 'Client Inconnu';
                 return (
                  <tr key={invoice.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 font-medium text-slate-900">{invoice.number}</td>
                    <td className="px-6 py-4 text-slate-600">{clientName}</td>
                    <td className="px-6 py-4 text-slate-600">{invoice.date}</td>
                    <td className="px-6 py-4 text-right font-medium text-slate-900">{invoice.total.toFixed(2)} €</td>
                    <td className="px-6 py-4 text-center">
                      <span className={`inline-flex px-2.5 py-1 rounded-full text-xs font-medium
                        ${invoice.status === InvoiceStatus.PAID ? 'bg-green-100 text-green-700' : 
                          invoice.status === InvoiceStatus.SENT ? 'bg-orange-100 text-orange-700' :
                          'bg-slate-100 text-slate-600'}`}>
                        {invoice.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right flex justify-end gap-2">
                      <button 
                        onClick={() => { setSelectedInvoice(invoice); setView('detail'); }}
                        className="text-blue-600 hover:bg-blue-50 p-1.5 rounded"
                        title="Voir"
                      >
                        <Printer size={16} />
                      </button>
                      <button 
                         onClick={() => deleteInvoice(invoice.id)}
                        className="text-slate-400 hover:text-red-500 hover:bg-red-50 p-1.5 rounded"
                        title="Supprimer"
                      >
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                );
              })}
              {invoices.length === 0 && (
                <tr>
                  <td colSpan={6} className="py-12 text-center text-slate-500">
                    Aucune facture. Commencez par en créer une !
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

