        return <Dashboard invoices={invoices} />;
      case 'invoices':
        return <InvoiceManager invoices={invoices} setInvoices={setInvoices} clients={clients} userProfile={userProfile} />;
      case 'clients':
        return <ClientManager clients={clients} setClients={setClients} />;
      case 'assistant':
        return <AIAssistant />;
      case 'settings':
        return <SettingsView />;
      default:
        return <Dashboard invoices={invoices} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans text-slate-900">
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        isMobileMenuOpen={isMobileMenuOpen}
        setIsMobileMenuOpen={setIsMobileMenuOpen}
      />

      <main className="flex-1 lg:ml-64 p-4 lg:p-8 overflow-x-hidden">
        {/* Mobile Header */}
        <div className="lg:hidden flex justify-between items-center mb-6">
          <h1 className="text-xl font-bold">AutoGest</h1>
          <button 
            onClick={() => setIsMobileMenuOpen(true)}
            className="p-2 bg-white rounded-lg shadow-sm border border-slate-200"
          >
            <Menu size={24} />
          </button>
        </div>

        {renderContent()}
      </main>
    </div>
  );
};

