import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import InvoiceManager from './components/InvoiceManager';
import ClientManager from './components/ClientManager';
import SupplierManager from './components/SupplierManager';
import ProductManager from './components/ProductManager';
import AccountingManager from './components/AccountingManager';
import AIAssistant from './components/AIAssistant';
import { ViewState, Invoice, Client, UserProfile, Supplier, Product, Expense } from './types';
import { Menu } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // --- STATE ---
  const [invoices, setInvoices] = useState<Invoice[]>(() => {
    const saved = localStorage.getItem('autogest_invoices');
    return saved ? JSON.parse(saved) : [];
  });

  const [clients, setClients] = useState<Client[]>(() => {
    const saved = localStorage.getItem('autogest_clients');
    return saved ? JSON.parse(saved) : [];
  });

  const [suppliers, setSuppliers] = useState<Supplier[]>(() => {
    const saved = localStorage.getItem('autogest_suppliers');
    return saved ? JSON.parse(saved) : [];
  });

  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('autogest_products');
    return saved ? JSON.parse(saved) : [];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autogest_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [userProfile, setUserProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('autogest_profile');
    return saved ? JSON.parse(saved) : {
      companyName: 'Ma Micro-Entreprise',
      siret: '123 456 789 00012',
      address: '123 Avenue de la République, 75001 Paris',
      email: 'contact@mon-entreprise.fr',
      phone: '01 02 03 04 05',
      bankAccount: 'FR76 1234 5678 9012 3456 7890 123'
    };
  });

  // --- EFFECTS ---
  useEffect(() => { localStorage.setItem('autogest_invoices', JSON.stringify(invoices)); }, [invoices]);
  useEffect(() => { localStorage.setItem('autogest_clients', JSON.stringify(clients)); }, [clients]);
  useEffect(() => { localStorage.setItem('autogest_suppliers', JSON.stringify(suppliers)); }, [suppliers]);
  useEffect(() => { localStorage.setItem('autogest_products', JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem('autogest_expenses', JSON.stringify(expenses)); }, [expenses]);
  useEffect(() => { localStorage.setItem('autogest_profile', JSON.stringify(userProfile)); }, [userProfile]);


  // --- SETTINGS VIEW COMPONENT (Inline) ---
  const SettingsView = () => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 max-w-2xl">
      <h2 className="text-2xl font-bold mb-6">Paramètres de l'entreprise</h2>
      <div className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-slate-700">Nom de l'entreprise</label>
          <input 
            type="text" 
            className="w-full p-2 border border-slate-300 rounded" 
            value={userProfile.companyName}
            onChange={(e) => setUserProfile({...userProfile, companyName: e.target.value})}
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700">SIRET</label>
          <input 
            type="text" 
            className="w-full p-2 border border-slate-300 rounded" 
            value={userProfile.siret}
            onChange={(e) => setUserProfile({...userProfile, siret: e.target.value})}
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700">Adresse</label>
          <textarea 
            className="w-full p-2 border border-slate-300 rounded" 
            value={userProfile.address}
            onChange={(e) => setUserProfile({...userProfile, address: e.target.value})}
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700">IBAN (pour les factures)</label>
          <input 
            type="text" 
            className="w-full p-2 border border-slate-300 rounded" 
            value={userProfile.bankAccount}
            onChange={(e) => setUserProfile({...userProfile, bankAccount: e.target.value})}
          />
        </div>
        <div className="pt-4 text-green-600 text-sm font-medium">
          Les modifications sont sauvegardées automatiquement.
        </div>
      </div>
    </div>
  );

  const renderContent = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard invoices={invoices} />;
      case 'invoices':
        return <InvoiceManager invoices={invoices} setInvoices={setInvoices} clients={clients} userProfile={userProfile} />;
      case 'clients':
        return <ClientManager clients={clients} setClients={setClients} />;
      case 'suppliers':
        return <SupplierManager suppliers={suppliers} setSuppliers={setSuppliers} />;
      case 'products':
        return <ProductManager products={products} setProducts={setProducts} />;
      case 'accounting':
        return <AccountingManager expenses={expenses} setExpenses={setExpenses} invoices={invoices} suppliers={suppliers} />;
      case 'assistant':
        return <AIAssistant />;
      case 'settings':
        return <SettingsView />;
      default:
        return <Dashboard invoices={invoices} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans text-slate-900">
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        isMobileMenuOpen={isMobileMenuOpen}
        setIsMobileMenuOpen={setIsMobileMenuOpen}
      />

      <main className="flex-1 lg:ml-64 p-4 lg:p-8 overflow-x-hidden">
        {/* Mobile Header */}
        <div className="lg:hidden flex justify-between items-center mb-6">
          <h1 className="text-xl font-bold">AutoGest</h1>
          <button 
            onClick={() => setIsMobileMenuOpen(true)}
            className="p-2 bg-white rounded-lg shadow-sm border border-slate-200"
          >
            <Menu size={24} />
          </button>
        </div>

        {renderContent()}
      </main>
    </div>
  );
};

export default App;

