import React, { useMemo } from 'react';
import { Invoice, InvoiceStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { Euro, TrendingUp, AlertCircle, ArrowUpRight, ArrowRight } from 'lucide-react';

interface DashboardProps {
  invoices: Invoice[];
}

const Dashboard: React.FC<DashboardProps> = ({ invoices }) => {
  // Stats Calculation
  const totalRevenue = useMemo(() => {
    return invoices
      .filter(inv => inv.status === InvoiceStatus.PAID)
      .reduce((sum, inv) => sum + inv.total, 0);
  }, [invoices]);

  const pendingRevenue = useMemo(() => {
    return invoices
      .filter(inv => inv.status === InvoiceStatus.SENT)
      .reduce((sum, inv) => sum + inv.total, 0);
  }, [invoices]);

  const monthlyData = useMemo(() => {
    const data: Record<string, number> = {};
    const months = ['Jan', 'Fév', 'Mar', 'Avr', 'Mai', 'Juin', 'Juil', 'Août', 'Sep', 'Oct', 'Nov', 'Déc'];

    // Initialize
    months.forEach(m => data[m] = 0);

    invoices.forEach(inv => {
      if (inv.status === InvoiceStatus.PAID) {
        const date = new Date(inv.date);
        const monthIndex = date.getMonth();
        data[months[monthIndex]] += inv.total;
      }
    });

    return months.map(name => ({ name, ca: data[name] }));
  }, [invoices]);

  // Thresholds (2024 approx for services)
  const VAT_THRESHOLD = 36800;

  const progressPercentage = Math.min((totalRevenue / VAT_THRESHOLD) * 100, 100);

  return (
    <div className="space-y-8 animate-fade-in max-w-7xl mx-auto">
      <div>
        <h2 className="text-2xl font-bold text-slate-900 tracking-tight">Tableau de bord</h2>
        <p className="text-slate-500">Vue d'ensemble de votre activité.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {/* Total Revenue Card */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-all duration-300 group">
          <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-blue-50 text-blue-600 rounded-xl group-hover:scale-110 transition-transform duration-300">
              <Euro size={24} />
            </div>
            <span className="flex items-center text-xs font-medium text-green-600 bg-green-50 px-2 py-1 rounded-full">
              <TrendingUp size={12} className="mr-1" />
              +12%
            </span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500">Chiffre d'Affaires (Encassé)</p>
            <h3 className="text-3xl font-bold text-slate-900 mt-1 tracking-tight">
              {totalRevenue.toLocaleString('fr-FR', { style: 'currency', currency: 'EUR' })}
            </h3>
          </div>
        </div>

        {/* Pending Card */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-all duration-300 group">
          <div className="flex justify-between items-start mb-4">
             <div className="p-3 bg-orange-50 text-orange-600 rounded-xl group-hover:scale-110 transition-transform duration-300">
              <AlertCircle size={24} />
            </div>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500">En attente de paiement</p>
            <h3 className="text-3xl font-bold text-slate-900 mt-1 tracking-tight">
              {pendingRevenue.toLocaleString('fr-FR', { style: 'currency', currency: 'EUR' })}
            </h3>
            <p className="text-xs text-slate-400 mt-2 font-medium">
              {invoices.filter(i => i.status === InvoiceStatus.SENT).length} factures non réglées
            </p>
          </div>
        </div>

        {/* VAT Threshold Card */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-all duration-300 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-4 opacity-10">
             <ArrowUpRight size={100} />
          </div>
          <div className="relative z-10">
            <p className="text-sm font-medium text-slate-500">Seuil Franchise TVA</p>
            <div className="flex justify-between items-baseline mt-1 mb-3">
               <h3 className="text-2xl font-bold text-slate-900">{progressPercentage.toFixed(1)}%</h3>
               <span className="text-xs font-medium text-slate-400 bg-slate-50 px-2 py-1 rounded-md border border-slate-200">
                 {VAT_THRESHOLD.toLocaleString()}€ max
               </span>
            </div>
            <div className="w-full bg-slate-100 rounded-full h-3 overflow-hidden">
              <div 
                className={`h-full rounded-full transition-all duration-1000 ease-out ${progressPercentage > 85 ? 'bg-red-500' : 'bg-gradient-to-r from-blue-500 to-indigo-500'}`} 
                style={{ width: `${progressPercentage}%` }}
              ></div>
            </div>
            <p className="mt-3 text-xs text-slate-500 font-medium">
              {totalRevenue < VAT_THRESHOLD 
                ? "Vous êtes en franchise de base." 
                : "Seuil dépassé, TVA applicable dès le 1er jour du mois de dépassement."}
            </p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Chart Section */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-900 mb-6 flex items-center gap-2">
            Évolution du CA
            <span className="text-xs font-normal text-slate-400 bg-slate-50 px-2 py-0.5 rounded-full border border-slate-200">2024</span>
          </h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={monthlyData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="name" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fill: '#94a3b8', fontSize: 11, fontWeight: 500 }} 
                  dy={10}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fill: '#94a3b8', fontSize: 11, fontWeight: 500 }}
                  tickFormatter={(value) => `${value/1000}k`}
                />
                <Tooltip 
                  cursor={{ fill: '#f8fafc' }}
                  contentStyle={{ 
                    borderRadius: '12px', 
                    border: 'none', 
                    boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)',
                    padding: '12px',
                    backgroundColor: 'rgba(255, 255, 255, 0.95)'
                  }}
                  formatter={(value: number) => [`${value} €`, 'CA']}
                />
                <Bar dataKey="ca" radius={[6, 6, 0, 0]} maxBarSize={50}>
                  {monthlyData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill="#3b82f6" fillOpacity={0.9} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Recent Activity List */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col">
          <div className="flex justify-between items-center mb-6">
             <h3 className="text-lg font-bold text-slate-900">Factures récentes</h3>
             <button className="text-xs font-medium text-blue-600 hover:bg-blue-50 px-2 py-1 rounded-md transition-colors flex items-center">
               Tout voir <ArrowRight size={12} className="ml-1" />
             </button>
          </div>

          <div className="flex-1 overflow-auto -mx-2 px-2">
            <div className="space-y-3">
              {invoices.slice(0, 5).map((invoice) => (
                <div key={invoice.id} className="flex items-center justify-between p-3 hover:bg-slate-50 rounded-xl transition-colors border border-transparent hover:border-slate-100 group cursor-pointer">
                  <div className="flex items-center gap-3">
                    <div className={`w-10 h-10 rounded-lg flex items-center justify-center text-xs font-bold
                      ${invoice.status === InvoiceStatus.PAID ? 'bg-green-100 text-green-700' : 
                        invoice.status === InvoiceStatus.SENT ? 'bg-orange-100 text-orange-700' :
                        'bg-slate-100 text-slate-600'}`}>
                      {invoice.status === InvoiceStatus.PAID ? '€' : '#'}
                    </div>
                    <div>
                      <p className="text-sm font-semibold text-slate-900">{invoice.number}</p>
                      <p className="text-xs text-slate-500">{invoice.date}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-sm font-bold text-slate-900">{invoice.total.toFixed(0)} €</p>
                    <p className="text-[10px] font-medium uppercase tracking-wide text-slate-400 group-hover:text-blue-500 transition-colors">
                      {invoice.status}
                    </p>
                  </div>
                </div>
              ))}
              {invoices.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-slate-400 py-10">
                  <p>Aucune activité récente.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Invoice, InvoiceItem, InvoiceStatus, Client, UserProfile } from '../types';
import { Plus, Trash2, Printer, Check, Wand2, ArrowLeft, Download, Send, FileText } from 'lucide-react';
import { suggestInvoiceDescription } from '../services/geminiService';

interface InvoiceManagerProps {
  invoices: Invoice[];
  setInvoices: (invoices: Invoice[]) => void;
  clients: Client[];
  userProfile: UserProfile;
}

const InvoiceManager: React.FC<InvoiceManagerProps> = ({ invoices, setInvoices, clients, userProfile }) => {
  const [view, setView] = useState<'list' | 'create' | 'detail'>('list');
  const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null);

  // New Invoice State
  const [newInvoiceData, setNewInvoiceData] = useState<Partial<Invoice>>({
    items: [],
    date: new Date().toISOString().split('T')[0],
    dueDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
  });
  const [selectedClientId, setSelectedClientId] = useState<string>('');
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);

  // Add Item
  const addItem = () => {
    const items = newInvoiceData.items || [];
    setNewInvoiceData({
      ...newInvoiceData,
      items: [...items, { id: Date.now().toString(), description: '', quantity: 1, unitPrice: 0 }]
    });
  };

  const updateItem = (id: string, field: keyof InvoiceItem, value: any) => {
    const items = newInvoiceData.items?.map(item => 
      item.id === id ? { ...item, [field]: value } : item
    ) || [];
    setNewInvoiceData({ ...newInvoiceData, items });
  };

  const removeItem = (id: string) => {
    const items = newInvoiceData.items?.filter(item => item.id !== id) || [];
    setNewInvoiceData({ ...newInvoiceData, items });
  };

  const handleGenerateDescription = async (itemId: string, currentDesc: string) => {
    if (!selectedClientId) {
      alert("Veuillez sélectionner un client d'abord.");
      return;
    }
    const client = clients.find(c => c.id === selectedClientId);
    if (!client) return;

    setIsGeneratingDesc(true);
    const suggestion = await suggestInvoiceDescription(client.name, currentDesc || "Service général");
    setIsGeneratingDesc(false);

    updateItem(itemId, 'description', suggestion);
  };

  const saveInvoice = () => {
    if (!selectedClientId || !newInvoiceData.date || !newInvoiceData.items?.length) {
      alert("Veuillez remplir tous les champs obligatoires (client, date, articles).");
      return;
    }

    const total = newInvoiceData.items.reduce((sum, item) => sum + (item.quantity * item.unitPrice), 0);

    // Generate Invoice Number
    const currentYear = new Date().getFullYear();
    const countThisYear = invoices.filter(i => i.date.startsWith(currentYear.toString())).length + 1;
    const number = `FACT-${currentYear}-${countThisYear.toString().padStart(3, '0')}`;

    const invoice: Invoice = {
      id: Date.now().toString(),
      number,
      clientId: selectedClientId,
      date: newInvoiceData.date,
      dueDate: newInvoiceData.dueDate!,
      items: newInvoiceData.items,
      status: InvoiceStatus.DRAFT,
      total,
      notes: newInvoiceData.notes
    };

    setInvoices([invoice, ...invoices]);
    setView('list');
    setNewInvoiceData({
      items: [],
      date: new Date().toISOString().split('T')[0],
      dueDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    });
    setSelectedClientId('');
  };

  const updateStatus = (id: string, status: InvoiceStatus) => {
    setInvoices(invoices.map(inv => inv.id === id ? { ...inv, status } : inv));
    // Update local selected invoice state to reflect change immediately in view
    if (selectedInvoice && selectedInvoice.id === id) {
        setSelectedInvoice({ ...selectedInvoice, status });
    }
  };

  const deleteInvoice = (id: string) => {
     if(confirm("Supprimer cette facture ?")) {
       setInvoices(invoices.filter(inv => inv.id !== id));
       if (selectedInvoice?.id === id) setView('list');
     }
  }

  // --- RENDERERS ---

  if (view === 'create') {
    return (
      <div className="max-w-5xl mx-auto animate-slide-in">
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-4">
            <button onClick={() => setView('list')} className="p-2 hover:bg-slate-200 rounded-full transition-colors text-slate-500">
              <ArrowLeft size={20} />
            </button>
            <div>
              <h2 className="text-2xl font-bold text-slate-900">Nouvelle Facture</h2>
              <p className="text-slate-500 text-sm">Créez et envoyez une nouvelle facture.</p>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-8">
            <div className="md:col-span-1">
              <label className="block text-sm font-semibold text-slate-700 mb-2">Client destinataire</label>
              <select 
                className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                value={selectedClientId}
                onChange={(e) => setSelectedClientId(e.target.value)}
              >
                <option value="">Sélectionner...</option>
                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </div>
            <div className="md:col-span-2 grid grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Date d'émission</label>
                <input 
                  type="date" 
                  className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none"
                  value={newInvoiceData.date}
                  onChange={(e) => setNewInvoiceData({...newInvoiceData, date: e.target.value})}
                />
              </div>
               <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Date d'échéance</label>
                <input 
                  type="date" 
                  className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none"
                  value={newInvoiceData.dueDate}
                  onChange={(e) => setNewInvoiceData({...newInvoiceData, dueDate: e.target.value})}
                />
              </div>
            </div>
          </div>

          <div className="mb-8 border border-slate-100 rounded-xl overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b border-slate-200">
                <tr className="text-xs font-semibold text-slate-500 uppercase tracking-wider">
                  <th className="py-3 px-4 w-1/2">Description</th>
                  <th className="py-3 px-4 w-24">Qté</th>
                  <th className="py-3 px-4 w-32">Prix Uni.</th>
                  <th className="py-3 px-4 w-32 text-right">Total</th>
                  <th className="py-3 px-4 w-12"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {newInvoiceData.items?.map((item) => (
                  <tr key={item.id} className="group hover:bg-slate-50/50">
                    <td className="py-2 px-4">
                      <div className="flex gap-2">
                        <input 
                          type="text" 
                          placeholder="Ex: Création site web"
                          className="w-full p-2 bg-transparent border-b border-transparent focus:border-blue-400 focus:bg-white rounded text-sm outline-none transition-colors"
                          value={item.description}
                          onChange={(e) => updateItem(item.id, 'description', e.target.value)}
                        />
                        <button 
                          onClick={() => handleGenerateDescription(item.id, item.description)}
                          className="p-1.5 text-indigo-500 hover:bg-indigo-50 rounded-lg opacity-0 group-hover:opacity-100 transition-all"
                          title="Assistant IA"
                          disabled={isGeneratingDesc}
                        >
                          <Wand2 size={14} className={isGeneratingDesc ? "animate-spin" : ""} />
                        </button>
                      </div>
                    </td>
                    <td className="py-2 px-4">
                       <input 
                          type="number" 
                          min="0"
                          className="w-full p-2 bg-transparent border-b border-transparent focus:border-blue-400 focus:bg-white rounded text-sm outline-none text-right"
                          value={item.quantity}
                          onChange={(e) => updateItem(item.id, 'quantity', parseFloat(e.target.value))}
                        />
                    </td>
                    <td className="py-2 px-4">
                       <input 
                          type="number" 
                          min="0"
                          step="0.01"
                          className="w-full p-2 bg-transparent border-b border-transparent focus:border-blue-400 focus:bg-white rounded text-sm outline-none text-right"
                          value={item.unitPrice}
                          onChange={(e) => updateItem(item.id, 'unitPrice', parseFloat(e.target.value))}
                        />
                    </td>
                    <td className="py-2 px-4 text-right font-medium text-slate-900">
                      {(item.quantity * item.unitPrice).toFixed(2)} €
                    </td>
                    <td className="py-2 px-4 text-right">
                      <button onClick={() => removeItem(item.id)} className="text-slate-300 hover:text-red-500 p-1 rounded transition-colors">
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            <div className="bg-slate-50 px-4 py-3 border-t border-slate-200">
                <button onClick={addItem} className="flex items-center gap-2 text-sm text-blue-600 font-medium hover:text-blue-700 transition-colors">
                    <Plus size={16} /> Ajouter une ligne
                </button>
            </div>
          </div>

          <div className="flex justify-between items-center pt-4">
            <div>
                 <label className="block text-sm font-semibold text-slate-700 mb-1">Notes (Optionnel)</label>
                 <textarea 
                   className="w-80 p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-1 focus:ring-blue-500 outline-none"
                   rows={2}
                   placeholder="Conditions de paiement..."
                   value={newInvoiceData.notes || ''}
                   onChange={e => setNewInvoiceData({...newInvoiceData, notes: e.target.value})}
                 />
            </div>
            <div className="text-right">
                 <p className="text-sm text-slate-500 mb-1">Total à payer</p>
                 <div className="text-3xl font-bold text-slate-900 mb-4">
                    {(newInvoiceData.items?.reduce((acc, i) => acc + (i.quantity * i.unitPrice), 0) || 0).toFixed(2)} €
                 </div>
                 <button 
                    onClick={saveInvoice}
                    className="bg-blue-600 text-white px-8 py-3 rounded-xl hover:bg-blue-700 font-semibold shadow-lg shadow-blue-900/20 transition-all hover:scale-[1.02]"
                >
                    Enregistrer la facture
                </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'detail' && selectedInvoice) {
    const client = clients.find(c => c.id === selectedInvoice.clientId);
    return (
      <div className="max-w-4xl mx-auto animate-fade-in pb-10">
        {/* Actions Bar (Hidden on Print) */}
        <div className="sticky top-0 z-10 bg-slate-50/80 backdrop-blur-md py-4 mb-6 flex justify-between items-center print:hidden border-b border-slate-200">
          <button onClick={() => setView('list')} className="flex items-center gap-2 text-slate-600 hover:text-slate-900 font-medium px-4 py-2 hover:bg-white rounded-lg transition-all">
            <ArrowLeft size={18} /> Retour
          </button>

          <div className="flex items-center gap-3">
            <div className="flex items-center gap-2 bg-white border border-slate-200 rounded-lg p-1 pr-3">
                <span className="text-xs font-semibold text-slate-500 uppercase tracking-wide ml-2">Statut</span>
                <select 
                value={selectedInvoice.status}
                onChange={(e) => updateStatus(selectedInvoice.id, e.target.value as InvoiceStatus)}
                className={`text-sm font-medium rounded-md py-1 px-2 cursor-pointer outline-none
                    ${selectedInvoice.status === InvoiceStatus.PAID ? 'bg-green-100 text-green-700' : 
                    selectedInvoice.status === InvoiceStatus.SENT ? 'bg-orange-100 text-orange-700' :
                    'bg-slate-100 text-slate-700'}`}
                >
                {Object.values(InvoiceStatus).map(s => <option key={s} value={s}>{s}</option>)}
                </select>
            </div>

            <button 
              onClick={() => window.print()}
              className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 transition-colors shadow-md"
            >
              <Printer size={16} /> Imprimer
            </button>
          </div>
        </div>

        {/* Invoice Preview - Paper Look */}
        <div 
            className="bg-white p-12 shadow-2xl shadow-slate-200 rounded-sm min-h-[1000px] relative mx-auto print:shadow-none print:w-full" 
            id="invoice-preview"
            style={{ maxWidth: '210mm' }}
        >
          {/* Header */}
          <div className="flex justify-between items-start mb-16">
            <div>
               <div className="flex items-center gap-3 mb-6">
                 <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center text-white">
                    <FileText size={20} />
                 </div>
                 <h1 className="text-2xl font-bold text-slate-900 tracking-tight uppercase">{userProfile.companyName}</h1>
               </div>
               <div className="text-sm text-slate-500 leading-relaxed">
                <p>{userProfile.address}</p>
                <p>{userProfile.email} | {userProfile.phone}</p>
                <p className="mt-1 font-mono text-xs">SIRET: {userProfile.siret}</p>
              </div>
            </div>
            <div className="text-right">
              <h2 className="text-4xl font-light text-slate-900 mb-2">FACTURE</h2>
              <p className="text-slate-400 font-mono">#{selectedInvoice.number}</p>

              <div className="mt-8 text-right">
                <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Destinataire</h3>
                <p className="font-bold text-slate-900 text-lg">{client?.name}</p>
                <p className="text-sm text-slate-500 whitespace-pre-line">{client?.address}</p>
                {client?.siret && <p className="text-xs text-slate-400 mt-1">SIRET: {client.siret}</p>}
              </div>
            </div>
          </div>

          {/* Dates */}
          <div className="flex gap-12 mb-12 border-t border-b border-slate-100 py-6">
             <div>
                <span className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Date d'émission</span>
                <span className="font-medium text-slate-900">{new Date(selectedInvoice.date).toLocaleDateString('fr-FR')}</span>
             </div>
             <div>
                <span className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Date d'échéance</span>
                <span className="font-medium text-slate-900">{new Date(selectedInvoice.dueDate).toLocaleDateString('fr-FR')}</span>
             </div>
          </div>

          {/* Items */}
          <table className="w-full mb-12">
            <thead>
              <tr className="border-b border-slate-900 text-left text-xs font-bold text-slate-900 uppercase tracking-wider">
                <th className="py-4">Description</th>
                <th className="py-4 text-right">Qté</th>
                <th className="py-4 text-right">Prix Unitaire</th>
                <th className="py-4 text-right">Total</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm">
              {selectedInvoice.items.map((item, idx) => (
                <tr key={idx}>
                  <td className="py-5 text-slate-800 font-medium">{item.description}</td>
                  <td className="py-5 text-right text-slate-500">{item.quantity}</td>
                  <td className="py-5 text-right text-slate-500">{item.unitPrice.toFixed(2)} €</td>
                  <td className="py-5 text-right font-bold text-slate-900">{(item.quantity * item.unitPrice).toFixed(2)} €</td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* Totals */}
          <div className="flex justify-end mb-16">
            <div className="w-1/3">
              <div className="flex justify-between mb-3 text-sm">
                <span className="text-slate-500">Total HT</span>
                <span className="font-medium text-slate-900">{selectedInvoice.total.toFixed(2)} €</span>
              </div>
              <div className="flex justify-between mb-4 text-sm">
                <span className="text-slate-500">TVA (non applicable)</span>
                <span className="font-medium text-slate-900">0.00 €</span>
              </div>
              <div className="flex justify-between border-t-2 border-slate-900 pt-4 text-xl font-bold">
                <span>Total TTC</span>
                <span className="text-blue-600">{selectedInvoice.total.toFixed(2)} €</span>
              </div>
            </div>
          </div>

          {/* Footer Notes */}
          <div className="absolute bottom-12 left-12 right-12 text-center">
             {selectedInvoice.notes && (
                 <div className="mb-6 bg-slate-50 p-4 rounded-lg text-sm text-slate-600 text-left border border-slate-100">
                     <span className="font-bold block mb-1 text-slate-900">Notes:</span>
                     {selectedInvoice.notes}
                 </div>
             )}
            <div className="text-[10px] text-slate-400 leading-relaxed border-t border-slate-100 pt-6">
                <p>TVA non applicable, art. 293 B du CGI.</p>
                {userProfile.bankAccount && <p className="mt-1 font-mono text-slate-500">IBAN : {userProfile.bankAccount}</p>}
                <p className="mt-2">En cas de retard de paiement, une pénalité de 3 fois le taux d'intérêt légal sera appliquée. 
                Une indemnité forfaitaire de 40€ pour frais de recouvrement sera due.</p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // List View
  return (
    <div className="space-y-6 max-w-7xl mx-auto animate-fade-in">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-900">Factures</h2>
            <p className="text-slate-500">Gérez et suivez vos facturations.</p>
        </div>
        <button 
          onClick={() => setView('create')}
          className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20 font-medium"
        >
          <Plus size={18} />
          Créer une facture
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50/50 border-b border-slate-200 text-slate-500">
              <tr>
                <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs">Numéro</th>
                <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs">Client</th>
                <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs">Date</th>
                <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs text-right">Montant</th>
                <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs text-center">Statut</th>
                <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {invoices.map((invoice) => {
                 const clientName = clients.find(c => c.id === invoice.clientId)?.name || 'Client Inconnu';
                 return (
                  <tr key={invoice.id} className="hover:bg-slate-50 transition-colors group">
                    <td className="px-6 py-4 font-mono font-medium text-slate-700">{invoice.number}</td>
                    <td className="px-6 py-4 text-slate-900 font-medium">{clientName}</td>
                    <td className="px-6 py-4 text-slate-500">{new Date(invoice.date).toLocaleDateString()}</td>
                    <td className="px-6 py-4 text-right font-bold text-slate-900">{invoice.total.toFixed(2)} €</td>
                    <td className="px-6 py-4 text-center">
                      <span className={`inline-flex px-3 py-1 rounded-full text-xs font-semibold border
                        ${invoice.status === InvoiceStatus.PAID ? 'bg-green-50 text-green-700 border-green-200' : 
                          invoice.status === InvoiceStatus.SENT ? 'bg-orange-50 text-orange-700 border-orange-200' :
                          'bg-slate-100 text-slate-600 border-slate-200'}`}>
                        {invoice.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                            onClick={() => { setSelectedInvoice(invoice); setView('detail'); }}
                            className="text-blue-600 hover:bg-blue-50 p-2 rounded-lg transition-colors"
                            title="Voir / Imprimer"
                        >
                            <Printer size={16} />
                        </button>
                        <button 
                            onClick={() => deleteInvoice(invoice.id)}
                            className="text-slate-400 hover:text-red-500 hover:bg-red-50 p-2 rounded-lg transition-colors"
                            title="Supprimer"
                        >
                            <Trash2 size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
              {invoices.length === 0 && (
                <tr>
                  <td colSpan={6} className="py-16 text-center">
                    <div className="flex flex-col items-center justify-center text-slate-400">
                        <FileText size={48} className="mb-4 opacity-20" />
                        <p className="text-lg font-medium text-slate-600">Aucune facture</p>
                        <p className="text-sm">Commencez par en créer une nouvelle.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default InvoiceManager;

import React, { useState } from 'react';
import { Client } from '../types';
import { Plus, Search, Trash2, Mail, MapPin, Phone, Building } from 'lucide-react';

interface ClientManagerProps {
  clients: Client[];
  setClients: (clients: Client[]) => void;
}

const ClientManager: React.FC<ClientManagerProps> = ({ clients, setClients }) => {
  const [showForm, setShowForm] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [newClient, setNewClient] = useState<Partial<Client>>({
    name: '',
    email: '',
    address: '',
    siret: '',
    phone: ''
  });

  const handleAddClient = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newClient.name || !newClient.email) return;

    const client: Client = {
      id: Date.now().toString(),
      name: newClient.name,
      email: newClient.email,
      address: newClient.address || '',
      siret: newClient.siret,
      phone: newClient.phone
    };

    setClients([...clients, client]);
    setNewClient({ name: '', email: '', address: '', siret: '', phone: '' });
    setShowForm(false);
  };

  const handleDeleteClient = (id: string) => {
    if (confirm('Êtes-vous sûr de vouloir supprimer ce client ?')) {
      setClients(clients.filter(c => c.id !== id));
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-fade-in max-w-7xl mx-auto">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Clients</h2>
          <p className="text-slate-500">Gérez votre carnet d'adresses</p>
        </div>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20 font-medium"
        >
          <Plus size={18} />
          Nouveau Client
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-8 rounded-2xl shadow-lg border border-slate-100 animate-slide-in relative z-10">
          <h3 className="text-lg font-bold text-slate-900 mb-6">Ajouter un client</h3>
          <form onSubmit={handleAddClient} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Nom / Société *</label>
              <input 
                type="text" 
                required
                className="w-full p-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-shadow"
                value={newClient.name}
                onChange={e => setNewClient({...newClient, name: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Email *</label>
              <input 
                type="email" 
                required
                className="w-full p-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-shadow"
                value={newClient.email}
                onChange={e => setNewClient({...newClient, email: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">SIRET</label>
              <input 
                type="text" 
                className="w-full p-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-shadow"
                value={newClient.siret}
                onChange={e => setNewClient({...newClient, siret: e.target.value})}
              />
            </div>
             <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Téléphone</label>
              <input 
                type="tel" 
                className="w-full p-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-shadow"
                value={newClient.phone}
                onChange={e => setNewClient({...newClient, phone: e.target.value})}
              />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-semibold text-slate-700 mb-1">Adresse complète</label>
              <textarea 
                className="w-full p-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-shadow"
                rows={2}
                value={newClient.address}
                onChange={e => setNewClient({...newClient, address: e.target.value})}
              />
            </div>
            <div className="md:col-span-2 flex justify-end gap-3 mt-4">
              <button 
                type="button" 
                onClick={() => setShowForm(false)}
                className="px-5 py-2.5 text-slate-600 hover:bg-slate-50 rounded-xl font-medium transition-colors"
              >
                Annuler
              </button>
              <button 
                type="submit" 
                className="px-5 py-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-medium shadow-md transition-all hover:scale-[1.02]"
