                 <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 text-white flex items-center justify-center font-bold text-xl shadow-md">
                   {client.name.charAt(0).toUpperCase()}
                 </div>
                 <div className="overflow-hidden">
                   <h4 className="font-bold text-slate-900 truncate pr-4 text-lg">{client.name}</h4>
                   <p className="text-xs font-mono text-slate-400">ID: {client.id.substring(client.id.length - 4)}</p>
                 </div>
               </div>

               <div className="space-y-3 text-sm text-slate-600 border-t border-slate-50 pt-4">
                 <div className="flex items-center gap-3">
                   <div className="p-1.5 bg-slate-50 rounded-md text-slate-400">
                     <Mail size={14} />
                   </div>
                   <span className="truncate font-medium">{client.email}</span>
                 </div>
                 {client.phone && (
                   <div className="flex items-center gap-3">
                     <div className="p-1.5 bg-slate-50 rounded-md text-slate-400">
                        <Phone size={14} />
                     </div>
                     <span>{client.phone}</span>
                   </div>
                 )}
                 {client.siret && (
                   <div className="flex items-center gap-3">
                     <div className="p-1.5 bg-slate-50 rounded-md text-slate-400">
                        <Building size={14} />
                     </div>
                     <span>{client.siret}</span>
