import { Send, Bot, User, Sparkles, MessageSquare } from 'lucide-react';

const AIAssistant: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      role: 'model',
      content: "Bonjour ! Je suis votre assistant administratif virtuel. Je peux vous aider avec vos questions sur le statut auto-entrepreneur, les déclarations URSSAF, ou la rédaction de courriers. Comment puis-je vous aider aujourd'hui ?",
      timestamp: Date.now()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    // Build context from last few messages
    const context = messages.slice(-3).map(m => `${m.role}: ${m.content}`).join('\n');

    const responseText = await generateAssistantResponse(userMsg.content, context);

    const modelMsg: ChatMessage = { role: 'model', content: responseText, timestamp: Date.now() };
    setMessages(prev => [...prev, modelMsg]);
    setIsLoading(false);
  };

  return (
    <div className="h-[calc(100vh-6rem)] max-w-5xl mx-auto flex flex-col bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden animate-fade-in">
      <div className="bg-gradient-to-r from-blue-700 to-indigo-700 p-6 flex items-center justify-between">
        <div className="flex items-center gap-4">
            <div className="p-2.5 bg-white/20 backdrop-blur-md rounded-xl shadow-inner">
                <Sparkles className="text-white" size={24} />
            </div>
            <div>
                <h2 className="text-white font-bold text-lg">Assistant Administratif</h2>
                <div className="flex items-center gap-2">
                    <span className="relative flex h-2 w-2">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                    </span>
                    <p className="text-blue-100 text-xs font-medium">En ligne • Propulsé par Google Gemini</p>
                </div>
            </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/50 scroll-smooth">
        {messages.map((msg, idx) => (
          <div 
            key={idx} 
            className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
          >
            <div className={`
              w-10 h-10 rounded-full flex items-center justify-center shrink-0 shadow-sm border
              ${msg.role === 'user' ? 'bg-slate-800 border-slate-700 text-white' : 'bg-white border-slate-200 text-blue-600'}
            `}>
              {msg.role === 'user' ? <User size={18} /> : <Bot size={20} />}
            </div>

            <div className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`
                max-w-[85%] px-5 py-3.5 text-sm leading-relaxed whitespace-pre-wrap shadow-sm
                ${msg.role === 'user' 
                    ? 'bg-blue-600 text-white rounded-2xl rounded-tr-sm' 
                    : 'bg-white text-slate-800 rounded-2xl rounded-tl-sm border border-slate-100'}
                `}>
                {msg.content}
                </div>
                <span className="text-[10px] text-slate-400 mt-1 px-1">
                    {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                </span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex items-start gap-4">
             <div className="w-10 h-10 rounded-full bg-white border border-slate-200 text-blue-600 flex items-center justify-center shrink-0 shadow-sm">
               <Bot size={20} />
             </div>
             <div className="bg-white px-5 py-4 rounded-2xl rounded-tl-sm border border-slate-100 shadow-sm">
               <div className="flex gap-1.5">
                 <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce"></div>
                 <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-.15s]"></div>
                 <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-.3s]"></div>
               </div>
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <form onSubmit={handleSend} className="p-6 bg-white border-t border-slate-100">
        <div className="relative flex gap-3">
          <input
            type="text"
            className="flex-1 pl-5 pr-12 py-3.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 outline-none transition-all shadow-sm bg-slate-50 focus:bg-white"
            placeholder="Posez une question (ex: Comment déclarer mon CA ?)"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={isLoading}
          />
          <button 
            type="submit"
            disabled={isLoading || !input.trim()}
            className="px-6 py-3.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 disabled:opacity-50 disabled:hover:bg-blue-600 transition-all font-medium shadow-md flex items-center gap-2"
          >
            <span>Envoyer</span>
            <Send size={18} />
          </button>
        </div>
        <div className="text-center mt-3">
            <p className="text-[10px] text-slate-400 flex items-center justify-center gap-1.5">
                <MessageSquare size={10} />
                L'IA peut commettre des erreurs. Vérifiez toujours les informations légales.
            </p>
        </div>
      </form>
    </div>
  );
};

export default AIAssistant;

import React, { useState } from 'react';
import { Supplier } from '../types';
import { Plus, Search, Trash2, Mail, MapPin, Phone, Truck, Package } from 'lucide-react';

interface SupplierManagerProps {
  suppliers: Supplier[];
  setSuppliers: (suppliers: Supplier[]) => void;
}

const SupplierManager: React.FC<SupplierManagerProps> = ({ suppliers, setSuppliers }) => {
  const [showForm, setShowForm] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [newSupplier, setNewSupplier] = useState<Partial<Supplier>>({
    name: '',
    email: '',
    address: '',
    phone: '',
    category: ''
  });

  const handleAddSupplier = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newSupplier.name) return;

    const supplier: Supplier = {
      id: Date.now().toString(),
      name: newSupplier.name!,
      email: newSupplier.email,
      address: newSupplier.address,
      phone: newSupplier.phone,
      category: newSupplier.category
    };

    setSuppliers([...suppliers, supplier]);
    setNewSupplier({ name: '', email: '', address: '', phone: '', category: '' });
    setShowForm(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Supprimer ce fournisseur ?')) {
      setSuppliers(suppliers.filter(s => s.id !== id));
    }
  };

  const filteredSuppliers = suppliers.filter(s => 
    s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    (s.category && s.category.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  return (
    <div className="space-y-8 animate-fade-in max-w-7xl mx-auto">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Fournisseurs</h2>
          <p className="text-slate-500">Gérez vos partenaires et achats</p>
        </div>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20 font-medium"
        >
          <Plus size={18} />
          Nouveau Fournisseur
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-8 rounded-2xl shadow-lg border border-slate-100 animate-slide-in relative z-10">
          <h3 className="text-lg font-bold text-slate-900 mb-6">Ajouter un fournisseur</h3>
          <form onSubmit={handleAddSupplier} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Nom / Société *</label>
              <input 
                type="text" 
                required
                className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-shadow"
                value={newSupplier.name}
                onChange={e => setNewSupplier({...newSupplier, name: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Catégorie (ex: Logiciel, Matériel)</label>
              <input 
                type="text" 
                className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-shadow"
                value={newSupplier.category}
                onChange={e => setNewSupplier({...newSupplier, category: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Email</label>
              <input 
                type="email" 
                className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-shadow"
                value={newSupplier.email}
                onChange={e => setNewSupplier({...newSupplier, email: e.target.value})}
              />
            </div>
             <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Téléphone</label>
              <input 
                type="tel" 
                className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-shadow"
                value={newSupplier.phone}
                onChange={e => setNewSupplier({...newSupplier, phone: e.target.value})}
              />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-semibold text-slate-700 mb-1">Adresse</label>
              <input 
                type="text"
                className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-shadow"
                value={newSupplier.address}
                onChange={e => setNewSupplier({...newSupplier, address: e.target.value})}
              />
            </div>
            <div className="md:col-span-2 flex justify-end gap-3 mt-4">
              <button 
                type="button" 
                onClick={() => setShowForm(false)}
                className="px-5 py-2.5 text-slate-600 hover:bg-slate-50 rounded-xl font-medium transition-colors"
              >
                Annuler
              </button>
              <button 
                type="submit" 
                className="px-5 py-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-medium shadow-md transition-all hover:scale-[1.02]"
              >
                Enregistrer
              </button>
            </div>
          </form>
        </div>
      )}

      {/* List */}
      <div>
        <div className="mb-6 relative max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher..."
              className="w-full pl-10 pr-4 py-2.5 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/50 bg-white shadow-sm transition-all"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredSuppliers.map(supplier => (
            <div key={supplier.id} className="bg-white border border-slate-100 rounded-2xl p-6 hover:shadow-lg hover:-translate-y-1 transition-all duration-300 group relative">
               <button 
                onClick={() => handleDelete(supplier.id)}
                className="absolute top-4 right-4 text-slate-300 hover:text-red-500 hover:bg-red-50 p-1.5 rounded-lg opacity-0 group-hover:opacity-100 transition-all"
                title="Supprimer"
               >
                 <Trash2 size={16} />
               </button>

               <div className="flex items-center gap-4 mb-4">
                 <div className="w-12 h-12 rounded-xl bg-slate-50 text-slate-600 flex items-center justify-center border border-slate-100">
                   <Truck size={24} className="opacity-80" />
                 </div>
                 <div className="overflow-hidden">
                   <h4 className="font-bold text-slate-900 truncate pr-4 text-lg">{supplier.name}</h4>
                   <p className="text-xs font-semibold text-blue-600 bg-blue-50 px-2 py-0.5 rounded-md inline-block mt-1">
                     {supplier.category || 'Général'}
                   </p>
                 </div>
               </div>

               <div className="space-y-3 text-sm text-slate-600 border-t border-slate-50 pt-4">
                 {supplier.email && (
                   <div className="flex items-center gap-3">
                     <div className="p-1.5 bg-slate-50 rounded-md text-slate-400">
                        <Mail size={14} />
                     </div>
                     <span className="truncate">{supplier.email}</span>
                   </div>
                 )}
                 {supplier.phone && (
                   <div className="flex items-center gap-3">
                     <div className="p-1.5 bg-slate-50 rounded-md text-slate-400">
                        <Phone size={14} />
                     </div>
                     <span>{supplier.phone}</span>
                   </div>
                 )}
                 {supplier.address && (
                   <div className="flex items-start gap-3">
                     <div className="p-1.5 bg-slate-50 rounded-md text-slate-400 mt-0.5">
                        <MapPin size={14} />
                     </div>
                     <span className="line-clamp-2">{supplier.address}</span>
                   </div>
                 )}
               </div>
            </div>
          ))}

          {filteredSuppliers.length === 0 && (
             <div className="col-span-full py-20 text-center">
               <div className="inline-block p-4 rounded-full bg-slate-50 mb-4">
                   <Package size={32} className="text-slate-300" />
               </div>
               <p className="text-slate-500">Aucun fournisseur trouvé.</p>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default SupplierManager;

import React, { useState } from 'react';
import { Product } from '../types';
import { Plus, Search, Trash2, Package, Tag, Briefcase } from 'lucide-react';

interface ProductManagerProps {
  products: Product[];
  setProducts: (products: Product[]) => void;
}

const ProductManager: React.FC<ProductManagerProps> = ({ products, setProducts }) => {
  const [showForm, setShowForm] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [newProduct, setNewProduct] = useState<Partial<Product>>({
    name: '',
    description: '',
    price: 0,
    type: 'service'
  });

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.name) return;

    const product: Product = {
      id: Date.now().toString(),
      name: newProduct.name!,
      description: newProduct.description || '',
      price: Number(newProduct.price) || 0,
      type: newProduct.type as 'service' | 'product'
    };

    setProducts([...products, product]);
    setNewProduct({ name: '', description: '', price: 0, type: 'service' });
    setShowForm(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Supprimer cet élément du catalogue ?')) {
      setProducts(products.filter(p => p.id !== id));
    }
  };

  const filteredProducts = products.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-fade-in max-w-7xl mx-auto">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Produits & Services</h2>
          <p className="text-slate-500">Gérez votre catalogue de prestations</p>
        </div>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20 font-medium"
        >
          <Plus size={18} />
          Nouvel Élément
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-8 rounded-2xl shadow-lg border border-slate-100 animate-slide-in relative z-10">
          <h3 className="text-lg font-bold text-slate-900 mb-6">Ajouter au catalogue</h3>
          <form onSubmit={handleAdd} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-2">
              <label className="block text-sm font-semibold text-slate-700 mb-1">Nom *</label>
              <input 
                type="text" 
                required
                className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-shadow"
                value={newProduct.name}
                onChange={e => setNewProduct({...newProduct, name: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Type</label>
              <select
                className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 bg-white transition-shadow"
                value={newProduct.type}
                onChange={e => setNewProduct({...newProduct, type: e.target.value as 'service' | 'product'})}
              >
                <option value="service">Prestation de Service</option>
                <option value="product">Vente de Marchandise</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Prix Unitaire (EUR)</label>
              <input 
                type="number" 
                step="0.01"
                className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-shadow"
                value={newProduct.price}
                onChange={e => setNewProduct({...newProduct, price: parseFloat(e.target.value)})}
              />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-semibold text-slate-700 mb-1">Description (par défaut)</label>
              <textarea 
                rows={2}
                className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-shadow"
                value={newProduct.description}
                onChange={e => setNewProduct({...newProduct, description: e.target.value})}
              />
            </div>
            <div className="md:col-span-2 flex justify-end gap-3 mt-4">
              <button 
                type="button" 
                onClick={() => setShowForm(false)}
                className="px-5 py-2.5 text-slate-600 hover:bg-slate-50 rounded-xl font-medium transition-colors"
              >
                Annuler
              </button>
              <button 
                type="submit" 
                className="px-5 py-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-medium shadow-md transition-all hover:scale-[1.02]"
              >
                Enregistrer
              </button>
            </div>
          </form>
        </div>
      )}

      {/* List */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50/50">
           <div className="relative max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher un service ou produit..."
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500/50 bg-white"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
           </div>
        </div>

        <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 border-b border-slate-200 text-slate-500">
              <tr>
                <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs w-16">Type</th>
                <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs">Nom</th>
                <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs">Description</th>
                <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs text-right">Prix</th>
                <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs text-right w-20"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredProducts.map((p) => (
                <tr key={p.id} className="hover:bg-slate-50 transition-colors group">
                  <td className="px-6 py-4">
                     {p.type === 'service' ? 
                       <div className="p-2 bg-blue-50 rounded-lg text-blue-600 inline-block">
                         <Briefcase size={16} title="Service" /> 
                       </div>
                       : 
                       <div className="p-2 bg-orange-50 rounded-lg text-orange-600 inline-block">
                         <Package size={16} title="Marchandise" />
                       </div>
                     }
                  </td>
                  <td className="px-6 py-4 font-bold text-slate-900">{p.name}</td>
                  <td className="px-6 py-4 text-slate-500 truncate max-w-xs">{p.description}</td>
                  <td className="px-6 py-4 text-right font-mono font-medium text-slate-900">{p.price.toFixed(2)} €</td>
                  <td className="px-6 py-4 text-right">
                    <button 
                      onClick={() => handleDelete(p.id)}
                      className="text-slate-300 hover:text-red-500 transition-colors p-2 rounded-lg hover:bg-red-50"
                    >
                      <Trash2 size={16} />
                    </button>
                  </td>
                </tr>
              ))}
               {filteredProducts.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-16 text-center text-slate-400">
                    Catalogue vide.
                  </td>
                </tr>
              )}
            </tbody>
        </table>
      </div>
    </div>
  );
};

export default ProductManager;

import React, { useState } from 'react';
import { Client } from '../types';
import { Plus, Search, Trash2, Mail, MapPin, Phone, Building, Users } from 'lucide-react';

interface ClientManagerProps {
  clients: Client[];
  setClients: (clients: Client[]) => void;
}

const ClientManager: React.FC<ClientManagerProps> = ({ clients, setClients }) => {
  const [showForm, setShowForm] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [newClient, setNewClient] = useState<Partial<Client>>({
    name: '',
    email: '',
    address: '',
    siret: '',
    phone: ''
  });

  const handleAddClient = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newClient.name || !newClient.email) return;

    const client: Client = {
      id: Date.now().toString(),
      name: newClient.name,
      email: newClient.email,
      address: newClient.address || '',
      siret: newClient.siret,
      phone: newClient.phone
    };

    setClients([...clients, client]);
    setNewClient({ name: '', email: '', address: '', siret: '', phone: '' });
    setShowForm(false);
  };

  const handleDeleteClient = (id: string) => {
    if (confirm('Êtes-vous sûr de vouloir supprimer ce client ?')) {
      setClients(clients.filter(c => c.id !== id));
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-fade-in max-w-7xl mx-auto">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Clients</h2>
          <p className="text-slate-500">Gérez votre carnet d'adresses</p>
        </div>
        <button 
          onClick={() => setShowForm(!showForm)}
