      {showForm && (
        <div className="bg-white p-8 rounded-2xl shadow-lg border border-slate-100 animate-slide-in relative z-10">
          <h3 className="text-lg font-bold text-slate-900 mb-6">Ajouter un client</h3>
          <form onSubmit={handleAddClient} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Nom / Société *</label>
              <input 
                type="text" 
                required
                className="w-full p-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-shadow"
