              <button 
                type="submit" 
                className="px-5 py-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-medium shadow-md transition-all hover:scale-[1.02]"
              >
                Enregistrer
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Search & List */}
      <div>
        <div className="mb-6 relative max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher par nom, email..."
              className="w-full pl-10 pr-4 py-2.5 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/50 bg-white shadow-sm transition-all"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredClients.map(client => (
            <div key={client.id} className="bg-white border border-slate-100 rounded-2xl p-6 hover:shadow-lg hover:-translate-y-1 transition-all duration-300 group relative">
               <button 
                onClick={() => handleDeleteClient(client.id)}
                className="absolute top-4 right-4 text-slate-300 hover:text-red-500 hover:bg-red-50 p-1.5 rounded-lg opacity-0 group-hover:opacity-100 transition-all"
                title="Supprimer"
               >
                 <Trash2 size={16} />
               </button>

               <div className="flex items-center gap-4 mb-4">
                 <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 text-white flex items-center justify-center font-bold text-xl shadow-md">
                   {client.name.charAt(0).toUpperCase()}
                 </div>
                 <div className="overflow-hidden">
                   <h4 className="font-bold text-slate-900 truncate pr-4 text-lg">{client.name}</h4>
                   <p className="text-xs font-mono text-slate-400">ID: {client.id.substring(client.id.length - 4)}</p>
                 </div>
               </div>

               <div className="space-y-3 text-sm text-slate-600 border-t border-slate-50 pt-4">
                 <div className="flex items-center gap-3">
                   <div className="p-1.5 bg-slate-50 rounded-md text-slate-400">
                     <Mail size={14} />
                   </div>
                   <span className="truncate font-medium">{client.email}</span>
                 </div>
                 {client.phone && (
                   <div className="flex items-center gap-3">
                     <div className="p-1.5 bg-slate-50 rounded-md text-slate-400">
                        <Phone size={14} />
                     </div>
                     <span>{client.phone}</span>
                   </div>
                 )}
                 {client.siret && (
                   <div className="flex items-center gap-3">
                     <div className="p-1.5 bg-slate-50 rounded-md text-slate-400">
                        <Building size={14} />
                     </div>
                     <span>{client.siret}</span>
                   </div>
                 )}
                 {client.address && (
                   <div className="flex items-start gap-3">
                     <div className="p-1.5 bg-slate-50 rounded-md text-slate-400 mt-0.5">
                        <MapPin size={14} />
                     </div>
                     <span className="line-clamp-2">{client.address}</span>
                   </div>
                 )}
               </div>
            </div>
          ))}

          {filteredClients.length === 0 && (
             <div className="col-span-full py-20 text-center">
               <div className="inline-block p-4 rounded-full bg-slate-50 mb-4">
                   <Users size={32} className="text-slate-300" />
               </div>
               <p className="text-slate-500">Aucun client trouvé.</p>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

