import React, { useMemo } from 'react';
import { Invoice, InvoiceStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { Euro, TrendingUp, AlertCircle, ArrowUpRight, ArrowRight } from 'lucide-react';

interface DashboardProps {
  invoices: Invoice[];
}

const Dashboard: React.FC<DashboardProps> = ({ invoices }) => {
  // Stats Calculation
  const totalRevenue = useMemo(() => {
    return invoices
      .filter(inv => inv.status === InvoiceStatus.PAID)
      .reduce((sum, inv) => sum + inv.total, 0);
  }, [invoices]);

  const pendingRevenue = useMemo(() => {
    return invoices
      .filter(inv => inv.status === InvoiceStatus.SENT)
      .reduce((sum, inv) => sum + inv.total, 0);
  }, [invoices]);

  const monthlyData = useMemo(() => {
    const data: Record<string, number> = {};
    const months = ['Jan', 'Fév', 'Mar', 'Avr', 'Mai', 'Juin', 'Juil', 'Août', 'Sep', 'Oct', 'Nov', 'Déc'];

    // Initialize
    months.forEach(m => data[m] = 0);

    invoices.forEach(inv => {
      if (inv.status === InvoiceStatus.PAID) {
        const date = new Date(inv.date);
        const monthIndex = date.getMonth();
        data[months[monthIndex]] += inv.total;
      }
    });

    return months.map(name => ({ name, ca: data[name] }));
  }, [invoices]);

  // Thresholds (2024 approx for services)
  const VAT_THRESHOLD = 36800;

  const progressPercentage = Math.min((totalRevenue / VAT_THRESHOLD) * 100, 100);

  return (
    <div className="space-y-10 animate-fade-in max-w-7xl mx-auto pb-10">
      <div className="flex items-end justify-between">
        <div>
           <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Bonjour,</h2>
           <p className="text-slate-500 mt-1 font-medium">Voici l'aperçu de votre activité.</p>
        </div>
        <div className="text-xs font-semibold bg-white border border-slate-200 text-slate-500 px-3 py-1.5 rounded-full">
            {new Date().toLocaleDateString('fr-FR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {/* Total Revenue Card */}
        <div className="bg-white p-8 rounded-[2rem] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 hover:shadow-[0_8px_30px_rgb(0,0,0,0.08)] transition-all duration-500 group relative overflow-hidden">
          <div className="absolute -right-10 -top-10 w-40 h-40 bg-blue-50 rounded-full blur-3xl opacity-50 group-hover:opacity-100 transition-opacity"></div>

          <div className="flex justify-between items-start mb-6 relative z-10">
            <div className="p-3.5 bg-blue-50 text-blue-600 rounded-2xl group-hover:scale-110 transition-transform duration-300">
              <Euro size={26} />
            </div>
            <span className="flex items-center text-xs font-bold text-emerald-600 bg-emerald-50 px-2.5 py-1 rounded-full border border-emerald-100">
              <TrendingUp size={12} className="mr-1.5" />
              +12%
            </span>
          </div>
          <div className="relative z-10">
            <p className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Chiffre d'Affaires</p>
            <h3 className="text-4xl font-bold text-slate-900 mt-2 tracking-tight">
              {totalRevenue.toLocaleString('fr-FR', { style: 'currency', currency: 'EUR', maximumFractionDigits: 0 })}
            </h3>
          </div>
        </div>

        {/* Pending Card */}
        <div className="bg-white p-8 rounded-[2rem] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 hover:shadow-[0_8px_30px_rgb(0,0,0,0.08)] transition-all duration-500 group relative overflow-hidden">
           <div className="absolute -right-10 -top-10 w-40 h-40 bg-orange-50 rounded-full blur-3xl opacity-50 group-hover:opacity-100 transition-opacity"></div>

          <div className="flex justify-between items-start mb-6 relative z-10">
             <div className="p-3.5 bg-orange-50 text-orange-600 rounded-2xl group-hover:scale-110 transition-transform duration-300">
              <AlertCircle size={26} />
            </div>
          </div>
          <div className="relative z-10">
            <p className="text-sm font-semibold text-slate-400 uppercase tracking-wider">En attente</p>
            <h3 className="text-4xl font-bold text-slate-900 mt-2 tracking-tight">
              {pendingRevenue.toLocaleString('fr-FR', { style: 'currency', currency: 'EUR', maximumFractionDigits: 0 })}
            </h3>
            <p className="text-xs text-slate-400 mt-3 font-medium bg-slate-50 inline-block px-2 py-1 rounded-lg">
              {invoices.filter(i => i.status === InvoiceStatus.SENT).length} factures non réglées
            </p>
          </div>
        </div>

        {/* VAT Threshold Card */}
        <div className="bg-slate-900 p-8 rounded-[2rem] shadow-xl shadow-slate-200 text-white relative overflow-hidden group">
           <div className="absolute -right-4 -bottom-4 opacity-10 rotate-12 group-hover:rotate-0 transition-transform duration-700">
             <ArrowUpRight size={140} />
           </div>

          <div className="relative z-10 h-full flex flex-col justify-between">
            <div>
                 <p className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Franchise TVA</p>
                 <div className="flex justify-between items-end mt-2 mb-4">
                    <h3 className="text-4xl font-bold">{progressPercentage.toFixed(0)}%</h3>
                    <span className="text-xs font-medium text-slate-300 mb-1.5">
                        {VAT_THRESHOLD.toLocaleString()}€ max
                    </span>
                 </div>
                 <div className="w-full bg-slate-800 rounded-full h-2 overflow-hidden">
                    <div 
                        className={`h-full rounded-full transition-all duration-1000 ease-out ${progressPercentage > 85 ? 'bg-red-400' : 'bg-gradient-to-r from-blue-400 to-indigo-400'}`} 
                        style={{ width: `${progressPercentage}%` }}
                    ></div>
                 </div>
            </div>

            <p className="mt-6 text-xs text-slate-400 font-medium leading-relaxed border-t border-slate-800 pt-4">
              {totalRevenue < VAT_THRESHOLD 
                ? "Vous êtes toujours en franchise de base TVA." 
                : "Seuil dépassé. TVA applicable."}
            </p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Chart Section */}
        <div className="lg:col-span-2 bg-white p-8 rounded-[2rem] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-lg font-bold text-slate-900">Évolution du CA</h3>
            <div className="flex gap-2">
                 <span className="w-3 h-3 rounded-full bg-blue-500"></span>
                 <span className="text-xs text-slate-500 font-medium">Revenus 2024</span>
            </div>
          </div>

          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={monthlyData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }} barSize={32}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="name" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fill: '#94a3b8', fontSize: 12, fontWeight: 500 }} 
                  dy={15}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fill: '#94a3b8', fontSize: 12, fontWeight: 500 }}
                  tickFormatter={(value) => `${value/1000}k`}
                />
                <Tooltip 
                  cursor={{ fill: '#f8fafc', radius: 12 }}
                  contentStyle={{ 
                    borderRadius: '16px', 
                    border: 'none', 
                    boxShadow: '0 10px 40px -10px rgba(0,0,0,0.1)',
                    padding: '16px',
                    backgroundColor: 'white',
                    fontFamily: 'Inter'
                  }}
                  formatter={(value: number) => [`${value} €`, 'CA']}
                />
                <Bar dataKey="ca" radius={[8, 8, 8, 8]}>
                  {monthlyData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.ca > 0 ? "#3b82f6" : "#f1f5f9"} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Recent Activity List */}
        <div className="bg-white p-8 rounded-[2rem] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 flex flex-col">
          <div className="flex justify-between items-center mb-8">
             <h3 className="text-lg font-bold text-slate-900">Activité récente</h3>
             <button className="text-xs font-semibold text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full hover:bg-blue-100 transition-colors flex items-center">
               Tout voir <ArrowRight size={12} className="ml-1" />
             </button>
          </div>

          <div className="flex-1 overflow-auto -mx-2 px-2 custom-scrollbar">
            <div className="space-y-4">
              {invoices.slice(0, 5).map((invoice) => (
                <div key={invoice.id} className="flex items-center justify-between p-3 hover:bg-slate-50 rounded-2xl transition-all duration-300 group cursor-pointer border border-transparent hover:border-slate-100">
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-sm font-bold shadow-sm
                      ${invoice.status === InvoiceStatus.PAID ? 'bg-emerald-100 text-emerald-600' : 
                        invoice.status === InvoiceStatus.SENT ? 'bg-amber-100 text-amber-600' :
                        'bg-slate-100 text-slate-500'}`}>
                      {invoice.status === InvoiceStatus.PAID ? '€' : '#'}
                    </div>
                    <div>
                      <p className="text-sm font-bold text-slate-900">{invoice.number}</p>
                      <p className="text-xs font-medium text-slate-400">{invoice.date}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-sm font-bold text-slate-900">{invoice.total.toFixed(0)} €</p>
                    <span className={`text-[10px] font-bold uppercase tracking-wide px-2 py-0.5 rounded-full
                         ${invoice.status === InvoiceStatus.PAID ? 'bg-emerald-50 text-emerald-600' : 
                        invoice.status === InvoiceStatus.SENT ? 'bg-amber-50 text-amber-600' :
                        'bg-slate-50 text-slate-400'}`}>
                      {invoice.status}
                    </span>
                  </div>
                </div>
              ))}
              {invoices.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-slate-400 py-10">
                  <p>Aucune activité récente.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

