import ProductManager from './components/ProductManager';
import AccountingManager from './components/AccountingManager';
import { ViewState, Invoice, Client, UserProfile, Supplier, Product, Expense } from './types';
import { Menu } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // --- STATE ---
  const [invoices, setInvoices] = useState<Invoice[]>(() => {
    const saved = localStorage.getItem('autogest_invoices');
    return saved ? JSON.parse(saved) : [];
  });

  const [clients, setClients] = useState<Client[]>(() => {
    const saved = localStorage.getItem('autogest_clients');
    return saved ? JSON.parse(saved) : [];
  });

  const [suppliers, setSuppliers] = useState<Supplier[]>(() => {
    const saved = localStorage.getItem('autogest_suppliers');
    return saved ? JSON.parse(saved) : [];
  });

  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('autogest_products');
    return saved ? JSON.parse(saved) : [];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autogest_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [userProfile, setUserProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('autogest_profile');
    return saved ? JSON.parse(saved) : {
      companyName: 'Ma Micro-Entreprise',
      siret: '123 456 789 00012',
      address: '123 Avenue de la République, 75001 Paris',
      email: 'contact@mon-entreprise.fr',
      phone: '01 02 03 04 05',
      bankAccount: 'FR76 1234 5678 9012 3456 7890 123'
    };
  });

  // --- EFFECTS ---
  useEffect(() => { localStorage.setItem('autogest_invoices', JSON.stringify(invoices)); }, [invoices]);
  useEffect(() => { localStorage.setItem('autogest_clients', JSON.stringify(clients)); }, [clients]);
  useEffect(() => { localStorage.setItem('autogest_suppliers', JSON.stringify(suppliers)); }, [suppliers]);
  useEffect(() => { localStorage.setItem('autogest_products', JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem('autogest_expenses', JSON.stringify(expenses)); }, [expenses]);
  useEffect(() => { localStorage.setItem('autogest_profile', JSON.stringify(userProfile)); }, [userProfile]);


  // --- SETTINGS VIEW COMPONENT (Inline) ---
  const SettingsView = () => (
    <div className="bg-white p-10 rounded-[2rem] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100 max-w-3xl mx-auto animate-fade-in">
      <h2 className="text-3xl font-bold mb-2 text-slate-900">Paramètres</h2>
      <p className="text-slate-500 mb-8">Informations de votre entreprise pour les factures.</p>

      <div className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Nom de l'entreprise</label>
            <input 
                type="text" 
                className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all" 
                value={userProfile.companyName}
                onChange={(e) => setUserProfile({...userProfile, companyName: e.target.value})}
            />
            </div>
            <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">SIRET</label>
            <input 
                type="text" 
                className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all" 
                value={userProfile.siret}
                onChange={(e) => setUserProfile({...userProfile, siret: e.target.value})}
            />
            </div>
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-2">Adresse</label>
          <textarea 
            className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all resize-none" 
            rows={3}
            value={userProfile.address}
            onChange={(e) => setUserProfile({...userProfile, address: e.target.value})}
          />
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Email</label>
                <input 
                    type="email" 
                    className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all" 
                    value={userProfile.email}
                    onChange={(e) => setUserProfile({...userProfile, email: e.target.value})}
                />
            </div>
            <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Téléphone</label>
                <input 
                    type="text" 
                    className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all" 
                    value={userProfile.phone}
                    onChange={(e) => setUserProfile({...userProfile, phone: e.target.value})}
                />
            </div>
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-2">IBAN (pour les factures)</label>
          <input 
            type="text" 
            className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-mono text-sm" 
            value={userProfile.bankAccount}
            onChange={(e) => setUserProfile({...userProfile, bankAccount: e.target.value})}
          />
        </div>
        <div className="pt-4 flex items-center gap-2 text-emerald-600 text-sm font-medium bg-emerald-50 p-4 rounded-xl border border-emerald-100">
          <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
          Les modifications sont sauvegardées automatiquement.
        </div>
      </div>
    </div>
  );

  const renderContent = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard invoices={invoices} />;
      case 'invoices':
        return <InvoiceManager invoices={invoices} setInvoices={setInvoices} clients={clients} userProfile={userProfile} />;
      case 'clients':
        return <ClientManager clients={clients} setClients={setClients} />;
      case 'suppliers':
        return <SupplierManager suppliers={suppliers} setSuppliers={setSuppliers} />;
      case 'products':
        return <ProductManager products={products} setProducts={setProducts} />;
      case 'accounting':
        return <AccountingManager expenses={expenses} setExpenses={setExpenses} invoices={invoices} suppliers={suppliers} />;
      case 'settings':
        return <SettingsView />;
      default:
        return <Dashboard invoices={invoices} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50/50 font-sans text-slate-900 selection:bg-blue-100 selection:text-blue-900">
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        isMobileMenuOpen={isMobileMenuOpen}
        setIsMobileMenuOpen={setIsMobileMenuOpen}
      />

      <main className="flex-1 lg:ml-72 p-6 lg:p-10 overflow-x-hidden">
        {/* Mobile Header */}
        <div className="lg:hidden flex justify-between items-center mb-8 sticky top-0 bg-slate-50/80 backdrop-blur-md z-10 py-4 border-b border-slate-200/50">
          <h1 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">AutoGest</h1>
          <button 
            onClick={() => setIsMobileMenuOpen(true)}
            className="p-2.5 bg-white rounded-xl shadow-sm border border-slate-200 text-slate-600"
          >
            <Menu size={20} />
          </button>
        </div>

        {renderContent()}
      </main>
    </div>
  );
};

export default App;

export type DocumentType = 'invoice' | 'quote';

export enum InvoiceStatus {
  DRAFT = 'Brouillon',
  SENT = 'Envoyée',
  PAID = 'Payée',
  CANCELLED = 'Annulée',
  // Status spécifiques aux devis
  ACCEPTED = 'Accepté',
  REJECTED = 'Refusé'
}

export interface Client {
  id: string;
  name: string;
  email: string;
  address: string;
  siret?: string;
  phone?: string;
}

export interface Supplier {
  id: string;
  name: string;
  email?: string;
  phone?: string;
  siret?: string;
  address?: string;
  category?: string; // ex: "Matériel", "Logiciel", "Assurance"
}

export interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  type: 'service' | 'product';
}

export interface Expense {
  id: string;
  date: string;
  description: string;
  amount: number;
  category: string;
  supplierId?: string;
}

export interface InvoiceItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
}

export interface Invoice {
  id: string;
  type: DocumentType; // Nouveau champ
  number: string;
  date: string;
  dueDate: string;
  clientId: string;
  items: InvoiceItem[];
  status: InvoiceStatus;
  notes?: string;
  total: number;
}

export interface UserProfile {
  companyName: string;
  siret: string;
  address: string;
  email: string;
  phone: string;
  bankAccount?: string; // IBAN short
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
  timestamp: number;
}

export type ViewState = 'dashboard' | 'invoices' | 'clients' | 'suppliers' | 'products' | 'accounting' | 'settings';

