                  formatter={(value: number) => [`${value} €`, 'CA']}
                />
                <Bar dataKey="ca" radius={[8, 8, 8, 8]}>
                  {monthlyData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.ca > 0 ? "#3b82f6" : "#f1f5f9"} />
                  ))}
