            <button 
                onClick={() => setActiveTab('order')}
                className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 flex items-center gap-2
                    ${activeTab === 'order' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'}`}
            >
                <ShoppingBag size={16} /> Commandes
            </button>
             <button 
                onClick={() => setActiveTab('credit_note')}
