      <div className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Nom de l'entreprise</label>
            <input 
                type="text" 
                className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all" 
                value={userProfile.companyName}
                onChange={(e) => setUserProfile({...userProfile, companyName: e.target.value})}
            />
            </div>
            <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">SIRET</label>
            <input 
                type="text" 
                className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all" 
                value={userProfile.siret}
                onChange={(e) => setUserProfile({...userProfile, siret: e.target.value})}
            />
            </div>
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-2">Adresse</label>
          <textarea 
            className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all resize-none" 
            rows={3}
            value={userProfile.address}
            onChange={(e) => setUserProfile({...userProfile, address: e.target.value})}
          />
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Email</label>
                <input 
                    type="email" 
                    className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all" 
                    value={userProfile.email}
                    onChange={(e) => setUserProfile({...userProfile, email: e.target.value})}
                />
            </div>
            <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Téléphone</label>
                <input 
                    type="text" 
                    className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all" 
                    value={userProfile.phone}
                    onChange={(e) => setUserProfile({...userProfile, phone: e.target.value})}
                />
            </div>
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-2">IBAN (pour les factures)</label>
          <input 
            type="text" 
            className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all font-mono text-sm" 
            value={userProfile.bankAccount}
            onChange={(e) => setUserProfile({...userProfile, bankAccount: e.target.value})}
          />
        </div>
        <div className="pt-4 flex items-center gap-2 text-emerald-600 text-sm font-medium bg-emerald-50 p-4 rounded-xl border border-emerald-100">
          <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
          Les modifications sont sauvegardées automatiquement.
        </div>
      </div>
    </div>
  );

  const renderContent = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard invoices={invoices} />;
      case 'invoices':
        return <InvoiceManager invoices={invoices} setInvoices={setInvoices} clients={clients} userProfile={userProfile} />;
      case 'clients':
        // Pass invoices to calculate total revenue per client
        return <ClientManager clients={clients} setClients={setClients} invoices={invoices} />;
      case 'suppliers':
        // Pass expenses to calculate total spent per supplier
        return <SupplierManager suppliers={suppliers} setSuppliers={setSuppliers} expenses={expenses} />;
      case 'products':
        return <ProductManager products={products} setProducts={setProducts} />;
      case 'accounting':
        return <AccountingManager expenses={expenses} setExpenses={setExpenses} invoices={invoices} suppliers={suppliers} />;
      case 'settings':
        return <SettingsView />;
      default:
        return <Dashboard invoices={invoices} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50/50 font-sans text-slate-900 selection:bg-blue-100 selection:text-blue-900">
      <Sidebar 
        currentView={currentView} 
        setView={setCurrentView} 
        isMobileMenuOpen={isMobileMenuOpen}
        setIsMobileMenuOpen={setIsMobileMenuOpen}
      />

      <main className="flex-1 lg:ml-72 p-6 lg:p-10 overflow-x-hidden">
        {/* Mobile Header */}
        <div className="lg:hidden flex justify-between items-center mb-8 sticky top-0 bg-slate-50/80 backdrop-blur-md z-10 py-4 border-b border-slate-200/50">
          <h1 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">AutoGest</h1>
          <button 
            onClick={() => setIsMobileMenuOpen(true)}
            className="p-2.5 bg-white rounded-xl shadow-sm border border-slate-200 text-slate-600"
          >
            <Menu size={20} />
          </button>
        </div>

        {renderContent()}
      </main>
    </div>
  );
};

