import React, { useState } from 'react';
import { Client, Invoice, InvoiceStatus } from '../types';
import { Plus, Search, Trash2, Mail, MapPin, Phone, Building, Users, X, Edit2, TrendingUp, FileText } from 'lucide-react';

interface ClientManagerProps {
  clients: Client[];
  setClients: (clients: Client[]) => void;
  invoices: Invoice[];
}

const ClientManager: React.FC<ClientManagerProps> = ({ clients, setClients, invoices }) => {
  const [isPanelOpen, setIsPanelOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    email: '',
    address: '',
    siret: '',
    phone: ''
  });

  const getClientRevenue = (clientId: string) => {
    return invoices
      .filter(inv => inv.clientId === clientId && inv.status === InvoiceStatus.PAID && (!inv.type || inv.type === 'invoice'))
      .reduce((sum, inv) => sum + inv.total, 0);
  };

  const getClientInvoiceCount = (clientId: string) => {
    return invoices.filter(inv => inv.clientId === clientId).length;
  };

  const openCreate = () => {
    setEditingId(null);
    setFormData({ name: '', email: '', address: '', siret: '', phone: '' });
    setIsPanelOpen(true);
  };

  const openEdit = (client: Client) => {
    setEditingId(client.id);
    setFormData({ ...client });
    setIsPanelOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.email) return;

    if (editingId) {
        // Edit Mode
        setClients(clients.map(c => c.id === editingId ? { ...c, ...formData } as Client : c));
    } else {
        // Create Mode
        const client: Client = {
            id: Date.now().toString(),
            name: formData.name,
            email: formData.email,
            address: formData.address || '',
            siret: formData.siret,
            phone: formData.phone
        };
        setClients([...clients, client]);
    }
    setIsPanelOpen(false);
  };

  const handleDeleteClient = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('Êtes-vous sûr de vouloir supprimer ce client ?')) {
      setClients(clients.filter(c => c.id !== id));
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-fade-in max-w-7xl mx-auto relative">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Clients</h2>
          <p className="text-slate-500">Gérez votre portefeuille et suivez les revenus.</p>
        </div>
        <button 
          onClick={openCreate}
          className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20 font-medium"
        >
          <Plus size={18} />
          Nouveau Client
        </button>
      </div>

      {/* Side Panel Form */}
      <div className={`fixed inset-y-0 right-0 w-full sm:w-[450px] bg-white shadow-2xl transform transition-transform duration-300 ease-in-out z-40 border-l border-slate-100 ${isPanelOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="h-full flex flex-col">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Modifier le client' : 'Nouveau client'}</h3>
                <button onClick={() => setIsPanelOpen(false)} className="p-2 hover:bg-slate-200 rounded-full text-slate-500 transition-colors">
                    <X size={20} />
                </button>
            </div>

            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-6">
                 <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1.5">Nom / Société <span className="text-red-500">*</span></label>
                    <input 
                        type="text" 
                        required
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                        value={formData.name}
                        onChange={e => setFormData({...formData, name: e.target.value})}
                        placeholder="Ex: Entreprise SAS"
                    />
                </div>
                <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1.5">Email Contact <span className="text-red-500">*</span></label>
                    <input 
                        type="email" 
                        required
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                        value={formData.email}
                        onChange={e => setFormData({...formData, email: e.target.value})}
                        placeholder="contact@exemple.com"
                    />
                </div>
                <div className="grid grid-cols-2 gap-4">
                     <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1.5">Téléphone</label>
                        <input 
                            type="tel" 
                            className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                            value={formData.phone}
                            onChange={e => setFormData({...formData, phone: e.target.value})}
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1.5">SIRET</label>
                        <input 
                            type="text" 
                            className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                            value={formData.siret}
                            onChange={e => setFormData({...formData, siret: e.target.value})}
                        />
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1.5">Adresse de facturation</label>
                    <textarea 
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all resize-none"
                        rows={3}
                        value={formData.address}
                        onChange={e => setFormData({...formData, address: e.target.value})}
                        placeholder="123 Rue de la Paix..."
                    />
                </div>
            </form>

            <div className="p-6 border-t border-slate-100 bg-slate-50/50 flex justify-end gap-3">
                 <button 
                    type="button" 
                    onClick={() => setIsPanelOpen(false)}
                    className="px-6 py-2.5 text-slate-600 hover:bg-white border border-transparent hover:border-slate-200 rounded-xl font-medium transition-all"
                >
                    Annuler
                </button>
                <button 
                    onClick={handleSubmit}
                    className="px-6 py-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-medium shadow-lg shadow-blue-200 transition-all hover:scale-[1.02]"
                >
                    {editingId ? 'Mettre à jour' : 'Enregistrer le client'}
                </button>
            </div>
        </div>
      </div>

      {/* Overlay */}
      {isPanelOpen && (
        <div 
            className="fixed inset-0 bg-slate-900/20 backdrop-blur-sm z-30 transition-opacity"
            onClick={() => setIsPanelOpen(false)}
        />
      )}

      {/* Search & List */}
      <div>
        <div className="mb-8 relative max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher par nom, email..."
              className="w-full pl-10 pr-4 py-3 border border-slate-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-blue-500/50 bg-white shadow-sm transition-all"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredClients.map(client => {
            const revenue = getClientRevenue(client.id);
            const invoiceCount = getClientInvoiceCount(client.id);

            return (
            <div 
                key={client.id} 
                className="bg-white border border-slate-100 rounded-3xl p-6 hover:shadow-[0_8px_30px_rgb(0,0,0,0.06)] hover:border-blue-100 transition-all duration-300 group relative flex flex-col"
            >
               {/* Actions Top Right */}
               <div className="absolute top-5 right-5 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button 
                        onClick={() => openEdit(client)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-colors"
                        title="Modifier"
                    >
