               </div>

               <div className="flex items-center gap-4 mb-6">
                 <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-blue-500 to-indigo-600 text-white flex items-center justify-center font-bold text-xl shadow-md shadow-blue-200">
                   {client.name.charAt(0).toUpperCase()}
                 </div>
                 <div className="overflow-hidden flex-1">
                   <h4 className="font-bold text-slate-900 truncate pr-4 text-lg">{client.name}</h4>
                   <p className="text-xs font-mono text-slate-400 mt-0.5">{client.email}</p>
                 </div>
               </div>

               {/* Mini Stats */}
               <div className="grid grid-cols-2 gap-4 mb-6 pb-6 border-b border-slate-50">
                    <div className="bg-slate-50 rounded-2xl p-3">
                        <p className="text-[10px] uppercase text-slate-400 font-bold mb-1 flex items-center gap-1">
                            <TrendingUp size={10} /> CA Généré
                        </p>
                        <p className="font-bold text-slate-900">{revenue.toLocaleString()} €</p>
                    </div>
                    <div className="bg-slate-50 rounded-2xl p-3">
                        <p className="text-[10px] uppercase text-slate-400 font-bold mb-1 flex items-center gap-1">
                            <FileText size={10} /> Factures
                        </p>
                        <p className="font-bold text-slate-900">{invoiceCount} docs</p>
                    </div>
               </div>

               <div className="space-y-3 text-sm text-slate-500 mt-auto">
                 {client.phone && (
                   <div className="flex items-center gap-3">
                     <Phone size={14} className="text-slate-300" />
                     <span>{client.phone}</span>
                   </div>
                 )}
                 {client.address && (
                   <div className="flex items-start gap-3">
                     <MapPin size={14} className="text-slate-300 mt-0.5" />
                     <span className="line-clamp-2 text-xs">{client.address}</span>
                   </div>
                 )}
               </div>
            </div>
          )})}

          {filteredClients.length === 0 && (
             <div className="col-span-full py-20 text-center">
               <div className="inline-block p-6 rounded-full bg-slate-50 mb-4 animate-pulse">
                   <Users size={32} className="text-slate-300" />
