import React, { useState } from 'react';
import { Product } from '../types';
import { Plus, Search, Trash2, Package, Tag, Briefcase, X, Edit2, Zap } from 'lucide-react';

interface ProductManagerProps {
  products: Product[];
  setProducts: (products: Product[]) => void;
}

const ProductManager: React.FC<ProductManagerProps> = ({ products, setProducts }) => {
  const [isPanelOpen, setIsPanelOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);

  const [formData, setFormData] = useState<Partial<Product>>({
    name: '',
    description: '',
    price: 0,
    type: 'service'
  });

  const openCreate = () => {
    setEditingId(null);
    setFormData({ name: '', description: '', price: 0, type: 'service' });
    setIsPanelOpen(true);
  };

  const openEdit = (product: Product) => {
    setEditingId(product.id);
    setFormData({ ...product });
    setIsPanelOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name) return;

    if (editingId) {
         setProducts(products.map(p => p.id === editingId ? { ...p, ...formData } as Product : p));
    } else {
        const product: Product = {
            id: Date.now().toString(),
            name: formData.name,
            description: formData.description || '',
            price: Number(formData.price) || 0,
            type: formData.type as 'service' | 'product'
        };
        setProducts([...products, product]);
    }
    setIsPanelOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Supprimer cet élément du catalogue ?')) {
      setProducts(products.filter(p => p.id !== id));
    }
  };

  const filteredProducts = products.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-fade-in max-w-7xl mx-auto relative">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Catalogue</h2>
          <p className="text-slate-500">Gérez vos produits et prestations de service.</p>
        </div>
        <button 
          onClick={openCreate}
          className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20 font-medium"
        >
          <Plus size={18} />
          Nouvel Élément
        </button>
      </div>

       {/* Side Panel Form */}
       <div className={`fixed inset-y-0 right-0 w-full sm:w-[450px] bg-white shadow-2xl transform transition-transform duration-300 ease-in-out z-40 border-l border-slate-100 ${isPanelOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="h-full flex flex-col">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Modifier l\'élément' : 'Nouvel élément'}</h3>
                <button onClick={() => setIsPanelOpen(false)} className="p-2 hover:bg-slate-200 rounded-full text-slate-500 transition-colors">
                    <X size={20} />
                </button>
            </div>

            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-6">
                <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1.5">Nom de l'élément <span className="text-red-500">*</span></label>
                    <input 
                        type="text" 
                        required
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                        value={formData.name}
                        onChange={e => setFormData({...formData, name: e.target.value})}
                        placeholder="Ex: Création site web"
                    />
                </div>

                <div className="grid grid-cols-2 gap-4">
                     <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1.5">Type</label>
                        <select
                            className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all appearance-none"
                            value={formData.type}
                            onChange={e => setFormData({...formData, type: e.target.value as 'service' | 'product'})}
                        >
                            <option value="service">Prestation</option>
                            <option value="product">Marchandise</option>
                        </select>
                    </div>
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1.5">Prix (EUR)</label>
                        <input 
                            type="number" 
                            step="0.01"
                            className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                            value={formData.price}
                            onChange={e => setFormData({...formData, price: parseFloat(e.target.value)})}
                        />
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1.5">Description (pour devis/factures)</label>
                    <textarea 
                        rows={4}
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all resize-none"
                        value={formData.description}
                        onChange={e => setFormData({...formData, description: e.target.value})}
                        placeholder="Description détaillée qui apparaîtra sur les documents..."
                    />
                </div>
            </form>

            <div className="p-6 border-t border-slate-100 bg-slate-50/50 flex justify-end gap-3">
                 <button 
                    type="button" 
                    onClick={() => setIsPanelOpen(false)}
                    className="px-6 py-2.5 text-slate-600 hover:bg-white border border-transparent hover:border-slate-200 rounded-xl font-medium transition-all"
                >
                    Annuler
                </button>
                <button 
                    onClick={handleSubmit}
                    className="px-6 py-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-medium shadow-lg shadow-blue-200 transition-all hover:scale-[1.02]"
                >
                    {editingId ? 'Mettre à jour' : 'Enregistrer'}
                </button>
            </div>
        </div>
      </div>

      {/* Overlay */}
      {isPanelOpen && (
        <div 
            className="fixed inset-0 bg-slate-900/20 backdrop-blur-sm z-30 transition-opacity"
            onClick={() => setIsPanelOpen(false)}
        />
      )}

      {/* List */}
      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden min-h-[400px]">
        <div className="p-6 border-b border-slate-100 bg-slate-50/50">
           <div className="relative max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher un service ou produit..."
              className="w-full pl-10 pr-4 py-3 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/50 bg-white shadow-sm transition-all"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
           </div>
        </div>

        <table className="w-full text-left text-sm">
            <thead className="bg-white border-b border-slate-100 text-slate-400">
              <tr>
                <th className="px-8 py-5 font-semibold uppercase tracking-wider text-xs w-20">Type</th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs">Nom & Description</th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs text-right">Prix Unitaire</th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs text-right w-32">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredProducts.map((p) => (
                <tr key={p.id} className="hover:bg-slate-50 transition-colors group">
                  <td className="px-8 py-5">
                     {p.type === 'service' ? 
                       <div className="w-10 h-10 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center border border-blue-100" title="Prestation de service">
                         <Briefcase size={18} /> 
                       </div>
                       : 
                       <div className="w-10 h-10 rounded-xl bg-purple-50 text-purple-600 flex items-center justify-center border border-purple-100" title="Vente de marchandise">
                         <Package size={18} />
                       </div>
                     }
                  </td>
                  <td className="px-6 py-5">
                      <div className="font-bold text-slate-900 text-base mb-1">{p.name}</div>
                      <div className="text-slate-500 truncate max-w-md text-xs">{p.description || "Aucune description"}</div>
                  </td>
                  <td className="px-6 py-5 text-right font-mono font-bold text-slate-700 text-base">{p.price.toFixed(2)} €</td>
                  <td className="px-6 py-5 text-right">
                    <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                            onClick={() => openEdit(p)}
                            className="p-2 text-blue-600 hover:bg-blue-50 rounded-xl transition-colors"
                        >
                            <Edit2 size={18} />
                        </button>
                        <button 
                        onClick={() => handleDelete(p.id)}
                        className="p-2 text-slate-300 hover:text-red-500 transition-colors rounded-xl hover:bg-red-50"
                        >
                        <Trash2 size={18} />
                        </button>
                    </div>
                  </td>
                </tr>
              ))}
               {filteredProducts.length === 0 && (
                <tr>
                  <td colSpan={4} className="py-24 text-center">
                     <div className="flex flex-col items-center justify-center text-slate-300">
                        <Zap size={48} className="mb-4 opacity-50" />
                        <p className="text-lg font-medium text-slate-500">Catalogue vide</p>
                        <p className="text-sm">Ajoutez votre premier élément.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
        </table>
      </div>
    </div>
  );
};

