                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default InvoiceManager;

import React, { useState } from 'react';
import { Invoice, InvoiceItem, InvoiceStatus, Client, UserProfile, DocumentType } from '../types';
import { Plus, Trash2, Printer, Check, Wand2, ArrowLeft, FileText, Repeat, FileCheck, XCircle, ShoppingBag, Receipt, Link as LinkIcon, ArrowRightCircle, Download } from 'lucide-react';
import { suggestInvoiceDescription } from '../services/geminiService';

interface InvoiceManagerProps {
  invoices: Invoice[];
  setInvoices: (invoices: Invoice[]) => void;
  clients: Client[];
  userProfile: UserProfile;
}

const InvoiceManager: React.FC<InvoiceManagerProps> = ({ invoices, setInvoices, clients, userProfile }) => {
  const [view, setView] = useState<'list' | 'create' | 'detail'>('list');
  const [activeTab, setActiveTab] = useState<DocumentType>('invoice');
  const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null);

  // New Document State
  const [newDocData, setNewDocData] = useState<Partial<Invoice>>({
    items: [],
    date: new Date().toISOString().split('T')[0],
    dueDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    type: 'invoice',
    linkedDocumentId: undefined
  });
  const [selectedClientId, setSelectedClientId] = useState<string>('');
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);

  // --- HELPERS ---

  const getFilteredDocuments = () => {
    // Legacy support: if type is undefined, assume invoice
    return invoices.filter(doc => (doc.type || 'invoice') === activeTab);
  };

  const getNextNumber = (type: DocumentType) => {
    const currentYear = new Date().getFullYear();
    const docsThisYear = invoices.filter(i => 
      (i.type || 'invoice') === type && 
      i.date.startsWith(currentYear.toString())
    ).length + 1;

    let prefix = 'FACT';
    if (type === 'quote') prefix = 'DEVIS';
    if (type === 'order') prefix = 'COMM';
    if (type === 'credit_note') prefix = 'AVOIR';

    return `${prefix}-${currentYear}-${docsThisYear.toString().padStart(3, '0')}`;
  };

  const getThemeColor = (type: DocumentType) => {
    switch(type) {
      case 'invoice': return 'blue';
      case 'quote': return 'violet';
      case 'order': return 'indigo';
      case 'credit_note': return 'rose';
      default: return 'blue';
    }
  };

  const getDocumentLabel = (type: DocumentType) => {
    switch(type) {
      case 'invoice': return 'Facture';
      case 'quote': return 'Devis';
      case 'order': return 'Commande';
      case 'credit_note': return 'Avoir';
      default: return 'Document';
    }
  };

  // --- ACTIONS ---

  const exportCurrentViewCSV = () => {
    // Filtrer les documents selon l'onglet actif (Facture, Avoir, Devis...)
    const docsToExport = invoices.filter(doc => (doc.type || 'invoice') === activeTab);

    const headers = ['Numéro', 'Date', 'Client', 'Statut', 'Total'];
    const rows = docsToExport.map(doc => {
        const clientName = clients.find(c => c.id === doc.clientId)?.name || 'Client Inconnu';
        return [
            doc.number,
            doc.date,
            `"${clientName}"`, // Quotes to handle potential commas in names
            doc.status,
            doc.total.toFixed(2)
        ].join(',');
    });

    // Determine filename based on active tab
    let filename = 'documents';
    if (activeTab === 'invoice') filename = 'factures';
    else if (activeTab === 'quote') filename = 'devis';
    else if (activeTab === 'order') filename = 'commandes';
    else if (activeTab === 'credit_note') filename = 'avoirs';

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `${filename}_export_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const getExportLabel = () => {
      switch(activeTab) {
          case 'invoice': return 'Export Factures';
          case 'quote': return 'Export Devis';
          case 'order': return 'Export Commandes';
          case 'credit_note': return 'Export Avoirs';
          default: return 'Export CSV';
      }
  };

  const addItem = () => {
    const items = newDocData.items || [];
    setNewDocData({
      ...newDocData,
      items: [...items, { id: Date.now().toString(), description: '', quantity: 1, unitPrice: 0 }]
    });
  };

  const updateItem = (id: string, field: keyof InvoiceItem, value: any) => {
    const items = newDocData.items?.map(item => 
      item.id === id ? { ...item, [field]: value } : item
    ) || [];
    setNewDocData({ ...newDocData, items });
  };

  const removeItem = (id: string) => {
    const items = newDocData.items?.filter(item => item.id !== id) || [];
    setNewDocData({ ...newDocData, items });
  };

  const handleGenerateDescription = async (itemId: string, currentDesc: string) => {
    if (!selectedClientId) {
      alert("Veuillez sélectionner un client d'abord.");
      return;
    }
    const client = clients.find(c => c.id === selectedClientId);
    if (!client) return;

    setIsGeneratingDesc(true);
    const suggestion = await suggestInvoiceDescription(client.name, currentDesc || "Service général");
    setIsGeneratingDesc(false);

    updateItem(itemId, 'description', suggestion);
  };

  const saveDocument = () => {
    if (!selectedClientId || !newDocData.date || !newDocData.items?.length) {
      alert("Veuillez remplir tous les champs obligatoires (client, date, articles).");
      return;
    }

    const total = newDocData.items.reduce((sum, item) => sum + (item.quantity * item.unitPrice), 0);
    const type = newDocData.type || activeTab;

    const document: Invoice = {
      id: Date.now().toString(),
      type: type,
      number: getNextNumber(type),
      clientId: selectedClientId,
      linkedDocumentId: newDocData.linkedDocumentId,
      date: newDocData.date!,
      dueDate: newDocData.dueDate!,
      items: newDocData.items,
      status: InvoiceStatus.DRAFT,
      total,
      notes: newDocData.notes
    };

    setInvoices([document, ...invoices]);
    setView('list');
    setNewDocData({
      items: [],
      date: new Date().toISOString().split('T')[0],
      dueDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      type: activeTab,
      linkedDocumentId: undefined
    });
    setSelectedClientId('');
  };

  // --- TRANSFORMATION LOGIC ---

  const convertQuoteToInvoice = (quote: Invoice) => {
    if (!confirm("Convertir ce devis en facture ?")) return;

    const updatedInvoices = invoices.map(i => 
        i.id === quote.id ? { ...i, status: InvoiceStatus.ACCEPTED } : i
    );

    const newInvoice: Invoice = {
        ...quote,
        id: Date.now().toString(),
        type: 'invoice',
        linkedDocumentId: quote.id,
        number: getNextNumber('invoice'),
        date: new Date().toISOString().split('T')[0],
        status: InvoiceStatus.DRAFT,
        notes: `Facture suite au devis ${quote.number}`
    };

    setInvoices([newInvoice, ...updatedInvoices]);
    setActiveTab('invoice');
    setSelectedInvoice(newInvoice);
  };

  const convertOrderToInvoice = (order: Invoice) => {
     if (!confirm("Facturer cette commande ?")) return;

     const newInvoice: Invoice = {
         ...order,
         id: Date.now().toString(),
         type: 'invoice',
         linkedDocumentId: order.id,
         number: getNextNumber('invoice'),
         date: new Date().toISOString().split('T')[0],
         status: InvoiceStatus.DRAFT,
         notes: `Facture pour la commande ${order.number}`
     };
     setInvoices([newInvoice, ...invoices]);
     setActiveTab('invoice');
     setSelectedInvoice(newInvoice);
  };

  const createCreditNoteFromInvoice = (invoice: Invoice) => {
    if (!confirm("Créer un avoir pour cette facture ?")) return;

    // Initialize new document data with invoice data
    setNewDocData({
        items: invoice.items.map(i => ({...i})),
        date: new Date().toISOString().split('T')[0],
        dueDate: new Date().toISOString().split('T')[0],
        type: 'credit_note',
        linkedDocumentId: invoice.id,
        notes: `Avoir sur facture ${invoice.number}`
    });
    setSelectedClientId(invoice.clientId);
    setActiveTab('credit_note');
    setView('create');
  };

  const updateStatus = (id: string, status: InvoiceStatus) => {
    setInvoices(invoices.map(inv => inv.id === id ? { ...inv, status } : inv));
    if (selectedInvoice && selectedInvoice.id === id) {
        setSelectedInvoice({ ...selectedInvoice, status });
    }
  };

  const deleteDocument = (id: string) => {
     if(confirm("Supprimer ce document définitivement ?")) {
       setInvoices(invoices.filter(inv => inv.id !== id));
       if (selectedInvoice?.id === id) setView('list');
     }
  }

  const startCreate = () => {
      setNewDocData({
        items: [],
        date: new Date().toISOString().split('T')[0],
        dueDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
        type: activeTab,
        linkedDocumentId: undefined
      });
      setSelectedClientId('');
      setView('create');
  }

  // --- STYLES HELPER ---
  const themeColor = getThemeColor(activeTab);

  // --- RENDERERS ---

  if (view === 'create') {
    return (
      <div className="max-w-5xl mx-auto animate-slide-in">
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-4">
            <button onClick={() => setView('list')} className="p-2 hover:bg-slate-200 rounded-full transition-colors text-slate-500">
              <ArrowLeft size={20} />
            </button>
            <div>
              <h2 className="text-2xl font-bold text-slate-900">Nouveau document : {getDocumentLabel(activeTab)}</h2>
              <p className="text-slate-500 text-sm">Remplissez les informations ci-dessous.</p>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 p-8">
          {/* Linked Doc Badge if exists */}
          {newDocData.linkedDocumentId && (
            <div className="mb-6 inline-flex items-center gap-2 bg-slate-100 text-slate-600 px-3 py-1.5 rounded-full text-xs font-semibold">
                <LinkIcon size={12} />
                Lié au document ID: {invoices.find(i => i.id === newDocData.linkedDocumentId)?.number || 'Inconnu'}
            </div>
          )}

          {/* Header Inputs */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-8">
            <div className="md:col-span-1">
              <label className="block text-sm font-semibold text-slate-700 mb-2">Client destinataire</label>
              <select 
                className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-${themeColor}-500/20 focus:border-${themeColor}-500 outline-none transition-all`}
                value={selectedClientId}
                onChange={(e) => setSelectedClientId(e.target.value)}
                disabled={!!newDocData.linkedDocumentId} // Lock client if created from another doc
              >
                <option value="">Sélectionner...</option>
                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </div>
            <div className="md:col-span-2 grid grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Date d'émission</label>
                <input 
                  type="date" 
                  className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-${themeColor}-500/20 focus:border-${themeColor}-500 outline-none transition-all`}
                  value={newDocData.date}
                  onChange={(e) => setNewDocData({...newDocData, date: e.target.value})}
                />
              </div>
               <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Date d'échéance</label>
                <input 
                  type="date" 
                  className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-${themeColor}-500/20 focus:border-${themeColor}-500 outline-none transition-all`}
                  value={newDocData.dueDate}
                  onChange={(e) => setNewDocData({...newDocData, dueDate: e.target.value})}
                />
              </div>
            </div>
          </div>

          {/* Items Table */}
          <div className="mb-8 border border-slate-100 rounded-2xl overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b border-slate-200">
                <tr className="text-xs font-semibold text-slate-500 uppercase tracking-wider">
                  <th className="py-3 px-6 w-1/2">Description</th>
                  <th className="py-3 px-4 w-24">Qté</th>
                  <th className="py-3 px-4 w-32">Prix Uni.</th>
                  <th className="py-3 px-6 w-32 text-right">Total</th>
                  <th className="py-3 px-4 w-12"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {newDocData.items?.map((item) => (
                  <tr key={item.id} className="group hover:bg-slate-50/50">
                    <td className="py-2 px-6">
                      <div className="flex gap-2 relative">
                        <input 
                          type="text" 
                          placeholder="Description de la prestation..."
                          className="w-full p-2 bg-transparent border-b border-transparent focus:border-blue-400 focus:bg-white rounded text-sm outline-none transition-colors"
                          value={item.description}
                          onChange={(e) => updateItem(item.id, 'description', e.target.value)}
                        />
                        <button 
                          onClick={() => handleGenerateDescription(item.id, item.description)}
                          className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 text-indigo-500 hover:bg-indigo-50 rounded-lg opacity-0 group-hover:opacity-100 transition-all"
                          title="Suggestion IA"
                          disabled={isGeneratingDesc}
                        >
                          <Wand2 size={14} className={isGeneratingDesc ? "animate-spin" : ""} />
                        </button>
                      </div>
                    </td>
                    <td className="py-2 px-4">
                       <input 
                          type="number" 
                          min="0"
                          className="w-full p-2 bg-transparent border-b border-transparent focus:border-blue-400 focus:bg-white rounded text-sm outline-none text-right"
                          value={item.quantity}
                          onChange={(e) => updateItem(item.id, 'quantity', parseFloat(e.target.value))}
                        />
                    </td>
                    <td className="py-2 px-4">
                       <input 
                          type="number" 
                          min="0"
                          step="0.01"
                          className="w-full p-2 bg-transparent border-b border-transparent focus:border-blue-400 focus:bg-white rounded text-sm outline-none text-right"
                          value={item.unitPrice}
                          onChange={(e) => updateItem(item.id, 'unitPrice', parseFloat(e.target.value))}
                        />
                    </td>
                    <td className="py-2 px-6 text-right font-medium text-slate-900">
                      {(item.quantity * item.unitPrice).toFixed(2)} €
                    </td>
                    <td className="py-2 px-4 text-right">
                      <button onClick={() => removeItem(item.id)} className="text-slate-300 hover:text-red-500 p-1 rounded transition-colors">
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            <div className="bg-slate-50 px-6 py-3 border-t border-slate-200">
                <button onClick={addItem} className={`flex items-center gap-2 text-sm text-${themeColor}-600 font-medium hover:text-${themeColor}-700 transition-colors`}>
                    <Plus size={16} /> Ajouter une ligne
                </button>
            </div>
          </div>

          {/* Footer & Actions */}
          <div className="flex flex-col md:flex-row justify-between items-start gap-8 pt-4">
            <div>
                 <label className="block text-sm font-semibold text-slate-700 mb-2">Notes (Optionnel)</label>
                 <textarea 
                   className="w-full md:w-96 p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all resize-none"
                   rows={3}
                   placeholder="Conditions de paiement, mentions légales..."
                   value={newDocData.notes || ''}
                   onChange={e => setNewDocData({...newDocData, notes: e.target.value})}
                 />
            </div>
            <div className="text-right w-full md:w-auto">
                 <p className="text-sm text-slate-500 mb-1 uppercase tracking-wider font-medium">Total {activeTab === 'credit_note' ? 'à déduire' : 'à payer'}</p>
                 <div className="text-4xl font-bold text-slate-900 mb-6 tracking-tight">
                    {(newDocData.items?.reduce((acc, i) => acc + (i.quantity * i.unitPrice), 0) || 0).toFixed(2)} €
                 </div>
                 <button 
                    onClick={saveDocument}
                    className={`w-full md:w-auto bg-${themeColor}-600 text-white px-8 py-3.5 rounded-xl hover:bg-${themeColor}-700 font-semibold shadow-lg shadow-${themeColor}-200 transition-all hover:scale-[1.02] active:scale-95`}
                >
                    Enregistrer
                </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'detail' && selectedInvoice) {
    const client = clients.find(c => c.id === selectedInvoice.clientId);
    const docType = selectedInvoice.type || 'invoice';
    const docTheme = getThemeColor(docType);
    const linkedDoc = selectedInvoice.linkedDocumentId ? invoices.find(i => i.id === selectedInvoice.linkedDocumentId) : null;

    // Labels based on type
    let title = 'FACTURE';
    let icon = <FileText size={24} />;

    if (docType === 'quote') { title = 'DEVIS'; icon = <FileCheck size={24} />; }
    if (docType === 'order') { title = 'COMMANDE'; icon = <ShoppingBag size={24} />; }
    if (docType === 'credit_note') { title = 'AVOIR'; icon = <Receipt size={24} />; }

    return (
      <div className="max-w-4xl mx-auto animate-fade-in pb-10">
        {/* Actions Bar (Hidden on Print) */}
        <div className="sticky top-0 z-10 bg-slate-50/80 backdrop-blur-md py-4 mb-6 flex justify-between items-center print:hidden border-b border-slate-200/50">
          <button onClick={() => setView('list')} className="flex items-center gap-2 text-slate-600 hover:text-slate-900 font-medium px-4 py-2 hover:bg-white rounded-lg transition-all">
            <ArrowLeft size={18} /> Retour
          </button>

          <div className="flex items-center gap-3">
             {/* Status Selector */}
            <div className="flex items-center gap-2 bg-white border border-slate-200 rounded-lg p-1 pr-3 shadow-sm">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider ml-2">Statut</span>
                <select 
                  value={selectedInvoice.status}
                  onChange={(e) => updateStatus(selectedInvoice.id, e.target.value as InvoiceStatus)}
                  className={`text-sm font-semibold rounded-md py-1 px-2 cursor-pointer outline-none bg-transparent ${
                      selectedInvoice.status === InvoiceStatus.PAID || selectedInvoice.status === InvoiceStatus.ACCEPTED ? 'text-emerald-600' :
                      selectedInvoice.status === InvoiceStatus.SENT ? 'text-amber-600' :
                      selectedInvoice.status === InvoiceStatus.REJECTED ? 'text-red-600' :
                      'text-slate-600'
                  }`}
                >
                {Object.values(InvoiceStatus).map(s => <option key={s} value={s}>{s}</option>)}
                </select>
            </div>

            {/* ACTION BUTTONS BASED ON TYPE */}

            {/* Quote -> Invoice */}
            {docType === 'quote' && selectedInvoice.status !== InvoiceStatus.ACCEPTED && (
                <button 
                    onClick={() => convertQuoteToInvoice(selectedInvoice)}
                    className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-colors shadow-md shadow-emerald-200 font-medium text-sm"
                >
                    <Repeat size={16} /> Convertir en Facture
                </button>
            )}

            {/* Order -> Invoice */}
             {docType === 'order' && (
                <button 
                    onClick={() => convertOrderToInvoice(selectedInvoice)}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-md shadow-indigo-200 font-medium text-sm"
                >
                    <ArrowRightCircle size={16} /> Facturer la commande
                </button>
            )}

            {/* Invoice -> Credit Note */}
            {docType === 'invoice' && (
                <button 
                    onClick={() => createCreditNoteFromInvoice(selectedInvoice)}
                    className="flex items-center gap-2 px-4 py-2 bg-rose-600 text-white rounded-lg hover:bg-rose-700 transition-colors shadow-md shadow-rose-200 font-medium text-sm"
                >
                    <Receipt size={16} /> Créer un avoir
                </button>
            )}

            <button 
              onClick={() => window.print()}
              className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 transition-colors shadow-lg shadow-slate-200 font-medium text-sm"
            >
              <Printer size={16} /> Imprimer
            </button>
          </div>
        </div>

        {/* Invoice Preview - Paper Look */}
        <div 
            className="bg-white p-12 shadow-2xl shadow-slate-200/50 rounded-sm min-h-[1000px] relative mx-auto print:shadow-none print:w-full print:m-0" 
            id="invoice-preview"
            style={{ maxWidth: '210mm' }}
        >
          {/* Header */}
          <div className="flex justify-between items-start mb-16">
            <div>
               <div className="flex items-center gap-3 mb-6">
                 <div className={`w-12 h-12 bg-${docTheme}-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-${docTheme}-200`}>
                    {icon}
                 </div>
                 <h1 className="text-2xl font-bold text-slate-900 tracking-tight uppercase">{userProfile.companyName}</h1>
               </div>
               <div className="text-sm text-slate-500 leading-relaxed font-medium">
                <p>{userProfile.address}</p>
                <p>{userProfile.email} • {userProfile.phone}</p>
                <p className="mt-2 font-mono text-xs text-slate-400">SIRET: {userProfile.siret}</p>
              </div>
            </div>
            <div className="text-right">
              <h2 className="text-5xl font-light text-slate-900 mb-2 tracking-tight">{title}</h2>
              <p className={`text-${docTheme}-600 font-mono font-bold text-lg`}>#{selectedInvoice.number}</p>

              {/* Reference to linked doc */}
              {linkedDoc && (
                <p className="text-xs text-slate-400 mt-1 flex items-center justify-end gap-1">
                    <LinkIcon size={10} /> Lié à #{linkedDoc.number}
                </p>
              )}

              <div className="mt-10 text-right bg-slate-50 p-6 rounded-2xl border border-slate-100 inline-block min-w-[200px]">
                <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">Client</h3>
                <p className="font-bold text-slate-900 text-lg">{client?.name}</p>
                <p className="text-sm text-slate-500 whitespace-pre-line mt-1">{client?.address}</p>
                {client?.siret && <p className="text-xs text-slate-400 mt-2 font-mono">SIRET: {client.siret}</p>}
              </div>
            </div>
          </div>

          {/* Dates */}
          <div className="flex gap-16 mb-12 border-y border-slate-100 py-8">
             <div>
                <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5">Date d'émission</span>
                <span className="font-bold text-slate-900 text-lg">{new Date(selectedInvoice.date).toLocaleDateString('fr-FR')}</span>
             </div>
             <div>
                <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5">{docType === 'quote' ? 'Validité' : 'Échéance'}</span>
                <span className="font-bold text-slate-900 text-lg">{new Date(selectedInvoice.dueDate).toLocaleDateString('fr-FR')}</span>
             </div>
          </div>

          {/* Items */}
          <table className="w-full mb-12">
            <thead>
              <tr className="border-b-2 border-slate-900 text-left text-[10px] font-bold text-slate-900 uppercase tracking-widest">
                <th className="py-4">Description</th>
                <th className="py-4 text-right">Qté</th>
                <th className="py-4 text-right">Prix Unitaire</th>
                <th className="py-4 text-right">Total</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm">
              {selectedInvoice.items.map((item, idx) => (
                <tr key={idx}>
                  <td className="py-5 text-slate-800 font-semibold">{item.description}</td>
                  <td className="py-5 text-right text-slate-500 font-medium">{item.quantity}</td>
                  <td className="py-5 text-right text-slate-500 font-medium">{item.unitPrice.toFixed(2)} €</td>
                  <td className="py-5 text-right font-bold text-slate-900">{(item.quantity * item.unitPrice).toFixed(2)} €</td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* Totals */}
          <div className="flex justify-end mb-16">
            <div className="w-1/2 md:w-1/3">
              <div className="flex justify-between mb-3 text-sm">
                <span className="text-slate-500 font-medium">Total HT</span>
                <span className="font-bold text-slate-900">{selectedInvoice.total.toFixed(2)} €</span>
              </div>
              <div className="flex justify-between mb-6 text-sm">
                <span className="text-slate-500 font-medium">TVA (non applicable)</span>
                <span className="font-bold text-slate-900">0.00 €</span>
              </div>
              <div className={`flex justify-between bg-${docTheme}-50 p-4 rounded-xl text-xl font-bold border border-${docTheme}-100`}>
                <span className={`text-${docTheme}-900`}>{docType === 'credit_note' ? 'Total à déduire' : 'Total TTC'}</span>
                <span className={`text-${docTheme}-600`}>{selectedInvoice.total.toFixed(2)} €</span>
              </div>
            </div>
          </div>

          {/* Footer Notes */}
          <div className="absolute bottom-12 left-12 right-12 text-center">
             {selectedInvoice.notes && (
                 <div className="mb-8 bg-slate-50 p-6 rounded-2xl text-sm text-slate-600 text-left border border-slate-100 relative">
                     <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Notes</span>
                     {selectedInvoice.notes}
                 </div>
             )}
            <div className="text-[10px] text-slate-400 leading-relaxed border-t border-slate-100 pt-8 font-medium">
                <p>TVA non applicable, art. 293 B du CGI.</p>
                {userProfile.bankAccount && <p className="mt-1 font-mono text-slate-500">IBAN : {userProfile.bankAccount}</p>}
                {(docType === 'invoice') && <p className="mt-2 text-slate-400">En cas de retard de paiement, une pénalité de 3 fois le taux d'intérêt légal sera appliquée. 
                Une indemnité forfaitaire de 40€ pour frais de recouvrement sera due.</p>}
            </div>
          </div>
        </div>
      </div>
    );
  }

  // List View
  return (
    <div className="space-y-8 max-w-7xl mx-auto animate-fade-in">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-900">Documents</h2>
            <p className="text-slate-500">Gérez vos documents commerciaux.</p>
        </div>

        {/* Type Toggle Pills - Enhanced */}
        <div className="bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 flex flex-wrap gap-1">
            <button 
                onClick={() => setActiveTab('invoice')}
                className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 flex items-center gap-2
                    ${activeTab === 'invoice' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'}`}
            >
                <FileText size={16} /> Factures
            </button>
            <button 
                onClick={() => setActiveTab('quote')}
                className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 flex items-center gap-2
                    ${activeTab === 'quote' ? 'bg-violet-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'}`}
            >
                <FileCheck size={16} /> Devis
            </button>
            <button 
                onClick={() => setActiveTab('order')}
                className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 flex items-center gap-2
                    ${activeTab === 'order' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'}`}
            >
                <ShoppingBag size={16} /> Commandes
            </button>
             <button 
                onClick={() => setActiveTab('credit_note')}
                className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 flex items-center gap-2
                    ${activeTab === 'credit_note' ? 'bg-rose-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'}`}
            >
                <Receipt size={16} /> Avoirs
            </button>
        </div>

        <div className="flex gap-2">
            <button 
                onClick={exportCurrentViewCSV}
                className="bg-white hover:bg-slate-50 text-slate-600 border border-slate-200 px-4 py-2.5 rounded-xl flex items-center gap-2 transition-all font-medium shadow-sm"
                title={`Exporter les ${activeTab === 'credit_note' ? 'avoirs' : activeTab === 'invoice' ? 'factures' : activeTab === 'quote' ? 'devis' : 'documents'} en CSV`}
            >
                <Download size={18} />
                <span className="hidden sm:inline">{getExportLabel()}</span>
            </button>

            <button 
            onClick={startCreate}
            className={`bg-${themeColor}-600 hover:bg-${themeColor}-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-${themeColor}-200 font-medium`}
            >
            <Plus size={18} />
            Créer
            </button>
        </div>
      </div>

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden min-h-[400px]">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50/50 border-b border-slate-200 text-slate-500">
              <tr>
                <th className="px-8 py-5 font-semibold uppercase tracking-wider text-xs">Numéro</th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs">Client</th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs">Date</th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs text-right">Montant</th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs text-center">Statut</th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {getFilteredDocuments().map((doc) => {
                 const clientName = clients.find(c => c.id === doc.clientId)?.name || 'Client Inconnu';
                 const type = doc.type || 'invoice';
                 const color = getThemeColor(type);

                 let Icon = FileText;
                 if (type === 'quote') Icon = FileCheck;
                 if (type === 'order') Icon = ShoppingBag;
                 if (type === 'credit_note') Icon = Receipt;

                 return (
                  <tr key={doc.id} className="hover:bg-slate-50 transition-colors group">
                    <td className="px-8 py-5 font-mono font-medium text-slate-700 flex items-center gap-3">
                         <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-${color}-600 bg-${color}-50`}>
                             <Icon size={16} />
                         </div>
                         <div className="flex flex-col">
                            <span>{doc.number}</span>
                            {doc.linkedDocumentId && <span className="text-[10px] text-slate-400 flex items-center gap-1"><LinkIcon size={8} /> Lié</span>}
                         </div>
                    </td>
                    <td className="px-6 py-5 text-slate-900 font-bold">{clientName}</td>
                    <td className="px-6 py-5 text-slate-500 font-medium">{new Date(doc.date).toLocaleDateString()}</td>
                    <td className="px-6 py-5 text-right font-bold text-slate-900">{doc.total.toFixed(2)} €</td>
                    <td className="px-6 py-5 text-center">
                      <span className={`inline-flex px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide
                        ${doc.status === InvoiceStatus.PAID || doc.status === InvoiceStatus.ACCEPTED ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 
                          doc.status === InvoiceStatus.SENT ? 'bg-amber-50 text-amber-600 border border-amber-100' :
                          doc.status === InvoiceStatus.REJECTED ? 'bg-red-50 text-red-600 border border-red-100' :
                          'bg-slate-100 text-slate-500 border border-slate-200'}`}>
                        {doc.status}
                      </span>
                    </td>
                    <td className="px-6 py-5 text-right">
                      <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                            onClick={() => { setSelectedInvoice(doc); setView('detail'); }}
                            className="text-blue-600 hover:bg-blue-50 p-2 rounded-xl transition-colors"
                            title="Voir"
                        >
                            <FileText size={18} />
                        </button>
                        <button 
                            onClick={() => deleteDocument(doc.id)}
                            className="text-slate-400 hover:text-red-500 hover:bg-red-50 p-2 rounded-xl transition-colors"
                            title="Supprimer"
                        >
                            <Trash2 size={18} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
              {getFilteredDocuments().length === 0 && (
                <tr>
                  <td colSpan={6} className="py-24 text-center">
                    <div className="flex flex-col items-center justify-center text-slate-300">
                        <FileText size={64} className="mb-4 opacity-50" />
                        <p className="text-lg font-medium text-slate-500">Aucun document de type "{getDocumentLabel(activeTab)}"</p>
                        <p className="text-sm">Commencez par en créer un nouveau.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default InvoiceManager;

export type DocumentType = 'invoice' | 'quote' | 'order' | 'credit_note';

export enum InvoiceStatus {
  DRAFT = 'Brouillon',
  SENT = 'Envoyée',
  PAID = 'Payée',
  CANCELLED = 'Annulée',
  // Status spécifiques aux devis
  ACCEPTED = 'Accepté',
  REJECTED = 'Refusé'
}

export interface Client {
  id: string;
  name: string;
  email: string;
  address: string;
  siret?: string;
  phone?: string;
  notes?: string; // Nouveau champ pour notes internes
  archived?: boolean; // Nouveau champ pour l'archivage
}

export interface Supplier {
  id: string;
  name: string;
  email?: string;
  phone?: string;
  siret?: string;
  address?: string;
  category?: string; // ex: "Matériel", "Logiciel", "Assurance"
  notes?: string; // Nouveau champ pour notes internes
}

export interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  type: 'service' | 'product';
}

export interface Expense {
  id: string;
  date: string;
  description: string;
  amount: number;
  category: string;
  supplierId?: string;
}

export interface InvoiceItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
}

export interface Invoice {
  id: string;
  type: DocumentType; // Nouveau champ
  number: string;
  linkedDocumentId?: string; // ID du document parent (ex: Facture pour un Avoir)
  date: string;
  dueDate: string;
  clientId: string;
  items: InvoiceItem[];
  status: InvoiceStatus;
  notes?: string;
  total: number;
}

export interface UserProfile {
  companyName: string;
  siret: string;
  address: string;
  email: string;
  phone: string;
  website?: string;
  bankAccount?: string; // IBAN short
  tvaNumber?: string; // Numéro TVA Intracom
  legalMentions?: string; // Mentions spécifiques bas de page
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
  timestamp: number;
}

export type ViewState = 'dashboard' | 'invoices' | 'clients' | 'suppliers' | 'products' | 'accounting' | 'settings';

import React, { useState, useMemo } from 'react';
import { Client, Invoice, InvoiceStatus } from '../types';
import { Plus, Search, Trash2, Mail, MapPin, Phone, Users, X, Edit2, TrendingUp, FileText, Download, SortAsc, Calendar, StickyNote, Archive, RefreshCcw } from 'lucide-react';

interface ClientManagerProps {
  clients: Client[];
  setClients: (clients: Client[]) => void;
  invoices: Invoice[];
}

type SortOption = 'name' | 'revenue' | 'activity';

const ClientManager: React.FC<ClientManagerProps> = ({ clients, setClients, invoices }) => {
  const [isPanelOpen, setIsPanelOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState<SortOption>('name');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showArchived, setShowArchived] = useState(false);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    email: '',
    address: '',
    siret: '',
    phone: '',
    notes: ''
  });

  // --- STATISTICS HELPERS ---

  const getClientStats = (clientId: string) => {
    const clientInvoices = invoices.filter(inv => inv.clientId === clientId);

    // Revenue (Paid invoices - Credit Notes)
    const revenue = clientInvoices
      .filter(inv => inv.status === InvoiceStatus.PAID)
      .reduce((sum, inv) => {
         if (inv.type === 'credit_note') return sum - inv.total;
         if (!inv.type || inv.type === 'invoice') return sum + inv.total;
         return sum;
      }, 0);

    // Last Activity Date
    const dates = clientInvoices.map(inv => new Date(inv.date).getTime());
    const lastActivity = dates.length > 0 ? Math.max(...dates) : 0;

    return {
      revenue,
      count: clientInvoices.length,
      lastActivity
    };
  };

  // --- SORTING & FILTERING ---

  const processedClients = useMemo(() => {
    // 1. Filter by Archive Status
    let result = clients.filter(c => !!c.archived === showArchived);

    // 2. Filter by Search
    result = result.filter(c => 
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      c.email.toLowerCase().includes(searchTerm.toLowerCase())
    );

    // 3. Sort
    return result.sort((a, b) => {
      const statsA = getClientStats(a.id);
      const statsB = getClientStats(b.id);

      if (sortBy === 'revenue') return statsB.revenue - statsA.revenue;
      if (sortBy === 'activity') return statsB.lastActivity - statsA.lastActivity;
      return a.name.localeCompare(b.name);
    });
  }, [clients, searchTerm, sortBy, invoices, showArchived]);

  // --- ACTIONS ---

  const openCreate = () => {
    setEditingId(null);
    setFormData({ name: '', email: '', address: '', siret: '', phone: '', notes: '' });
    setIsPanelOpen(true);
  };

  const openEdit = (client: Client) => {
    setEditingId(client.id);
    setFormData({ ...client });
    setIsPanelOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.email) return;

    if (editingId) {
        setClients(clients.map(c => c.id === editingId ? { ...c, ...formData } as Client : c));
    } else {
        const client: Client = {
            id: Date.now().toString(),
            name: formData.name,
            email: formData.email,
            address: formData.address || '',
            siret: formData.siret,
            phone: formData.phone,
            notes: formData.notes,
            archived: false
        };
        setClients([...clients, client]);
    }
    setIsPanelOpen(false);
  };

  const toggleArchiveClient = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      setClients(clients.map(c => c.id === id ? { ...c, archived: !c.archived } : c));
  };

  const handleDeleteClient = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('Êtes-vous sûr de vouloir supprimer ce client DÉFINITIVEMENT ? Cette action est irréversible.')) {
      setClients(clients.filter(c => c.id !== id));
    }
  };

  const exportCSV = () => {
    const headers = ['Nom', 'Email', 'Téléphone', 'SIRET', 'Adresse', 'Notes', 'CA Généré', 'Dernière Activité', 'Statut'];
    const rows = processedClients.map(c => {
        const stats = getClientStats(c.id);
        return [
            `"${c.name}"`,
            `"${c.email}"`,
            `"${c.phone || ''}"`,
            `"${c.siret || ''}"`,
            `"${c.address?.replace(/\n/g, ' ') || ''}"`,
            `"${c.notes?.replace(/\n/g, ' ') || ''}"`,
            stats.revenue.toFixed(2),
            stats.lastActivity ? new Date(stats.lastActivity).toLocaleDateString() : 'Jamais',
            c.archived ? 'Archivé' : 'Actif'
        ].join(',');
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `clients_${showArchived ? 'archives' : 'actifs'}_export_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-8 animate-fade-in max-w-7xl mx-auto relative">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Clients</h2>
          <p className="text-slate-500">Gérez votre portefeuille et suivez les revenus.</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-3 items-center">
            {/* Archive Toggle */}
            <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200">
               <button 
                 onClick={() => setShowArchived(false)}
                 className={`px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all shadow-sm ${!showArchived ? 'bg-white text-blue-600 shadow' : 'bg-transparent text-slate-500 hover:text-slate-700 shadow-none'}`}
               >
                 Actifs
               </button>
               <button 
                 onClick={() => setShowArchived(true)}
                 className={`px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all shadow-sm ${showArchived ? 'bg-white text-slate-600 shadow' : 'bg-transparent text-slate-500 hover:text-slate-700 shadow-none'}`}
               >
                 Archivés
               </button>
            </div>

            <div className="flex gap-2 w-full sm:w-auto">
                <button 
                onClick={exportCSV}
                className="bg-white hover:bg-slate-50 text-slate-600 border border-slate-200 px-4 py-2.5 rounded-xl flex items-center gap-2 transition-all font-medium shadow-sm flex-1 sm:flex-initial justify-center"
                title="Exporter la vue actuelle en CSV"
                >
                <Download size={18} />
                <span className="hidden sm:inline">Export</span>
                </button>
                <button 
                onClick={openCreate}
                className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20 font-medium flex-1 sm:flex-initial justify-center"
                >
                <Plus size={18} />
                <span className="hidden sm:inline">Nouveau Client</span>
                <span className="sm:hidden">Nouveau</span>
                </button>
            </div>
        </div>
      </div>

      {/* Side Panel Form */}
      <div className={`fixed inset-y-0 right-0 w-full sm:w-[500px] bg-white shadow-2xl transform transition-transform duration-300 ease-in-out z-40 border-l border-slate-100 ${isPanelOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="h-full flex flex-col">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                <h3 className="text-xl font-bold text-slate-900">{editingId ? 'Modifier le client' : 'Nouveau client'}</h3>
                <button onClick={() => setIsPanelOpen(false)} className="p-2 hover:bg-slate-200 rounded-full text-slate-500 transition-colors">
                    <X size={20} />
                </button>
            </div>

            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-6">
                 <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1.5">Nom / Société <span className="text-red-500">*</span></label>
                    <input 
                        type="text" 
                        required
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                        value={formData.name}
                        onChange={e => setFormData({...formData, name: e.target.value})}
                        placeholder="Ex: Entreprise SAS"
                    />
                </div>
                <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1.5">Email Contact <span className="text-red-500">*</span></label>
                    <input 
                        type="email" 
                        required
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                        value={formData.email}
                        onChange={e => setFormData({...formData, email: e.target.value})}
                        placeholder="contact@exemple.com"
                    />
                </div>
                <div className="grid grid-cols-2 gap-4">
                     <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1.5">Téléphone</label>
                        <input 
                            type="tel" 
                            className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                            value={formData.phone}
                            onChange={e => setFormData({...formData, phone: e.target.value})}
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-1.5">SIRET</label>
                        <input 
                            type="text" 
                            className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                            value={formData.siret}
                            onChange={e => setFormData({...formData, siret: e.target.value})}
                        />
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-1.5">Adresse de facturation</label>
                    <textarea 
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all resize-none"
                        rows={3}
                        value={formData.address}
                        onChange={e => setFormData({...formData, address: e.target.value})}
                        placeholder="123 Rue de la Paix..."
                    />
                </div>

                <div className="pt-4 border-t border-slate-100">
                    <label className="block text-sm font-semibold text-slate-700 mb-1.5 flex items-center gap-2">
                        <StickyNote size={14} className="text-slate-400"/> Notes privées (Interne)
                    </label>
                    <textarea 
                        className="w-full p-3 bg-yellow-50/50 border border-yellow-200 rounded-xl focus:ring-2 focus:ring-yellow-500/20 focus:border-yellow-400 outline-none transition-all resize-none text-sm text-slate-700"
                        rows={3}
                        value={formData.notes || ''}
                        onChange={e => setFormData({...formData, notes: e.target.value})}
                        placeholder="Code porte, préférences, contact secondaire..."
                    />
                </div>
            </form>

            <div className="p-6 border-t border-slate-100 bg-slate-50/50 flex justify-end gap-3">
                 <button 
                    type="button" 
                    onClick={() => setIsPanelOpen(false)}
                    className="px-6 py-2.5 text-slate-600 hover:bg-white border border-transparent hover:border-slate-200 rounded-xl font-medium transition-all"
                >
                    Annuler
                </button>
                <button 
                    onClick={handleSubmit}
                    className="px-6 py-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-medium shadow-lg shadow-blue-200 transition-all hover:scale-[1.02]"
                >
                    {editingId ? 'Mettre à jour' : 'Enregistrer le client'}
                </button>
            </div>
        </div>
      </div>

      {/* Overlay */}
      {isPanelOpen && (
        <div 
            className="fixed inset-0 bg-slate-900/20 backdrop-blur-sm z-30 transition-opacity"
            onClick={() => setIsPanelOpen(false)}
        />
      )}

      {/* Filter & List */}
      <div className="space-y-6">
        {/* Search & Sort Toolbar */}
        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                type="text" 
                placeholder={showArchived ? "Rechercher dans les archives..." : "Rechercher par nom, email..."}
                className="w-full pl-10 pr-4 py-3 border border-slate-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-blue-500/50 bg-white shadow-sm transition-all"
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
                />
            </div>

            <div className="flex items-center gap-2 bg-white px-4 py-2 border border-slate-200 rounded-2xl shadow-sm">
                <SortAsc size={18} className="text-slate-400" />
                <span className="text-sm font-semibold text-slate-600">Trier par:</span>
                <select 
                    value={sortBy}
                    onChange={(e) => setSortBy(e.target.value as SortOption)}
                    className="bg-transparent text-sm font-bold text-slate-800 outline-none cursor-pointer"
                >
                    <option value="name">Nom (A-Z)</option>
                    <option value="revenue">Chiffre d'Affaires</option>
                    <option value="activity">Activité Récente</option>
                </select>
            </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {processedClients.map(client => {
            const stats = getClientStats(client.id);

            return (
            <div 
                key={client.id} 
                className={`bg-white border border-slate-100 rounded-3xl p-6 hover:shadow-[0_8px_30px_rgb(0,0,0,0.06)] hover:border-blue-100 transition-all duration-300 group relative flex flex-col ${client.archived ? 'grayscale-[0.5] opacity-90' : ''}`}
            >
               {/* Actions Top Right */}
               <div className="absolute top-5 right-5 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-10">
                    <button 
                        onClick={() => openEdit(client)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-colors"
                        title="Modifier"
                    >
                        <Edit2 size={16} />
                    </button>
                    <button 
                        onClick={(e) => toggleArchiveClient(client.id, e)}
                        className={`p-2 rounded-xl transition-colors ${client.archived ? 'text-emerald-500 hover:bg-emerald-50' : 'text-amber-500 hover:bg-amber-50'}`}
                        title={client.archived ? "Restaurer" : "Archiver"}
                    >
                        {client.archived ? <RefreshCcw size={16} /> : <Archive size={16} />}
                    </button>
                    {/* Only show delete if strictly necessary, maybe only on archived items or always */}
                    <button 
                        onClick={(e) => handleDeleteClient(client.id, e)}
                        className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-colors"
                        title="Supprimer définitivement"
                    >
