                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs cursor-pointer hover:bg-slate-100 transition-colors" onClick={() => handleSort('client')}>
                    <div className="flex items-center gap-1">Client {sortConfig.key === 'client' && (sortConfig.direction === 'asc' ? <ChevronUp size={14}/> : <ChevronDown size={14}/>)}</div>
                </th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs cursor-pointer hover:bg-slate-100 transition-colors" onClick={() => handleSort('date')}>
                    <div className="flex items-center gap-1">Date {sortConfig.key === 'date' && (sortConfig.direction === 'asc' ? <ChevronUp size={14}/> : <ChevronDown size={14}/>)}</div>
                </th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs text-right cursor-pointer hover:bg-slate-100 transition-colors" onClick={() => handleSort('total')}>
                    <div className="flex items-center justify-end gap-1">Montant HT</div>
                </th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs text-right cursor-pointer hover:bg-slate-100 transition-colors" onClick={() => handleSort('total')}>
                    <div className="flex items-center justify-end gap-1">Montant TTC {sortConfig.key === 'total' && (sortConfig.direction === 'asc' ? <ChevronUp size={14}/> : <ChevronDown size={14}/>)}</div>
                </th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs text-center">Statut</th>
                <th className="px-6 py-5 font-semibold uppercase tracking-wider text-xs text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredAndSortedDocuments.map((doc) => {
                 const clientName = clients.find(c => c.id === doc.clientId)?.name || 'Client Inconnu';
                 const type = doc.type || 'invoice';
                 const color = getThemeColor(type);

                 let Icon = FileText;
                 if (type === 'quote') Icon = FileCheck;
                 if (type === 'order') Icon = ShoppingBag;
                 if (type === 'credit_note') Icon = Receipt;

                 return (
                  <tr key={doc.id} className={`hover:bg-slate-50 transition-colors group ${selectedIds.has(doc.id) ? 'bg-blue-50/30' : ''}`}>
                    <td className="px-4 py-5 text-center">
                         <button onClick={() => toggleSelection(doc.id)} className={`transition-colors ${selectedIds.has(doc.id) ? 'text-blue-600' : 'text-slate-300 hover:text-slate-400'}`}>
                            {selectedIds.has(doc.id) ? <CheckSquare size={18} /> : <Square size={18} />}
                        </button>
                    </td>
                    <td className="px-4 py-5 font-mono font-medium text-slate-700">
                         <div className="flex items-center gap-3">
                            <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-${color}-600 bg-${color}-50`}>
                                <Icon size={16} />
                            </div>
                            <div className="flex flex-col">
                                <span>{doc.number}</span>
                                {doc.linkedDocumentId && <span className="text-[10px] text-slate-400 flex items-center gap-1"><LinkIcon size={8} /> Lié</span>}
                            </div>
                         </div>
                    </td>
                    <td className="px-6 py-5 text-slate-900 font-bold">{clientName}</td>
                    <td className="px-6 py-5 text-slate-500 font-medium">{new Date(doc.date).toLocaleDateString()}</td>
                    <td className="px-6 py-5 text-right font-medium text-slate-500">{doc.total.toFixed(2)} €</td>
                    <td className="px-6 py-5 text-right font-bold text-slate-900">{doc.total.toFixed(2)} €</td>
                    <td className="px-6 py-5 text-center">
                      <span className={`inline-flex px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide
                        ${doc.status === InvoiceStatus.PAID || doc.status === InvoiceStatus.ACCEPTED ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 
                          doc.status === InvoiceStatus.SENT ? 'bg-amber-50 text-amber-600 border border-amber-100' :
                          doc.status === InvoiceStatus.REJECTED ? 'bg-red-50 text-red-600 border border-red-100' :
                          'bg-slate-100 text-slate-500 border border-slate-200'}`}>
                        {doc.status}
                      </span>
                    </td>
                    <td className="px-6 py-5 text-right">
                      <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        {/* New Preview Button Explicitly */}
                        <button 
                            onClick={() => { setSelectedInvoice(doc); setView('detail'); }}
                            className="text-slate-500 hover:text-slate-800 hover:bg-slate-100 p-2 rounded-xl transition-colors"
                            title="Aperçu & Impression"
                        >
                            <Eye size={18} />
                        </button>
                        <button 
                            onClick={() => { setSelectedInvoice(doc); setView('detail'); }}
                            className="text-blue-600 hover:bg-blue-50 p-2 rounded-xl transition-colors"
                            title="Ouvrir le détail"
                        >
                            <FileText size={18} />
                        </button>
                        <button 
                            onClick={() => deleteDocument(doc.id)}
                            className="text-slate-400 hover:text-red-500 hover:bg-red-50 p-2 rounded-xl transition-colors"
                            title="Supprimer"
                        >
                            <Trash2 size={18} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
              {filteredAndSortedDocuments.length === 0 && (
                <tr>
                  <td colSpan={8} className="py-24 text-center">
                    <div className="flex flex-col items-center justify-center text-slate-300">
                        <FileText size={64} className="mb-4 opacity-50" />
                        <p className="text-lg font-medium text-slate-500">Aucun document trouvé</p>
                        <p className="text-sm">Modifiez vos filtres ou créez un nouveau document.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default InvoiceManager;

import React, { useState, useMemo } from 'react';
import { Expense, Invoice, InvoiceStatus, Supplier } from '../types';
import { Plus, Trash2, TrendingUp, TrendingDown, DollarSign, Calendar, PieChart as PieChartIcon } from 'lucide-react';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer, Legend } from 'recharts';

interface AccountingManagerProps {
  expenses: Expense[];
  setExpenses: (expenses: Expense[]) => void;
  invoices: Invoice[];
  suppliers: Supplier[];
}

const AccountingManager: React.FC<AccountingManagerProps> = ({ expenses, setExpenses, invoices, suppliers }) => {
  const [activeTab, setActiveTab] = useState<'journal' | 'bilan'>('journal');
  const [showForm, setShowForm] = useState(false);

  // Form State
  const [newExpense, setNewExpense] = useState<Partial<Expense>>({
    date: new Date().toISOString().split('T')[0],
    description: '',
    amount: 0,
    category: 'Achats',
    supplierId: ''
  });

  const handleAddExpense = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newExpense.description || !newExpense.amount) return;

    const expense: Expense = {
      id: Date.now().toString(),
      date: newExpense.date!,
      description: newExpense.description,
      amount: Number(newExpense.amount),
      category: newExpense.category!,
      supplierId: newExpense.supplierId
    };

    setExpenses([expense, ...expenses]);
    setNewExpense({
      date: new Date().toISOString().split('T')[0],
      description: '',
      amount: 0,
      category: 'Achats',
      supplierId: ''
    });
    setShowForm(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Supprimer cette dépense ?')) {
      setExpenses(expenses.filter(e => e.id !== id));
    }
  };

  // --- STATISTICS ---
  const totalRevenue = useMemo(() => {
    return invoices
      .filter(inv => inv.status === InvoiceStatus.PAID)
      .reduce((sum, inv) => sum + inv.total, 0);
  }, [invoices]);

  const totalExpenses = useMemo(() => {
    return expenses.reduce((sum, exp) => sum + exp.amount, 0);
  }, [expenses]);

  const netResult = totalRevenue - totalExpenses;

  // Estimation charges (simplifiée ~22% pour services)
  const estimatedCharges = totalRevenue * 0.22;
  const netAfterCharges = netResult - estimatedCharges;

  // Données pour le graphique
  const expensesByCategory = useMemo(() => {
    const data: Record<string, number> = {};
    expenses.forEach(exp => {
      const cat = exp.category || 'Autre';
      data[cat] = (data[cat] || 0) + exp.amount;
    });
    return Object.entries(data).map(([name, value]) => ({ name, value }));
  }, [expenses]);

  const COLORS = ['#3b82f6', '#8b5cf6', '#ec4899', '#f59e0b', '#10b981', '#6366f1'];

  return (
    <div className="space-y-8 animate-fade-in max-w-7xl mx-auto">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Comptabilité</h2>
          <p className="text-slate-500">Suivi financier et trésorerie</p>
        </div>
        <div className="flex bg-slate-100/80 p-1.5 rounded-xl border border-slate-200">
           <button 
             onClick={() => setActiveTab('journal')}
             className={`px-6 py-2 rounded-lg text-sm font-semibold transition-all shadow-sm ${activeTab === 'journal' ? 'bg-white text-blue-600 shadow' : 'bg-transparent text-slate-500 hover:text-slate-700 shadow-none'}`}
           >
             Journal
           </button>
           <button 
             onClick={() => setActiveTab('bilan')}
             className={`px-6 py-2 rounded-lg text-sm font-semibold transition-all shadow-sm ${activeTab === 'bilan' ? 'bg-white text-blue-600 shadow' : 'bg-transparent text-slate-500 hover:text-slate-700 shadow-none'}`}
           >
             Bilan
           </button>
        </div>
      </div>

      {activeTab === 'bilan' && (
        <div className="space-y-8 animate-slide-in">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                  <TrendingUp size={80} />
              </div>
              <p className="text-sm font-medium text-slate-500 mb-2">Recettes Totales</p>
              <h3 className="text-3xl font-bold text-slate-900 mb-2">{totalRevenue.toFixed(2)} €</h3>
              <div className="inline-flex items-center text-xs font-semibold text-green-600 bg-green-50 px-2 py-1 rounded-md">
                  Encassé
              </div>
            </div>

            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                  <TrendingDown size={80} />
              </div>
              <p className="text-sm font-medium text-slate-500 mb-2">Dépenses Totales</p>
              <h3 className="text-3xl font-bold text-slate-900 mb-2">{totalExpenses.toFixed(2)} €</h3>
              <div className="inline-flex items-center text-xs font-semibold text-red-600 bg-red-50 px-2 py-1 rounded-md">
                  Décaissé
              </div>
            </div>

            <div className="bg-gradient-to-br from-blue-600 to-indigo-700 text-white p-6 rounded-2xl shadow-lg shadow-blue-900/20 relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-20">
                  <DollarSign size={80} />
              </div>
              <p className="text-sm font-medium text-blue-100 mb-2">Résultat Brut</p>
              <h3 className="text-3xl font-bold mb-2">{netResult.toFixed(2)} €</h3>
              <p className="text-xs text-blue-200">Avant cotisations sociales</p>
            </div>

            <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 border-dashed relative">
              <div className="absolute top-4 right-4 text-slate-300">
                  <PieChartIcon size={24} />
              </div>
              <p className="text-sm font-medium text-slate-500 mb-2">Estimation Net</p>
              <h3 className="text-2xl font-bold text-slate-700 mb-1">{netAfterCharges.toFixed(0)} €</h3>
              <p className="text-xs text-slate-400 mt-2">
                  Après déduction approx. de {estimatedCharges.toFixed(0)}€ de charges (22%)
              </p>
            </div>
          </div>

          {/* Répartition des dépenses Graphique */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
             <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
                <h3 className="text-lg font-bold text-slate-900 mb-6">Répartition des dépenses</h3>
                {expensesByCategory.length > 0 ? (
                  <div className="h-[300px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie
                          data={expensesByCategory}
                          cx="50%"
                          cy="50%"
                          innerRadius={60}
                          outerRadius={80}
                          paddingAngle={5}
                          dataKey="value"
                        >
                          {expensesByCategory.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                          ))}
                        </Pie>
                        <Tooltip 
                          formatter={(value: number) => [`${value.toFixed(2)} €`, 'Montant']}
                          contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                        />
                        <Legend verticalAlign="bottom" height={36}/>
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                ) : (
                  <div className="h-[300px] flex items-center justify-center text-slate-400 bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                     Aucune donnée à afficher
                  </div>
                )}
             </div>

             <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 flex flex-col justify-center">
                 <h3 className="text-lg font-bold text-slate-900 mb-4">Conseil Trésorerie</h3>
                 <div className="space-y-4 text-sm text-slate-600">
                    <p>
                        Vos dépenses représentent <strong className="text-slate-900">{((totalExpenses / (totalRevenue || 1)) * 100).toFixed(1)}%</strong> de votre chiffre d'affaires.
