import React, { useState, useMemo } from 'react';
import { Supplier, Expense } from '../types';
import { Plus, Search, Trash2, Mail, MapPin, Phone, Truck, Package, X, Edit2, Wallet, ArrowDownRight, Download, SortAsc, StickyNote, Tag, Filter } from 'lucide-react';

interface SupplierManagerProps {
  suppliers: Supplier[];
  setSuppliers: (suppliers: Supplier[]) => void;
  expenses: Expense[];
}

type SortOption = 'name' | 'spending' | 'category';

const SupplierManager: React.FC<SupplierManagerProps> = ({ suppliers, setSuppliers, expenses }) => {
  const [isPanelOpen, setIsPanelOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState<SortOption>('name');
  const [selectedCategory, setSelectedCategory] = useState<string>('');
  const [editingId, setEditingId] = useState<string | null>(null);

  const [formData, setFormData] = useState<Partial<Supplier>>({
    name: '',
    email: '',
    address: '',
    phone: '',
    category: '',
    notes: ''
  });

  // --- STATS HELPERS ---

  const getSupplierStats = (supplierId: string) => {
    const supplierExpenses = expenses.filter(exp => exp.supplierId === supplierId);
    const totalSpent = supplierExpenses.reduce((sum, exp) => sum + exp.amount, 0);
    return {
      totalSpent,
      count: supplierExpenses.length
    };
  };

  // --- SORTING & FILTERING ---

  // Extraire les catégories uniques pour le filtre
  const categories = useMemo(() => {
    const cats = new Set(suppliers.map(s => s.category).filter(Boolean));
    return Array.from(cats);
  }, [suppliers]);

  const processedSuppliers = useMemo(() => {
    let result = suppliers.filter(s => 
      s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      (s.category && s.category.toLowerCase().includes(searchTerm.toLowerCase()))
    );

    if (selectedCategory) {
        result = result.filter(s => s.category === selectedCategory);
    }

    return result.sort((a, b) => {
      if (sortBy === 'spending') {
        return getSupplierStats(b.id).totalSpent - getSupplierStats(a.id).totalSpent;
      }
      if (sortBy === 'category') {
        return (a.category || '').localeCompare(b.category || '');
      }
      return a.name.localeCompare(b.name);
    });
  }, [suppliers, searchTerm, sortBy, selectedCategory, expenses]);

  // --- ACTIONS ---

  const openCreate = () => {
    setEditingId(null);
    setFormData({ name: '', email: '', address: '', phone: '', category: '', notes: '' });
    setIsPanelOpen(true);
  };

  const openEdit = (supplier: Supplier) => {
    setEditingId(supplier.id);
    setFormData({ ...supplier });
    setIsPanelOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name) return;

    if (editingId) {
        setSuppliers(suppliers.map(s => s.id === editingId ? { ...s, ...formData } as Supplier : s));
    } else {
        const supplier: Supplier = {
            id: Date.now().toString(),
            name: formData.name,
            email: formData.email,
            address: formData.address,
            phone: formData.phone,
            category: formData.category,
            notes: formData.notes
        };
        setSuppliers([...suppliers, supplier]);
    }
    setIsPanelOpen(false);
  };

  const handleDelete = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('Supprimer ce fournisseur ?')) {
      setSuppliers(suppliers.filter(s => s.id !== id));
    }
  };

  const exportCSV = () => {
    const headers = ['Nom', 'Catégorie', 'Email', 'Téléphone', 'Adresse', 'Notes', 'Total Dépensé'];
    const rows = suppliers.map(s => {
        const stats = getSupplierStats(s.id);
        return [
            `"${s.name}"`,
            `"${s.category || ''}"`,
            `"${s.email || ''}"`,
            `"${s.phone || ''}"`,
            `"${s.address?.replace(/\n/g, ' ') || ''}"`,
            `"${s.notes?.replace(/\n/g, ' ') || ''}"`,
            stats.totalSpent.toFixed(2)
        ].join(',');
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
