  date: string;
  description: string;
  amount: number;
  category: string;
  supplierId?: string;
}

export interface InvoiceItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
}

export interface Invoice {
  id: string;
  type: DocumentType; 
  number: string;
  linkedDocumentId?: string; // ID du document parent (ex: Facture pour un Avoir)
  date: string;
  dueDate: string;
  clientId: string;
  items: InvoiceItem[];
  status: string; // Changé de InvoiceStatus à string pour permettre la personnalisation
  notes?: string;
  total: number;
  reminderDate?: string; // Nouveau champ pour les rappels

  // Nouveaux champs logiques métiers
  discount?: number; // Pourcentage de remise globale (0-100)
  shipping?: number; // Frais de port / déplacement
  deposit?: number; // Montant de l'acompte déjà versé ou demandé
}

export interface UserProfile {
  companyName: string;
  siret: string;
  address: string;
  email: string;
  phone: string;
  website?: string;
  bankAccount?: string; // IBAN short
  tvaNumber?: string; // Numéro TVA Intracom
  legalMentions?: string; // Mentions spécifiques bas de page
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
  timestamp: number;
}

export type ViewState = 'dashboard' | 'invoices' | 'clients' | 'suppliers' | 'products' | 'accounting' | 'settings';

import React, { useState, useMemo } from 'react';
import { Invoice, InvoiceItem, InvoiceStatus, Client, UserProfile, DocumentType } from '../types';
import { Plus, Trash2, Printer, Wand2, ArrowLeft, FileText, Repeat, FileCheck, ShoppingBag, Receipt, Link as LinkIcon, ArrowRightCircle, Download, Calendar, ChevronDown, ChevronUp, CheckSquare, Square, Eye, ThumbsUp, ThumbsDown, ExternalLink, Bell, Edit3, AlertCircle, Percent, Truck, Coins, Calculator } from 'lucide-react';
import { suggestInvoiceDescription } from '../services/geminiService';

interface InvoiceManagerProps {
  invoices: Invoice[];
  setInvoices: (invoices: Invoice[]) => void;
  clients: Client[];
  userProfile: UserProfile;
}

const InvoiceManager: React.FC<InvoiceManagerProps> = ({ invoices, setInvoices, clients, userProfile }) => {
  const [view, setView] = useState<'list' | 'create' | 'detail'>('list');
  const [activeTab, setActiveTab] = useState<DocumentType>('invoice');
  const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null);

  // --- ETATS FILTRES & TRI ---
  const [filters, setFilters] = useState({
    dateStart: '',
    dateEnd: '',
    status: '',
    clientId: ''
  });

  const [sortConfig, setSortConfig] = useState<{ key: 'number' | 'date' | 'client' | 'total'; direction: 'asc' | 'desc' }>({
    key: 'date',
    direction: 'desc'
  });

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isCustomStatus, setIsCustomStatus] = useState(false);

  // --- ETAT NOUVEAU DOCUMENT ---
  const [newDocData, setNewDocData] = useState<Partial<Invoice>>({
    items: [],
    date: new Date().toISOString().split('T')[0],
    dueDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    type: 'invoice',
    linkedDocumentId: undefined,
    discount: 0,
    shipping: 0,
    deposit: 0
  });
  const [selectedClientId, setSelectedClientId] = useState<string>('');
  const [isGeneratingDesc, setIsGeneratingDesc] = useState(false);

  // --- LOGIQUE METIER & CALCULS ---

  // Calcul dynamique des totaux pour le formulaire de création
  const formTotals = useMemo(() => {
    const subtotal = (newDocData.items || []).reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
    const discountAmount = subtotal * ((newDocData.discount || 0) / 100);
    const totalAfterDiscount = subtotal - discountAmount;
    const totalWithShipping = totalAfterDiscount + (newDocData.shipping || 0);
    const balanceDue = Math.max(0, totalWithShipping - (newDocData.deposit || 0));

    return {
        subtotal,
        discountAmount,
        total: totalWithShipping,
        balanceDue
    };
  }, [newDocData.items, newDocData.discount, newDocData.shipping, newDocData.deposit]);

  // --- LOGIQUE TRI/FILTRE ---

  const availableStatuses = useMemo(() => {
    const currentStatuses = new Set(invoices.map(i => i.status));
    Object.values(InvoiceStatus).forEach(s => currentStatuses.add(s));
    return Array.from(currentStatuses);
  }, [invoices]);

  const handleSort = (key: 'number' | 'date' | 'client' | 'total') => {
    setSortConfig(current => ({
      key,
      direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  const filteredAndSortedDocuments = useMemo(() => {
    let docs = invoices.filter(doc => (doc.type || 'invoice') === activeTab);

    if (filters.dateStart) docs = docs.filter(doc => doc.date >= filters.dateStart);
    if (filters.dateEnd) docs = docs.filter(doc => doc.date <= filters.dateEnd);
    if (filters.status) docs = docs.filter(doc => doc.status === filters.status);
    if (filters.clientId) docs = docs.filter(doc => doc.clientId === filters.clientId);

    return docs.sort((a, b) => {
      let valA: any = '';
      let valB: any = '';

      switch (sortConfig.key) {
        case 'number': valA = a.number; valB = b.number; break;
        case 'date': valA = new Date(a.date).getTime(); valB = new Date(b.date).getTime(); break;
        case 'client':
          valA = clients.find(c => c.id === a.clientId)?.name || '';
          valB = clients.find(c => c.id === b.clientId)?.name || '';
          break;
        case 'total': valA = a.total; valB = b.total; break;
      }

      if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
      if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });
  }, [invoices, activeTab, filters, sortConfig, clients]);

  // --- BULK SELECTION ---

  const toggleSelection = (id: string) => {
    const newSelection = new Set(selectedIds);
    if (newSelection.has(id)) newSelection.delete(id);
    else newSelection.add(id);
    setSelectedIds(newSelection);
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === filteredAndSortedDocuments.length) setSelectedIds(new Set());
    else setSelectedIds(new Set(filteredAndSortedDocuments.map(d => d.id)));
  };

  const handleBulkStatusChange = (newStatus: string) => {
    if (confirm(`Modifier le statut de ${selectedIds.size} document(s) en "${newStatus}" ?`)) {
      setInvoices(invoices.map(doc => 
        selectedIds.has(doc.id) ? { ...doc, status: newStatus } : doc
      ));
      setSelectedIds(new Set());
    }
  };

  // --- HELPERS ---

  const getNextNumber = (type: DocumentType) => {
    const currentYear = new Date().getFullYear();
    const docsThisYear = invoices.filter(i => 
      (i.type || 'invoice') === type && 
      i.date.startsWith(currentYear.toString())
    ).length + 1;

    let prefix = 'FACT';
    if (type === 'quote') prefix = 'DEVIS';
    if (type === 'order') prefix = 'COMM';
    if (type === 'credit_note') prefix = 'AVOIR';

    return `${prefix}-${currentYear}-${docsThisYear.toString().padStart(3, '0')}`;
  };

  const getThemeColor = (type: DocumentType) => {
    switch(type) {
      case 'invoice': return 'blue';
      case 'quote': return 'violet';
      case 'order': return 'indigo';
      case 'credit_note': return 'rose';
      default: return 'blue';
    }
  };

  const getDocumentLabel = (type: DocumentType) => {
    switch(type) {
      case 'invoice': return 'Facture';
      case 'quote': return 'Devis';
      case 'order': return 'Commande';
      case 'credit_note': return 'Avoir';
      default: return 'Document';
    }
  };

  const openLinkedDocument = (linkedId: string) => {
    const target = invoices.find(i => i.id === linkedId);
    if (target) {
        if ((target.type || 'invoice') !== activeTab) {
           setActiveTab(target.type || 'invoice');
        }
        setSelectedInvoice(target);
        setView('detail');
    }
  };

  // --- ACTIONS ---

  const exportCurrentViewCSV = () => {
    const headers = ['Numéro', 'Date (AAAA-MM-JJ)', 'Client', 'Statut', 'Sous-Total HT', 'Remise', 'Total TTC'];
    const rows = filteredAndSortedDocuments.map(doc => {
        const clientName = clients.find(c => c.id === doc.clientId)?.name || 'Client Inconnu';
        const formattedDate = new Date(doc.date).toISOString().split('T')[0];

        // Recalcul simple pour export si champs pas présents
        const subtotal = doc.items.reduce((s, i) => s + (i.quantity * i.unitPrice), 0);
        const discountVal = subtotal * ((doc.discount || 0) / 100);

        return [
            doc.number,
            formattedDate,
            `"${clientName.replace(/"/g, '""')}"`,
            `"${doc.status}"`,
            subtotal.toFixed(2),
            discountVal.toFixed(2),
            doc.total.toFixed(2)
        ].join(',');
    });

    let filename = 'documents';
    if (activeTab === 'invoice') filename = 'factures';
    else if (activeTab === 'quote') filename = 'devis';
    else if (activeTab === 'order') filename = 'commandes';
    else if (activeTab === 'credit_note') filename = 'avoirs';

    const csvContent = "data:text/csv;charset=utf-8,\uFEFF" + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `${filename}_export_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const getExportLabel = () => {
      switch(activeTab) {
          case 'invoice': return 'Export Factures';
          case 'quote': return 'Export Devis';
          case 'order': return 'Export Commandes';
          case 'credit_note': return 'Export Avoirs';
          default: return 'Export CSV';
      }
  };

  // --- FORM ITEM MANIPULATION ---

  const addItem = () => {
    const items = newDocData.items || [];
    setNewDocData({
      ...newDocData,
      items: [...items, { id: Date.now().toString(), description: '', quantity: 1, unitPrice: 0 }]
    });
  };

  const updateItem = (id: string, field: keyof InvoiceItem, value: any) => {
    const items = newDocData.items?.map(item => 
      item.id === id ? { ...item, [field]: value } : item
    ) || [];
    setNewDocData({ ...newDocData, items });
  };

  const removeItem = (id: string) => {
    const items = newDocData.items?.filter(item => item.id !== id) || [];
    setNewDocData({ ...newDocData, items });
  };

  const handleGenerateDescription = async (itemId: string, currentDesc: string) => {
    if (!selectedClientId) {
      alert("Veuillez sélectionner un client d'abord.");
      return;
    }
    const client = clients.find(c => c.id === selectedClientId);
    if (!client) return;

    setIsGeneratingDesc(true);
    const suggestion = await suggestInvoiceDescription(client.name, currentDesc || "Service général");
    setIsGeneratingDesc(false);

    updateItem(itemId, 'description', suggestion);
  };

  const saveDocument = () => {
    if (!selectedClientId || !newDocData.date || !newDocData.items?.length) {
      alert("Veuillez remplir tous les champs obligatoires (client, date, articles).");
      return;
    }

    // Le total final sauvegardé est le total "Net à payer" théorique avant acompte pour le CA
    // Cependant, la logique veut souvent que le total de la facture soit le montant total de la prestation.
    // L'acompte est une modalité de paiement.
    // Stockons le total "Net" (après remise et port) dans `total`.
    const type = newDocData.type || activeTab;

    const document: Invoice = {
      id: Date.now().toString(),
      type: type,
      number: getNextNumber(type),
      clientId: selectedClientId,
      linkedDocumentId: newDocData.linkedDocumentId,
      date: newDocData.date!,
      dueDate: newDocData.dueDate!,
      items: newDocData.items,
      status: InvoiceStatus.DRAFT,
      total: formTotals.total, // Total TTC final
      discount: newDocData.discount || 0,
      shipping: newDocData.shipping || 0,
      deposit: newDocData.deposit || 0,
      notes: newDocData.notes
    };

    setInvoices([document, ...invoices]);
    setView('list');
    setNewDocData({
      items: [],
      date: new Date().toISOString().split('T')[0],
      dueDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      type: activeTab,
      linkedDocumentId: undefined,
      discount: 0, 
      shipping: 0,
      deposit: 0
    });
    setSelectedClientId('');
  };

  // --- TRANSFORMATION LOGIC ---

  const convertQuoteToInvoice = (quote: Invoice) => {
    if (!confirm("Convertir ce devis en facture ?")) return;

    let updatedInvoices = invoices;
    if (quote.status !== InvoiceStatus.ACCEPTED) {
         updatedInvoices = invoices.map(i => 
            i.id === quote.id ? { ...i, status: InvoiceStatus.ACCEPTED } : i
        );
    }

    const newInvoice: Invoice = {
        ...quote,
        id: Date.now().toString(),
        type: 'invoice',
        linkedDocumentId: quote.id,
        number: getNextNumber('invoice'),
        date: new Date().toISOString().split('T')[0],
        status: InvoiceStatus.DRAFT,
        notes: `Facture suite au devis ${quote.number}`
    };

    setInvoices([newInvoice, ...updatedInvoices]);
    setActiveTab('invoice');
    setSelectedInvoice(newInvoice);
  };

  const convertOrderToInvoice = (order: Invoice) => {
     if (!confirm("Facturer cette commande ?")) return;

     const newInvoice: Invoice = {
         ...order,
         id: Date.now().toString(),
         type: 'invoice',
         linkedDocumentId: order.id,
         number: getNextNumber('invoice'),
         date: new Date().toISOString().split('T')[0],
         status: InvoiceStatus.DRAFT,
         notes: `Facture pour la commande ${order.number}`
     };
     setInvoices([newInvoice, ...invoices]);
     setActiveTab('invoice');
     setSelectedInvoice(newInvoice);
  };

  const createCreditNoteFromInvoice = (invoice: Invoice) => {
    if (!confirm("Créer un avoir pour cette facture ?")) return;

    setNewDocData({
        items: invoice.items.map(i => ({...i})),
        date: new Date().toISOString().split('T')[0],
        dueDate: new Date().toISOString().split('T')[0],
        type: 'credit_note',
        linkedDocumentId: invoice.id,
        discount: invoice.discount,
        notes: `Avoir sur facture ${invoice.number}`
    });
    setSelectedClientId(invoice.clientId);
    setActiveTab('credit_note');
    setView('create');
  };

  const updateStatus = (id: string, status: string) => {
    if (status === 'CUSTOM_INPUT') {
      setIsCustomStatus(true);
      return;
    }
    setInvoices(invoices.map(inv => inv.id === id ? { ...inv, status } : inv));
    if (selectedInvoice && selectedInvoice.id === id) {
        setSelectedInvoice({ ...selectedInvoice, status });
    }
    setIsCustomStatus(false);
  };

  const updateReminder = (id: string, date: string) => {
    setInvoices(invoices.map(inv => inv.id === id ? { ...inv, reminderDate: date } : inv));
    if (selectedInvoice && selectedInvoice.id === id) {
        setSelectedInvoice({ ...selectedInvoice, reminderDate: date });
    }
  }

  const deleteDocument = (id: string) => {
     if(confirm("Supprimer ce document définitivement ?")) {
       setInvoices(invoices.filter(inv => inv.id !== id));
       if (selectedInvoice?.id === id) setView('list');
     }
  }

  const startCreate = () => {
      setNewDocData({
        items: [],
        date: new Date().toISOString().split('T')[0],
        dueDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
        type: activeTab,
        linkedDocumentId: undefined,
        discount: 0,
        shipping: 0,
        deposit: 0
      });
      setSelectedClientId('');
      setView('create');
  }

  // --- STYLES HELPER ---
  const themeColor = getThemeColor(activeTab);

  // --- RENDERERS ---

  if (view === 'create') {
    const selectedClient = clients.find(c => c.id === selectedClientId);

    return (
      <div className="max-w-6xl mx-auto animate-slide-in pb-20">
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-4">
            <button onClick={() => setView('list')} className="p-2 hover:bg-slate-200 rounded-full transition-colors text-slate-500">
              <ArrowLeft size={20} />
            </button>
            <div>
              <h2 className="text-2xl font-bold text-slate-900">Éditeur : {getDocumentLabel(activeTab)}</h2>
              <p className="text-slate-500 text-sm">Créez votre document en quelques clics.</p>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Colonne Gauche : Config & Client */}
            <div className="lg:col-span-2 space-y-6">
                 {/* Card Client & Dates */}
                <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 p-8">
                    {newDocData.linkedDocumentId && (
                        <div className="mb-6 inline-flex items-center gap-2 bg-slate-100 text-slate-600 px-3 py-1.5 rounded-full text-xs font-semibold">
                            <LinkIcon size={12} />
                            Lié au document ID: {invoices.find(i => i.id === newDocData.linkedDocumentId)?.number || 'Inconnu'}
                        </div>
                    )}

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Client</label>
                            <select 
                                className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-${themeColor}-500/20 focus:border-${themeColor}-500 outline-none transition-all font-semibold`}
                                value={selectedClientId}
                                onChange={(e) => setSelectedClientId(e.target.value)}
                                disabled={!!newDocData.linkedDocumentId}
                            >
                                <option value="">Sélectionner un client...</option>
                                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                            </select>
                            {selectedClient && (
                                <div className="mt-4 p-4 bg-slate-50 rounded-xl border border-slate-100 text-sm">
                                    <p className="font-bold text-slate-800">{selectedClient.name}</p>
                                    <p className="text-slate-500 whitespace-pre-line mt-1">{selectedClient.address}</p>
                                    {selectedClient.siret && <p className="text-xs text-slate-400 mt-2 font-mono">SIRET: {selectedClient.siret}</p>}
                                </div>
                            )}
                        </div>
                        <div className="space-y-4">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Date d'émission</label>
                                <input 
                                type="date" 
                                className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-${themeColor}-500/20 focus:border-${themeColor}-500 outline-none transition-all`}
                                value={newDocData.date}
                                onChange={(e) => setNewDocData({...newDocData, date: e.target.value})}
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Date d'échéance</label>
                                <input 
                                type="date" 
                                className={`w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-${themeColor}-500/20 focus:border-${themeColor}-500 outline-none transition-all`}
                                value={newDocData.dueDate}
                                onChange={(e) => setNewDocData({...newDocData, dueDate: e.target.value})}
                                />
                            </div>
                        </div>
                    </div>
                </div>

                {/* Card Items */}
                <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 p-8">
                     <div className="flex justify-between items-center mb-6">
                        <h3 className="text-lg font-bold text-slate-900">Prestations & Produits</h3>
                     </div>

                     <div className="space-y-4">
                        {newDocData.items?.map((item, index) => (
                            <div key={item.id} className="flex flex-col md:flex-row gap-4 items-start md:items-center bg-slate-50 p-4 rounded-xl border border-slate-100 group hover:border-blue-200 transition-colors">
                                <span className="bg-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold text-slate-400 border border-slate-200 shadow-sm shrink-0">
                                    {index + 1}
                                </span>
                                <div className="flex-1 w-full relative">
                                    <input 
                                        type="text" 
                                        placeholder="Description..."
                                        className="w-full bg-transparent border-b border-slate-200 focus:border-blue-500 outline-none py-1 text-slate-900 font-medium placeholder:text-slate-400"
                                        value={item.description}
                                        onChange={(e) => updateItem(item.id, 'description', e.target.value)}
                                    />
                                     <button 
                                        onClick={() => handleGenerateDescription(item.id, item.description)}
                                        className="absolute right-0 top-1/2 -translate-y-1/2 text-indigo-400 hover:text-indigo-600 transition-colors opacity-0 group-hover:opacity-100"
                                        title="Améliorer avec IA"
                                    >
                                        <Wand2 size={14} className={isGeneratingDesc ? "animate-spin" : ""} />
                                    </button>
                                </div>
                                <div className="flex gap-4 w-full md:w-auto">
                                    <div className="flex flex-col w-20">
                                        <label className="text-[10px] uppercase font-bold text-slate-400">Qté</label>
                                        <input 
                                            type="number" min="0" step="0.5"
                                            className="bg-white border border-slate-200 rounded-lg p-1.5 text-right outline-none focus:border-blue-500"
                                            value={item.quantity}
                                            onChange={(e) => updateItem(item.id, 'quantity', parseFloat(e.target.value))}
                                        />
                                    </div>
                                    <div className="flex flex-col w-24">
                                        <label className="text-[10px] uppercase font-bold text-slate-400">Prix Uni.</label>
                                        <input 
                                            type="number" min="0" step="0.01"
                                            className="bg-white border border-slate-200 rounded-lg p-1.5 text-right outline-none focus:border-blue-500"
                                            value={item.unitPrice}
                                            onChange={(e) => updateItem(item.id, 'unitPrice', parseFloat(e.target.value))}
                                        />
                                    </div>
                                    <div className="flex flex-col w-24 justify-end">
                                        <div className="text-right font-bold text-slate-900 py-2">
                                            {(item.quantity * item.unitPrice).toFixed(2)} €
                                        </div>
                                    </div>
                                    <button onClick={() => removeItem(item.id)} className="self-end mb-2 text-slate-300 hover:text-red-500 transition-colors">
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            </div>
                        ))}

                        <button onClick={addItem} className={`w-full py-3 border-2 border-dashed border-slate-200 rounded-xl text-slate-500 hover:border-${themeColor}-400 hover:text-${themeColor}-600 transition-all font-medium flex items-center justify-center gap-2`}>
                            <Plus size={18} /> Ajouter une ligne
                        </button>
                     </div>
                </div>

                <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 p-8">
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Notes & Conditions</label>
                    <textarea 
                        className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all resize-none"
                        rows={3}
                        placeholder="Conditions de paiement, mentions légales spécifiques..."
                        value={newDocData.notes || ''}
                        onChange={e => setNewDocData({...newDocData, notes: e.target.value})}
                    />
                </div>
            </div>

            {/* Colonne Droite : Totaux & Validation */}
            <div className="lg:col-span-1 space-y-6">
                <div className="bg-slate-900 text-white rounded-[2rem] p-8 shadow-xl shadow-slate-200 sticky top-6">
                    <h3 className="text-lg font-bold mb-6 flex items-center gap-2">
                        <Calculator size={20} className="text-blue-400" />
                        Récapitulatif
                    </h3>

                    <div className="space-y-4 mb-6 text-sm">
                        <div className="flex justify-between items-center text-slate-300">
                            <span>Sous-total HT</span>
                            <span className="font-mono">{formTotals.subtotal.toFixed(2)} €</span>
                        </div>

                        {/* Remise Input */}
                        <div className="flex justify-between items-center">
                            <div className="flex items-center gap-2 text-slate-300">
                                <Percent size={14} />
                                <span>Remise (%)</span>
                            </div>
                            <input 
                                type="number" min="0" max="100"
                                className="w-16 bg-slate-800 border border-slate-700 rounded-lg px-2 py-1 text-right text-white outline-none focus:border-blue-500"
                                value={newDocData.discount || ''}
                                onChange={(e) => setNewDocData({...newDocData, discount: parseFloat(e.target.value)})}
                                placeholder="0"
                            />
                        </div>
                        {formTotals.discountAmount > 0 && (
                            <div className="flex justify-end text-xs text-green-400 font-mono">
                                - {formTotals.discountAmount.toFixed(2)} €
                            </div>
                        )}

                        {/* Shipping Input */}
                        <div className="flex justify-between items-center">
                            <div className="flex items-center gap-2 text-slate-300">
                                <Truck size={14} />
                                <span>Frais de port</span>
                            </div>
                            <input 
                                type="number" min="0"
                                className="w-20 bg-slate-800 border border-slate-700 rounded-lg px-2 py-1 text-right text-white outline-none focus:border-blue-500"
                                value={newDocData.shipping || ''}
                                onChange={(e) => setNewDocData({...newDocData, shipping: parseFloat(e.target.value)})}
                                placeholder="0.00"
                            />
                        </div>

                        <div className="h-px bg-slate-700 my-4"></div>

                        <div className="flex justify-between items-end">
                            <span className="font-bold text-lg">Total</span>
                            <span className="font-bold text-2xl tracking-tight">{formTotals.total.toFixed(2)} €</span>
                        </div>

                         {/* Deposit Input */}
                         <div className="bg-slate-800/50 p-4 rounded-xl mt-6">
                            <div className="flex justify-between items-center mb-2">
                                <div className="flex items-center gap-2 text-slate-300 text-xs uppercase font-bold">
                                    <Coins size={12} />
                                    <span>Acompte {activeTab === 'quote' ? 'demandé' : 'versé'}</span>
                                </div>
                                <input 
                                    type="number" min="0"
                                    className="w-24 bg-slate-900 border border-slate-700 rounded-lg px-2 py-1 text-right text-white outline-none focus:border-blue-500 font-mono text-sm"
                                    value={newDocData.deposit || ''}
                                    onChange={(e) => setNewDocData({...newDocData, deposit: parseFloat(e.target.value)})}
                                    placeholder="0.00"
                                />
                            </div>
                            <div className="flex justify-between items-center pt-2 border-t border-slate-700/50">
                                <span className="text-blue-200 font-bold text-sm">Reste à payer</span>
                                <span className="text-blue-200 font-bold font-mono text-lg">{formTotals.balanceDue.toFixed(2)} €</span>
                            </div>
                        </div>
                    </div>

                    <button 
                        onClick={saveDocument}
                        className={`w-full bg-${themeColor}-600 text-white py-4 rounded-xl hover:bg-${themeColor}-500 font-bold shadow-lg shadow-${themeColor}-900/50 transition-all hover:scale-[1.02] active:scale-95`}
                    >
                        Enregistrer le document
                    </button>
                </div>
            </div>
        </div>
      </div>
    );
  }

  if (view === 'detail' && selectedInvoice) {
    const client = clients.find(c => c.id === selectedInvoice.clientId);
    const docType = selectedInvoice.type || 'invoice';
    const docTheme = getThemeColor(docType);
    const linkedDoc = selectedInvoice.linkedDocumentId ? invoices.find(i => i.id === selectedInvoice.linkedDocumentId) : null;

    let title = 'FACTURE';
    let icon = <FileText size={24} />;

    if (docType === 'quote') { title = 'DEVIS'; icon = <FileCheck size={24} />; }
    if (docType === 'order') { title = 'COMMANDE'; icon = <ShoppingBag size={24} />; }
    if (docType === 'credit_note') { title = 'AVOIR'; icon = <Receipt size={24} />; }

    // Calculations for display
    const subtotal = selectedInvoice.items.reduce((s, i) => s + (i.quantity * i.unitPrice), 0);
    const discountVal = subtotal * ((selectedInvoice.discount || 0) / 100);
    const totalBeforeDeposit = subtotal - discountVal + (selectedInvoice.shipping || 0);
    const balanceDue = totalBeforeDeposit - (selectedInvoice.deposit || 0);

    return (
      <div className="max-w-4xl mx-auto animate-fade-in pb-10">
        <div className="sticky top-0 z-10 bg-slate-50/80 backdrop-blur-md py-4 mb-6 flex justify-between items-center print:hidden border-b border-slate-200/50">
          <button onClick={() => setView('list')} className="flex items-center gap-2 text-slate-600 hover:text-slate-900 font-medium px-4 py-2 hover:bg-white rounded-lg transition-all">
            <ArrowLeft size={18} /> Retour
          </button>

          <div className="flex items-center gap-3">
             {/* CUSTOM STATUS SELECTOR */}
            <div className="flex items-center gap-2 bg-white border border-slate-200 rounded-lg p-1 pr-3 shadow-sm">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider ml-2">Statut</span>
                {isCustomStatus ? (
                  <div className="flex items-center gap-1">
                    <input 
                      type="text" 
                      autoFocus
                      className="text-sm font-semibold rounded-md py-1 px-2 outline-none bg-slate-50 w-32 border border-blue-200"
                      placeholder="Nouveau statut"
                      value={selectedInvoice.status}
                      onChange={(e) => updateStatus(selectedInvoice.id, e.target.value)}
                      onBlur={() => setIsCustomStatus(false)}
                      onKeyDown={(e) => e.key === 'Enter' && setIsCustomStatus(false)}
                    />
                    <button onClick={() => setIsCustomStatus(false)} className="text-slate-400 hover:text-slate-600"><CheckSquare size={14}/></button>
                  </div>
                ) : (
                  <select 
                    value={selectedInvoice.status}
                    onChange={(e) => updateStatus(selectedInvoice.id, e.target.value)}
                    className={`text-sm font-semibold rounded-md py-1 px-2 cursor-pointer outline-none bg-transparent ${
                        selectedInvoice.status === InvoiceStatus.PAID || selectedInvoice.status === InvoiceStatus.ACCEPTED ? 'text-emerald-600' :
                        selectedInvoice.status === InvoiceStatus.SENT ? 'text-amber-600' :
                        selectedInvoice.status === InvoiceStatus.REJECTED ? 'text-red-600' :
                        'text-slate-600'
                    }`}
                  >
                  {availableStatuses.map(s => <option key={s} value={s}>{s}</option>)}
                  <option value="CUSTOM_INPUT" className="font-bold text-blue-600">+ Personnalisé...</option>
                  </select>
                )}
            </div>

            {/* Reminder Feature */}
            {selectedInvoice.status !== InvoiceStatus.PAID && (
                 <div className="flex items-center bg-white border border-slate-200 rounded-lg shadow-sm relative group">
                    <div className="p-2 text-slate-400 group-hover:text-blue-500 transition-colors">
                        <Bell size={16} />
                    </div>
                    <input 
                        type="date" 
                        className="text-xs font-medium text-slate-600 bg-transparent outline-none w-28 cursor-pointer"
                        value={selectedInvoice.reminderDate || ''}
                        onChange={(e) => updateReminder(selectedInvoice.id, e.target.value)}
                        title="Date de rappel"
                    />
                 </div>
            )}

            {/* QUOTE ACTIONS */}
            {docType === 'quote' && selectedInvoice.status === InvoiceStatus.SENT && (
                <>
                <button 
                    onClick={() => updateStatus(selectedInvoice.id, InvoiceStatus.ACCEPTED)}
                    className="flex items-center gap-2 px-3 py-2 bg-emerald-100 text-emerald-700 hover:bg-emerald-200 rounded-lg transition-colors font-medium text-xs"
                    title="Accepter le devis"
                >
                    <ThumbsUp size={14} /> Accepter
                </button>
                 <button 
                    onClick={() => updateStatus(selectedInvoice.id, InvoiceStatus.REJECTED)}
                    className="flex items-center gap-2 px-3 py-2 bg-slate-100 text-slate-600 hover:bg-red-100 hover:text-red-600 rounded-lg transition-colors font-medium text-xs"
                    title="Refuser le devis"
                >
                    <ThumbsDown size={14} /> Refuser
                </button>
                </>
            )}

            {docType === 'quote' && selectedInvoice.status === InvoiceStatus.ACCEPTED && (
                <button 
                    onClick={() => convertQuoteToInvoice(selectedInvoice)}
                    className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-colors shadow-md shadow-emerald-200 font-medium text-sm"
                >
                    <Repeat size={16} /> Convertir en Facture
                </button>
            )}

             {docType === 'order' && (
                <button 
                    onClick={() => convertOrderToInvoice(selectedInvoice)}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-md shadow-indigo-200 font-medium text-sm"
                >
                    <ArrowRightCircle size={16} /> Facturer la commande
                </button>
            )}

            {docType === 'invoice' && (
                <button 
                    onClick={() => createCreditNoteFromInvoice(selectedInvoice)}
                    className="flex items-center gap-2 px-4 py-2 bg-rose-600 text-white rounded-lg hover:bg-rose-700 transition-colors shadow-md shadow-rose-200 font-medium text-sm"
                >
                    <Receipt size={16} /> Créer un avoir
                </button>
            )}

            <button 
              onClick={() => window.print()}
              className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 transition-colors shadow-lg shadow-slate-200 font-medium text-sm"
              title="Ceci est l'aperçu avant impression"
            >
              <Printer size={16} /> Imprimer
            </button>
          </div>
        </div>

        {/* Invoice Preview - Paper Look */}
        <div 
            className="bg-white p-12 shadow-2xl shadow-slate-200/50 rounded-sm min-h-[1000px] relative mx-auto print:shadow-none print:w-full print:m-0" 
            id="invoice-preview"
            style={{ maxWidth: '210mm' }}
        >
           {/* Visual Link Banner */}
           {linkedDoc && (
             <div 
                className="bg-blue-50 border border-blue-100 rounded-xl p-4 mb-8 flex items-center justify-between cursor-pointer hover:bg-blue-100 transition-colors print:hidden"
                onClick={() => openLinkedDocument(linkedDoc.id)}
             >
                <div className="flex items-center gap-3">
                    <div className="bg-blue-200 p-2 rounded-lg text-blue-700">
                        <LinkIcon size={18} />
                    </div>
                    <div>
                        <p className="text-sm font-bold text-blue-900">Document lié : {linkedDoc.type === 'quote' ? 'Devis' : linkedDoc.type === 'order' ? 'Commande' : 'Facture'} #{linkedDoc.number}</p>
                        <p className="text-xs text-blue-600">Cliquez pour voir le document original</p>
                    </div>
                </div>
                <ArrowRightCircle size={18} className="text-blue-400" />
             </div>
           )}

           <div className="flex justify-between items-start mb-16">
            <div>
               <div className="flex items-center gap-3 mb-6">
                 <div className={`w-12 h-12 bg-${docTheme}-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-${docTheme}-200`}>
                    {icon}
                 </div>
                 <h1 className="text-2xl font-bold text-slate-900 tracking-tight uppercase">{userProfile.companyName}</h1>
               </div>
               <div className="text-sm text-slate-500 leading-relaxed font-medium">
                <p>{userProfile.address}</p>
                <p>{userProfile.email} • {userProfile.phone}</p>
                <p className="mt-2 font-mono text-xs text-slate-400">SIRET: {userProfile.siret}</p>
              </div>
            </div>
            <div className="text-right">
              <h2 className="text-5xl font-light text-slate-900 mb-2 tracking-tight">{title}</h2>
              <p className={`text-${docTheme}-600 font-mono font-bold text-lg`}>#{selectedInvoice.number}</p>

              <div className="mt-10 text-right bg-slate-50 p-6 rounded-2xl border border-slate-100 inline-block min-w-[200px]">
                <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">Client</h3>
                <p className="font-bold text-slate-900 text-lg">{client?.name}</p>
                <p className="text-sm text-slate-500 whitespace-pre-line mt-1">{client?.address}</p>
                {client?.siret && <p className="text-xs text-slate-400 mt-2 font-mono">SIRET: {client.siret}</p>}
              </div>
            </div>
          </div>

          <div className="flex gap-16 mb-12 border-y border-slate-100 py-8">
             <div>
                <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5">Date d'émission</span>
                <span className="font-bold text-slate-900 text-lg">{new Date(selectedInvoice.date).toLocaleDateString('fr-FR')}</span>
             </div>
             <div>
                <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5">{docType === 'quote' ? 'Validité' : 'Échéance'}</span>
                <span className="font-bold text-slate-900 text-lg">{new Date(selectedInvoice.dueDate).toLocaleDateString('fr-FR')}</span>
             </div>
          </div>

          <table className="w-full mb-8">
            <thead>
              <tr className="border-b-2 border-slate-900 text-left text-[10px] font-bold text-slate-900 uppercase tracking-widest">
                <th className="py-4">Description</th>
                <th className="py-4 text-right">Qté</th>
                <th className="py-4 text-right">Prix Unitaire</th>
                <th className="py-4 text-right">Total</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm">
              {selectedInvoice.items.map((item, idx) => (
                <tr key={idx}>
                  <td className="py-5 text-slate-800 font-semibold">{item.description}</td>
                  <td className="py-5 text-right text-slate-500 font-medium">{item.quantity}</td>
                  <td className="py-5 text-right text-slate-500 font-medium">{item.unitPrice.toFixed(2)} €</td>
                  <td className="py-5 text-right font-bold text-slate-900">{(item.quantity * item.unitPrice).toFixed(2)} €</td>
                </tr>
              ))}
            </tbody>
          </table>

          <div className="flex justify-end mb-16">
            <div className="w-1/2">
                <div className="space-y-3 pb-6 border-b border-slate-100">
                    <div className="flex justify-between text-sm">
                        <span className="text-slate-500 font-medium">Sous-Total HT</span>
                        <span className="font-bold text-slate-900">{subtotal.toFixed(2)} €</span>
                    </div>
                    {(selectedInvoice.discount || 0) > 0 && (
                        <div className="flex justify-between text-sm text-green-600">
                            <span className="font-medium">Remise ({selectedInvoice.discount}%)</span>
                            <span className="font-bold">- {discountVal.toFixed(2)} €</span>
                        </div>
                    )}
                    {(selectedInvoice.shipping || 0) > 0 && (
                         <div className="flex justify-between text-sm">
                            <span className="text-slate-500 font-medium">Frais de port</span>
                            <span className="font-bold text-slate-900">+ {selectedInvoice.shipping?.toFixed(2)} €</span>
                        </div>
                    )}
                     <div className="flex justify-between text-sm">
                        <span className="text-slate-500 font-medium">TVA (non applicable)</span>
                        <span className="font-bold text-slate-900">0.00 €</span>
                    </div>
                </div>

                <div className="pt-6">
                    <div className="flex justify-between items-end mb-2">
                         <span className={`text-${docTheme}-900 font-bold text-lg`}>Total TTC</span>
                         <span className={`text-${docTheme}-600 font-bold text-xl`}>{totalBeforeDeposit.toFixed(2)} €</span>
                    </div>

                    {(selectedInvoice.deposit || 0) > 0 && (
                        <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 mt-4">
                            <div className="flex justify-between text-sm text-slate-600 mb-2">
                                <span>Acompte {docType === 'quote' ? 'demandé' : 'déjà réglé'}</span>
                                <span className="font-mono">- {selectedInvoice.deposit?.toFixed(2)} €</span>
                            </div>
                            <div className={`flex justify-between font-bold text-lg text-${docTheme}-700 border-t border-slate-200 pt-2`}>
                                <span>Reste à payer</span>
                                <span>{balanceDue.toFixed(2)} €</span>
                            </div>
                        </div>
                    )}
                </div>
            </div>
          </div>

          <div className="absolute bottom-12 left-12 right-12 text-center">
             {selectedInvoice.notes && (
                 <div className="mb-8 bg-slate-50 p-6 rounded-2xl text-sm text-slate-600 text-left border border-slate-100 relative">
                     <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Notes</span>
                     {selectedInvoice.notes}
                 </div>
             )}
            <div className="text-[10px] text-slate-400 leading-relaxed border-t border-slate-100 pt-8 font-medium">
                <p>TVA non applicable, art. 293 B du CGI.</p>
                {userProfile.bankAccount && <p className="mt-1 font-mono text-slate-500">IBAN : {userProfile.bankAccount}</p>}
                {(docType === 'invoice') && <p className="mt-2 text-slate-400">En cas de retard de paiement, une pénalité de 3 fois le taux d'intérêt légal sera appliquée. 
                Une indemnité forfaitaire de 40€ pour frais de recouvrement sera due.</p>}
            </div>
          </div>
        </div>
      </div>
    );
  }

  // List View remains mostly similar but we ensure context is correct
  return (
    <div className="space-y-8 max-w-7xl mx-auto animate-fade-in">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-900">Documents</h2>
            <p className="text-slate-500">Gérez vos documents commerciaux.</p>
        </div>

        {/* Type Toggle Pills */}
        <div className="bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200 flex flex-wrap gap-1">
            <button onClick={() => { setActiveTab('invoice'); setSelectedIds(new Set()); }} className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 flex items-center gap-2 ${activeTab === 'invoice' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'}`}><FileText size={16} /> Factures</button>
            <button onClick={() => { setActiveTab('quote'); setSelectedIds(new Set()); }} className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 flex items-center gap-2 ${activeTab === 'quote' ? 'bg-violet-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'}`}><FileCheck size={16} /> Devis</button>
            <button onClick={() => { setActiveTab('order'); setSelectedIds(new Set()); }} className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 flex items-center gap-2 ${activeTab === 'order' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'}`}><ShoppingBag size={16} /> Commandes</button>
            <button onClick={() => { setActiveTab('credit_note'); setSelectedIds(new Set()); }} className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300 flex items-center gap-2 ${activeTab === 'credit_note' ? 'bg-rose-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-50'}`}><Receipt size={16} /> Avoirs</button>
        </div>

        <div className="flex gap-2">
            <button 
                onClick={exportCurrentViewCSV}
                className="bg-white hover:bg-slate-50 text-slate-600 border border-slate-200 px-4 py-2.5 rounded-xl flex items-center gap-2 transition-all font-medium shadow-sm"
                title={`Exporter en CSV`}
            >
                <Download size={18} />
                <span className="hidden sm:inline">{getExportLabel()}</span>
            </button>

            <button 
                onClick={startCreate}
                className={`bg-${themeColor}-600 hover:bg-${themeColor}-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-${themeColor}-200 font-medium`}
            >
                <Plus size={18} />
                Créer
            </button>
        </div>
      </div>

      {/* FILTER BAR */}
      <div className="bg-white rounded-2xl p-4 shadow-sm border border-slate-200 flex flex-wrap gap-4 items-end">
         <div className="flex flex-col gap-1">
             <label className="text-xs font-bold text-slate-500 uppercase">Du</label>
             <div className="relative">
                 <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                 <input 
                    type="date" 
                    className="pl-9 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-all"
                    value={filters.dateStart}
                    onChange={(e) => setFilters({...filters, dateStart: e.target.value})}
                 />
             </div>
         </div>
         <div className="flex flex-col gap-1">
             <label className="text-xs font-bold text-slate-500 uppercase">Au</label>
             <div className="relative">
                 <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
                 <input 
                    type="date" 
                    className="pl-9 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-all"
                    value={filters.dateEnd}
                    onChange={(e) => setFilters({...filters, dateEnd: e.target.value})}
                 />
             </div>
         </div>
         <div className="flex flex-col gap-1">
             <label className="text-xs font-bold text-slate-500 uppercase">Client</label>
             <select 
                className="px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-all w-40"
                value={filters.clientId}
                onChange={(e) => setFilters({...filters, clientId: e.target.value})}
             >
                 <option value="">Tous</option>
                 {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
             </select>
         </div>
         <div className="flex flex-col gap-1">
             <label className="text-xs font-bold text-slate-500 uppercase">Statut</label>
             <select 
                className="px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-all w-32"
                value={filters.status}
                onChange={(e) => setFilters({...filters, status: e.target.value})}
             >
                 <option value="">Tous</option>
                 {availableStatuses.map(s => <option key={s} value={s}>{s}</option>)}
             </select>
         </div>
         <button 
            onClick={() => setFilters({ dateStart: '', dateEnd: '', status: '', clientId: '' })}
            className="px-4 py-2 text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors mb-0.5"
         >
             Réinitialiser
