        <div>
          <h2 className="text-2xl font-bold text-slate-900">Comptabilité</h2>
          <p className="text-slate-500">Suivi financier et trésorerie</p>
        </div>
        <div className="flex bg-slate-100/80 p-1.5 rounded-xl border border-slate-200">
           <button 
             onClick={() => setActiveTab('journal')}
             className={`px-6 py-2 rounded-lg text-sm font-semibold transition-all shadow-sm ${activeTab === 'journal' ? 'bg-white text-blue-600 shadow' : 'bg-transparent text-slate-500 hover:text-slate-700 shadow-none'}`}
           >
             Journal
           </button>
           <button 
             onClick={() => setActiveTab('bilan')}
             className={`px-6 py-2 rounded-lg text-sm font-semibold transition-all shadow-sm ${activeTab === 'bilan' ? 'bg-white text-blue-600 shadow' : 'bg-transparent text-slate-500 hover:text-slate-700 shadow-none'}`}
           >
             Bilan
           </button>
        </div>
      </div>

      {activeTab === 'bilan' && (
        <div className="space-y-8 animate-slide-in">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                  <TrendingUp size={80} />
              </div>
              <p className="text-sm font-medium text-slate-500 mb-2">Recettes Totales</p>
              <h3 className="text-3xl font-bold text-slate-900 mb-2">{totalRevenue.toFixed(2)} €</h3>
              <div className="inline-flex items-center text-xs font-semibold text-green-600 bg-green-50 px-2 py-1 rounded-md">
                  Encaissé
              </div>
            </div>

            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                  <TrendingDown size={80} />
              </div>
              <p className="text-sm font-medium text-slate-500 mb-2">Dépenses Totales</p>
              <h3 className="text-3xl font-bold text-slate-900 mb-2">{totalExpenses.toFixed(2)} €</h3>
              <div className="inline-flex items-center text-xs font-semibold text-red-600 bg-red-50 px-2 py-1 rounded-md">
                  Décaissé
              </div>
            </div>

            <div className="bg-gradient-to-br from-blue-600 to-indigo-700 text-white p-6 rounded-2xl shadow-lg shadow-blue-900/20 relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-20">
                  <DollarSign size={80} />
              </div>
              <p className="text-sm font-medium text-blue-100 mb-2">Résultat Brut</p>
              <h3 className="text-3xl font-bold mb-2">{netResult.toFixed(2)} €</h3>
              <p className="text-xs text-blue-200">Avant cotisations sociales</p>
            </div>

            <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 border-dashed relative">
              <div className="absolute top-4 right-4 text-slate-300">
                  <PieChartIcon size={24} />
              </div>
              <p className="text-sm font-medium text-slate-500 mb-2">Estimation Net</p>
              <h3 className="text-2xl font-bold text-slate-700 mb-1">{netAfterCharges.toFixed(0)} €</h3>
              <p className="text-xs text-slate-400 mt-2">
                  Après déduction approx. de {estimatedCharges.toFixed(0)}€ de charges (22%)
              </p>
            </div>
          </div>

          {/* Répartition des dépenses Graphique */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
             <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
                <h3 className="text-lg font-bold text-slate-900 mb-6">Répartition des dépenses</h3>
                {expensesByCategory.length > 0 ? (
                  <div className="h-[300px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie
                          data={expensesByCategory}
                          cx="50%"
                          cy="50%"
                          innerRadius={60}
                          outerRadius={80}
                          paddingAngle={5}
                          dataKey="value"
                        >
                          {expensesByCategory.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                          ))}
                        </Pie>
                        <Tooltip 
                          formatter={(value: number) => [`${value.toFixed(2)} €`, 'Montant']}
                          contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                        />
                        <Legend verticalAlign="bottom" height={36}/>
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                ) : (
                  <div className="h-[300px] flex items-center justify-center text-slate-400 bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                     Aucune donnée à afficher
                  </div>
                )}
             </div>

             <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 flex flex-col justify-center">
                 <h3 className="text-lg font-bold text-slate-900 mb-4">Conseil Trésorerie</h3>
                 <div className="space-y-4 text-sm text-slate-600">
                    <p>
                        Vos dépenses représentent <strong className="text-slate-900">{((totalExpenses / (totalRevenue || 1)) * 100).toFixed(1)}%</strong> de votre chiffre d'affaires.
                    </p>
                    <p>
                        La catégorie principale de dépense est <strong className="text-blue-600">{expensesByCategory.sort((a,b) => b.value - a.value)[0]?.name || 'Aucune'}</strong>.
                    </p>
                    <div className="p-4 bg-blue-50 text-blue-700 rounded-xl mt-4">
                        Pensez à mettre de côté environ <strong>22%</strong> de chaque encaissement pour vos cotisations URSSAF trimestrielles ou mensuelles.
                    </div>
                 </div>
             </div>
          </div>
        </div>
      )}

      {activeTab === 'journal' && (
        <div className="animate-fade-in">
          {/* Add Expense Button Area */}
          <div className="flex justify-end mb-6">
             <button 
              onClick={() => setShowForm(!showForm)}
              className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20 font-medium"
            >
              <Plus size={18} />
              Nouvelle Dépense
            </button>
          </div>

          {showForm && (
            <div className="bg-white p-8 rounded-2xl shadow-lg border border-slate-100 animate-slide-in mb-8">
              <h3 className="text-lg font-bold text-slate-900 mb-6">Ajouter une dépense</h3>
              <form onSubmit={handleAddExpense} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Date</label>
                  <input 
                    type="date" 
                    required
                    className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-shadow"
                    value={newExpense.date}
                    onChange={e => setNewExpense({...newExpense, date: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Montant TTC</label>
                  <input 
                    type="number" 
                    step="0.01"
                    required
                    className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-shadow"
                    value={newExpense.amount}
                    onChange={e => setNewExpense({...newExpense, amount: parseFloat(e.target.value)})}
                  />
                </div>
                <div className="md:col-span-2">
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Description</label>
                  <input 
                    type="text" 
                    required
                    className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-shadow"
                    value={newExpense.description}
                    onChange={e => setNewExpense({...newExpense, description: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Catégorie</label>
                  <select
                    className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 bg-white transition-shadow"
                    value={newExpense.category}
                    onChange={e => setNewExpense({...newExpense, category: e.target.value})}
                  >
                    <option value="Achats">Achats Matériel</option>
                    <option value="Loyer">Loyer / Charges</option>
                    <option value="Logiciels">Logiciels / SaaS</option>
                    <option value="Deplacements">Déplacements</option>
                    <option value="Assurance">Assurance</option>
                    <option value="Autre">Autre</option>
                  </select>
                </div>
                 <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Fournisseur (Optionnel)</label>
                  <select
                    className="w-full p-2.5 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 bg-white transition-shadow"
                    value={newExpense.supplierId}
                    onChange={e => setNewExpense({...newExpense, supplierId: e.target.value})}
                  >
                    <option value="">Aucun</option>
                    {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </div>

                <div className="md:col-span-2 flex justify-end gap-3 mt-4">
                  <button 
                    type="button" 
                    onClick={() => setShowForm(false)}
                    className="px-5 py-2.5 text-slate-600 hover:bg-slate-50 rounded-xl font-medium transition-colors"
                  >
                    Annuler
                  </button>
                  <button 
                    type="submit" 
                    className="px-5 py-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-medium shadow-md transition-all hover:scale-[1.02]"
                  >
                    Ajouter
                  </button>
                </div>
              </form>
            </div>
          )}

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <table className="w-full text-left text-sm">
              <thead className="bg-slate-50/50 border-b border-slate-200 text-slate-500">
                <tr>
                  <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs">Date</th>
                  <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs">Description</th>
                  <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs">Catégorie</th>
                  <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs">Fournisseur</th>
                  <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs text-right">Montant</th>
                  <th className="px-6 py-4 font-semibold uppercase tracking-wider text-xs w-16"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {expenses.map((exp) => {
                  const supplierName = suppliers.find(s => s.id === exp.supplierId)?.name || '-';
                  return (
                    <tr key={exp.id} className="hover:bg-slate-50 transition-colors group">
                      <td className="px-6 py-4 text-slate-500 font-mono text-xs">{new Date(exp.date).toLocaleDateString()}</td>
                      <td className="px-6 py-4 font-medium text-slate-900">{exp.description}</td>
                      <td className="px-6 py-4">
                        <span className="inline-flex px-2.5 py-1 rounded-md bg-slate-100 text-slate-600 text-xs font-medium border border-slate-200">
                          {exp.category}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-slate-600">{supplierName}</td>
                      <td className="px-6 py-4 text-right font-bold text-slate-900">-{exp.amount.toFixed(2)} €</td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => handleDelete(exp.id)}
                          className="text-slate-300 hover:text-red-500 p-2 rounded-lg opacity-0 group-hover:opacity-100 transition-all"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
                {expenses.length === 0 && (
                  <tr>
                    <td colSpan={6} className="py-16 text-center text-slate-400">
                        Aucune dépense enregistrée pour le moment.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
};

