                       <button onClick={() => handleBulkStatusChange(InvoiceStatus.REJECTED)} className="px-3 py-1.5 bg-red-600 hover:bg-red-700 rounded-lg text-sm font-medium transition-colors">
                           Refusé
                       </button>
